def startup_trace(message):
    if not STARTUP_TRACE_ENABLED:
        return
    try:
        os.makedirs(os.path.dirname(STARTUP_TRACE_PATH), exist_ok=True)
        with open(STARTUP_TRACE_PATH, "a", encoding="utf-8") as handle:
            handle.write(f"{time.time():.6f} {message}\n")
    except Exception:
        pass


def current_timestamp_text():
    return datetime.now(APP_TIMEZONE).strftime("%Y-%m-%d %H:%M:%S")


def system_utc_offset_seconds():
    try:
        offset = datetime.now().astimezone().utcoffset()
        return int(offset.total_seconds()) if offset is not None else 0
    except Exception:
        return 0


def json_safe_value(value):
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    if isinstance(value, (str, int, float, bool)) or value is None:
        return value
    return clean_text(value) if "clean_text" in globals() else str(value)


def json_safe_dict(data):
    if not isinstance(data, dict):
        return {}
    safe = {}
    for key, value in data.items():
        if str(key).startswith("_") and key not in {"_resistance_ohm", "_power", "_unsupported_reason"}:
            continue
        safe[str(key)] = json_safe_value(value)
    return safe


