def ensure_configured_admin_member_account():
    ensure_member_auth_schema()
    username, password = get_no_match_admin_credentials()
    username = clean_text(username)
    password_text = str(password or "")
    if username == "" or password_text == "" or not member_username_is_valid(username):
        return
    now = current_timestamp_text()
    with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        row = conn.execute(
            "SELECT * FROM members WHERE lower(username)=lower(?) ORDER BY id ASC LIMIT 1",
            (username,),
        ).fetchone()
        if row is None:
            for legacy_username in NO_MATCH_ADMIN_LEGACY_DEFAULT_USERNAMES:
                legacy_username = clean_text(legacy_username)
                if legacy_username == "" or legacy_username.lower() == username.lower():
                    continue
                legacy_row = conn.execute(
                    "SELECT * FROM members WHERE lower(username)=lower(?) ORDER BY id ASC LIMIT 1",
                    (legacy_username,),
                ).fetchone()
                if legacy_row is None:
                    continue
                conn.execute(
                    """
                    UPDATE members
                    SET username=?, display_name=?, password_hash=?, role='admin', status='active', updated_at=?
                    WHERE id=?
                    """,
                    (
                        username,
                        username,
                        hash_member_password(password_text),
                        now,
                        int(legacy_row["id"]),
                    ),
                )
                row = conn.execute(
                    "SELECT * FROM members WHERE id=?",
                    (int(legacy_row["id"]),),
                ).fetchone()
                break
        if row is None:
            conn.execute(
                """
                INSERT INTO members (
                    username, password_hash, display_name, company, email, phone,
                    role, status, created_at, updated_at
                )
                VALUES (?, ?, ?, '', '', '', 'admin', 'active', ?, ?)
                """,
                (username, hash_member_password(password_text), username, now, now),
            )
        else:
            member = member_row_to_dict(row)
            updates = []
            values = []
            if not verify_member_password(password_text, member.get("password_hash", "")):
                updates.append("password_hash=?")
                values.append(hash_member_password(password_text))
            if clean_text(member.get("username", "")) != username:
                updates.append("username=?")
                values.append(username)
            if clean_text(member.get("display_name", "")) == "":
                updates.append("display_name=?")
                values.append(username)
            if normalize_member_role(member.get("role", "")) != "admin":
                updates.append("role=?")
                values.append("admin")
            if normalize_member_status(member.get("status", "")) != "active":
                updates.append("status=?")
                values.append("active")
            if updates:
                updates.append("updated_at=?")
                values.append(now)
                values.append(int(member["id"]))
                conn.execute(
                    "UPDATE members SET " + ", ".join(updates) + " WHERE id=?",
                    tuple(values),
                )
            for legacy_username in NO_MATCH_ADMIN_LEGACY_DEFAULT_USERNAMES:
                legacy_username = clean_text(legacy_username)
                if legacy_username == "" or legacy_username.lower() == username.lower():
                    continue
                conn.execute(
                    """
                    UPDATE members
                    SET status='disabled', updated_at=?
                    WHERE lower(username)=lower(?) AND id<>?
                    """,
                    (now, legacy_username, int(member["id"])),
                )
        conn.commit()
    flush_member_auth_remote_snapshot()


def list_members_for_admin():
    refresh_member_auth_remote_snapshot()
    ensure_configured_admin_member_account()
    ensure_member_auth_schema()
    with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            """
            SELECT id, username, display_name, company, email, phone, role, status,
                   created_at, updated_at, last_login_at
            FROM members
            ORDER BY id DESC
            """
        ).fetchall()
    return [member_row_to_dict(row) for row in rows]


def approve_member_account_admin(member_id):
    refresh_member_auth_remote_snapshot(force=True)
    ensure_member_auth_schema()
    try:
        member_id = int(member_id)
    except Exception:
        return False, "会员 ID 无效。"
    now = current_timestamp_text()
    with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
        exists = conn.execute("SELECT id FROM members WHERE id=?", (member_id,)).fetchone()
        if exists is None:
            return False, "会员不存在或已被删除。"
        conn.execute("UPDATE members SET status='active', updated_at=? WHERE id=?", (now, member_id))
        conn.commit()
    flush_member_auth_remote_snapshot()
    return True, "审核通过，会员现在可以登录。"


def member_admin_summary_dataframe(members):
    rows = []
    for member in members or []:
        rows.append(
            {
                "ID": member.get("id", ""),
                "账号": member.get("username", ""),
                "姓名/称呼": member.get("display_name", ""),
                "公司": member.get("company", ""),
                "邮箱": member.get("email", ""),
                "电话": member.get("phone", ""),
                "角色": format_member_role(member.get("role", "")),
                "状态": format_member_status(member.get("status", "")),
                "注册时间": member.get("created_at", ""),
                "最后登录": member.get("last_login_at", ""),
                "更新时间": member.get("updated_at", ""),
            }
        )
    return pd.DataFrame(rows)


def update_current_member_profile(member_id, display_name="", company="", email="", phone=""):
    refresh_member_auth_remote_snapshot(force=True)
    ensure_member_auth_schema()
    try:
        member_id = int(member_id)
    except Exception:
        return False, "会员 ID 无效。"
    new_values = {
        "display_name": clean_text(display_name),
        "company": clean_text(company),
        "email": clean_text(email),
        "phone": clean_text(phone),
    }
    if new_values["display_name"] == "":
        return False, "姓名/称呼不能为空。"
    now = current_timestamp_text()
    try:
        with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
            conn.row_factory = sqlite3.Row
            row = conn.execute("SELECT * FROM members WHERE id=?", (member_id,)).fetchone()
            if row is None:
                return False, "会员不存在或已被删除。"
            old_member = member_row_to_dict(row)
            changes = collect_member_profile_changes(
                old_member,
                new_values,
                ["display_name", "company", "email", "phone"],
            )
            if not changes:
                return True, "资料没有变化。"
            conn.execute(
                """
                UPDATE members
                SET display_name=?, company=?, email=?, phone=?, updated_at=?
                WHERE id=?
                """,
                (
                    new_values["display_name"],
                    new_values["company"],
                    new_values["email"],
                    new_values["phone"],
                    now,
                    member_id,
                ),
            )
            insert_member_profile_change_logs(
                conn,
                member_id,
                changes,
                changed_by=clean_text(old_member.get("username", "")),
                change_source="会员自助修改",
            )
            conn.commit()
        flush_member_auth_remote_snapshot()
        return True, "会员资料已更新。"
    except Exception as exc:
        return False, f"更新失败：{exc}"


def change_current_member_password(member_id, current_password="", new_password="", confirm_password=""):
    refresh_member_auth_remote_snapshot(force=True)
    ensure_member_auth_schema()
    try:
        member_id = int(member_id)
    except Exception:
        return False, "会员 ID 无效。"
    current_password = str(current_password or "")
    new_password = str(new_password or "")
    confirm_password = str(confirm_password or "")
    if new_password != confirm_password:
        return False, "两次输入的新密码不一致。"
    if len(new_password) < 6:
        return False, "新密码至少需要 6 位。"
    now = current_timestamp_text()
    try:
        with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
            conn.row_factory = sqlite3.Row
            row = conn.execute("SELECT * FROM members WHERE id=?", (member_id,)).fetchone()
            if row is None:
                return False, "会员不存在或已被删除。"
            member = member_row_to_dict(row)
            if not verify_member_password(current_password, member.get("password_hash", "")):
                return False, "当前密码不正确。"
            conn.execute(
                "UPDATE members SET password_hash=?, updated_at=? WHERE id=?",
                (hash_member_password(new_password), now, member_id),
            )
            conn.commit()
        flush_member_auth_remote_snapshot()
        return True, "密码已更新。"
    except Exception as exc:
        return False, f"密码更新失败：{exc}"


def update_member_account_admin(member_id, username, display_name="", company="", email="", phone="", role="member", status="active", new_password="", actor_username=""):
    refresh_member_auth_remote_snapshot(force=True)
    ensure_member_auth_schema()
    try:
        member_id = int(member_id)
    except Exception:
        return False, "会员 ID 无效。"
    username = clean_text(username)
    if not member_username_is_valid(username):
        return False, "账号只能使用 3-64 位英文、数字、点号、下划线、加号、减号或 @。"
    password_text = str(new_password or "")
    if password_text != "" and len(password_text) < 6:
        return False, "重置密码至少需要 6 位；如果不改密码请留空。"
    status_value = normalize_member_status(status)
    role_value = normalize_member_role(role)
    now = current_timestamp_text()
    try:
        with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
            conn.row_factory = sqlite3.Row
            row = conn.execute("SELECT * FROM members WHERE id=?", (member_id,)).fetchone()
            if row is None:
                return False, "会员不存在或已被删除。"
            if find_member_username_conflict(conn, username, exclude_member_id=member_id):
                return False, "这个账号已经被其他会员使用。"
            old_member = member_row_to_dict(row)
            new_values = {
                "username": username,
                "display_name": clean_text(display_name) or username,
                "company": clean_text(company),
                "email": clean_text(email),
                "phone": clean_text(phone),
                "role": role_value,
                "status": status_value,
            }
            changes = collect_member_profile_changes(
                old_member,
                new_values,
                ["username", "display_name", "company", "email", "phone", "role", "status"],
            )
            if password_text:
                conn.execute(
                    """
                    UPDATE members
                    SET username=?, display_name=?, company=?, email=?, phone=?, role=?, status=?,
                        password_hash=?, updated_at=?
                    WHERE id=?
                    """,
                    (
                        username,
                        new_values["display_name"],
                        new_values["company"],
                        new_values["email"],
                        new_values["phone"],
                        role_value,
                        status_value,
                        hash_member_password(password_text),
                        now,
                        member_id,
                    ),
                )
                conn.execute("DELETE FROM member_sessions WHERE member_id=?", (member_id,))
            else:
                conn.execute(
                    """
                    UPDATE members
                    SET username=?, display_name=?, company=?, email=?, phone=?, role=?, status=?, updated_at=?
                    WHERE id=?
                    """,
                    (
                        username,
                        new_values["display_name"],
                        new_values["company"],
                        new_values["email"],
                        new_values["phone"],
                        role_value,
                        status_value,
                        now,
                        member_id,
                    ),
                )
                if status_value != "active":
                    conn.execute("DELETE FROM member_sessions WHERE member_id=?", (member_id,))
            insert_member_profile_change_logs(
                conn,
                member_id,
                changes,
                changed_by=clean_text(actor_username) or get_no_match_admin_credentials()[0],
                change_source="管理员修改",
            )
            conn.commit()
        flush_member_auth_remote_snapshot()
        return True, "会员资料已更新。"
    except sqlite3.IntegrityError:
        return False, "这个账号已经被其他会员使用。"
    except Exception as exc:
        return False, f"更新失败：{exc}"


def delete_member_account_admin(member_id):
    refresh_member_auth_remote_snapshot(force=True)
    ensure_member_auth_schema()
    try:
        member_id = int(member_id)
    except Exception:
        return False, "会员 ID 无效。"
    with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
        exists = conn.execute("SELECT id FROM members WHERE id=?", (member_id,)).fetchone()
        if exists is None:
            return False, "会员不存在或已被删除。"
        conn.execute("DELETE FROM member_sessions WHERE member_id=?", (member_id,))
        conn.execute("DELETE FROM member_profile_change_logs WHERE member_id=?", (member_id,))
        cursor = conn.execute("DELETE FROM members WHERE id=?", (member_id,))
        conn.commit()
    flush_member_auth_remote_snapshot()
    return int(cursor.rowcount or 0) > 0, "会员已删除。"


def create_member_session(member_id):
    ensure_member_auth_schema()
    token = secrets.token_urlsafe(32)
    expires_at_ts = int(time.time()) + MEMBER_AUTH_SESSION_TTL_SECONDS
    now = current_timestamp_text()
    with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
        conn.execute(
            "INSERT INTO member_sessions (token, member_id, created_at, expires_at_ts) VALUES (?, ?, ?, ?)",
            (token, int(member_id), now, expires_at_ts),
        )
        conn.execute("UPDATE members SET last_login_at=?, updated_at=? WHERE id=?", (now, now, int(member_id)))
        conn.commit()
    flush_member_auth_remote_snapshot()
    return token


def authenticate_member(username, password):
    refresh_member_auth_remote_snapshot()
    ensure_configured_admin_member_account()
    member = get_member_by_username(username)
    if not member:
        return None, "账号或密码不正确。"
    status_value = normalize_member_status(member.get("status", ""))
    if status_value == "pending":
        return None, "账号正在等待管理员审核，通过后才能登录。"
    if status_value != "active":
        return None, "账号尚未开通或已停用，请联系管理员。"
    if not verify_member_password(password, member.get("password_hash", "")):
        return None, "账号或密码不正确。"
    token = create_member_session(int(member["id"]))
    member = get_member_by_id(int(member["id"]))
    if member:
        member["_session_token"] = token
    return member, ""


def get_member_by_session_token(token):
    refresh_member_auth_remote_snapshot()
    ensure_member_auth_schema()
    token = clean_text(token)
    if token == "":
        return None
    now_ts = int(time.time())
    with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        row = conn.execute(
            """
            SELECT m.*, s.expires_at_ts AS _session_expires_at_ts
            FROM member_sessions s
            JOIN members m ON m.id = s.member_id
            WHERE s.token=? AND s.expires_at_ts > ?
            """,
            (token, now_ts),
        ).fetchone()
        if row is None:
            conn.execute("DELETE FROM member_sessions WHERE token=?", (token,))
            conn.commit()
            flush_needed = True
        else:
            current_expiry = int(row["_session_expires_at_ts"] or 0)
            flush_needed = current_expiry <= now_ts + max(60, MEMBER_AUTH_SESSION_TTL_SECONDS // 2)
            if flush_needed:
                conn.execute(
                    "UPDATE member_sessions SET expires_at_ts=? WHERE token=?",
                    (now_ts + MEMBER_AUTH_SESSION_TTL_SECONDS, token),
                )
                conn.commit()
    if row is None:
        if flush_needed:
            flush_member_auth_remote_snapshot()
            return None
    if flush_needed:
        flush_member_auth_remote_snapshot()
    member = member_row_to_dict(row)
    member.pop("_session_expires_at_ts", None)
    if member and normalize_member_status(member.get("status", "")) == "active":
        member["_session_token"] = token
        return member
    return None


def current_member():
    state_token = clean_text(st.session_state.get("_member_auth_token", ""))
    query_token = clean_text(get_query_param_value(MEMBER_AUTH_QUERY_PARAM))
    saw_invalid_query_token = False
    for token in [state_token, query_token]:
        if token == "":
            continue
        member = get_member_by_session_token(token)
        if member is not None:
            st.session_state["_member_auth_token"] = token
            st.session_state["_member_display_name"] = clean_text(member.get("display_name", "")) or clean_text(member.get("username", ""))
            return member
        if token == query_token:
            saw_invalid_query_token = True
    if state_token != "":
        st.session_state.pop("_member_auth_token", None)
        st.session_state.pop("_member_display_name", None)
    if saw_invalid_query_token and query_token != "":
        st.session_state["_member_auth_clear_browser_token"] = True
        update_query_params(**{MEMBER_AUTH_QUERY_PARAM: ""})
    return None


def render_member_auth_browser_persistence_bridge():
    current_member()
    token = clean_text(st.session_state.get("_member_auth_token", "")) or clean_text(get_query_param_value(MEMBER_AUTH_QUERY_PARAM))
    bridge_channel = clean_text(get_query_param_value(MEMBER_AUTH_BRIDGE_CHANNEL_PARAM))
    clear_token = bool(st.session_state.pop("_member_auth_clear_browser_token", False))
    ttl_seconds = int(MEMBER_AUTH_SESSION_TTL_SECONDS)
    script = f"""
    <script>
    (function() {{
        const storageKey = {json.dumps(MEMBER_AUTH_BROWSER_STORAGE_KEY)};
        const expiresKey = {json.dumps(MEMBER_AUTH_BROWSER_EXPIRES_KEY)};
        const cookieName = {json.dumps(MEMBER_AUTH_COOKIE_NAME)};
        const queryParam = {json.dumps(MEMBER_AUTH_QUERY_PARAM)};
        const bridgeChannel = {json.dumps(bridge_channel)};
        const outerShellOrigin = {json.dumps(MEMBER_AUTH_OUTER_SHELL_ORIGIN)};
        const token = {json.dumps(token)};
        const clearToken = {json.dumps(clear_token)};
        const ttlSeconds = {ttl_seconds};
        const ttlMs = ttlSeconds * 1000;
        const now = Date.now();
        const targetWindow = window.parent || window;

        function notifyOuterShell(action, value, expiresAt) {{
            if (!bridgeChannel) return;
            try {{
                window.top.postMessage({{
                    source: "fruition-member-auth",
                    channel: bridgeChannel,
                    action: action,
                    token: value || "",
                    expiresAt: Number(expiresAt || 0),
                }}, outerShellOrigin);
            }} catch (err) {{}}
        }}

        function getDocument() {{
            try {{ return targetWindow.document || document; }} catch (err) {{ return document; }}
        }}

        function getStorage() {{
            try {{ return targetWindow.localStorage || window.localStorage; }} catch (err) {{ return null; }}
        }}

        function writeCookie(value, maxAgeSeconds) {{
            try {{
                getDocument().cookie = cookieName + "=" + encodeURIComponent(value) + "; Max-Age=" + maxAgeSeconds + "; Path=/; SameSite=Lax";
            }} catch (err) {{}}
        }}

        function deleteCookie() {{
            writeCookie("", 0);
        }}

        function readCookie() {{
            try {{
                const pairs = (getDocument().cookie || "").split("; ");
                for (const pair of pairs) {{
                    const idx = pair.indexOf("=");
                    if (idx <= 0) continue;
                    if (pair.slice(0, idx) === cookieName) {{
                        return decodeURIComponent(pair.slice(idx + 1) || "");
                    }}
                }}
            }} catch (err) {{}}
            return "";
        }}

        function clearSavedToken() {{
            const storage = getStorage();
            try {{
                if (storage) {{
                    storage.removeItem(storageKey);
                    storage.removeItem(expiresKey);
                }}
            }} catch (err) {{}}
            deleteCookie();
            notifyOuterShell("clear", "", 0);
        }}

        if (clearToken) {{
            clearSavedToken();
            return;
        }}

        if (token) {{
            const expiresAt = String(now + ttlMs);
            const storage = getStorage();
            try {{
                if (storage) {{
                    storage.setItem(storageKey, token);
                    storage.setItem(expiresKey, expiresAt);
                }}
            }} catch (err) {{}}
            writeCookie(token, ttlSeconds);
            notifyOuterShell("save", token, expiresAt);
            return;
        }}

        let savedToken = "";
        let expiresAt = 0;
        const storage = getStorage();
        try {{
            if (storage) {{
                savedToken = storage.getItem(storageKey) || "";
                expiresAt = parseInt(storage.getItem(expiresKey) || "0", 10) || 0;
            }}
        }} catch (err) {{}}
        if (!savedToken) {{
            savedToken = readCookie();
            expiresAt = savedToken ? now + ttlMs : 0;
        }}
        if (!savedToken || (expiresAt && expiresAt <= now)) {{
            clearSavedToken();
            return;
        }}

        try {{
            const url = new URL(targetWindow.location.href);
            if (!url.searchParams.get(queryParam)) {{
                url.searchParams.set(queryParam, savedToken);
                targetWindow.location.replace(url.toString());
            }}
        }} catch (err) {{}}
    }})();
    </script>
    """
    components.html(script, height=0, scrolling=False)


def set_current_member(member):
    if not isinstance(member, dict):
        return
    token = clean_text(member.get("_session_token", ""))
    if token:
        st.session_state["_member_auth_token"] = token
        st.session_state["_member_display_name"] = clean_text(member.get("display_name", "")) or clean_text(member.get("username", ""))
        st.session_state.pop("_member_auth_prompt_action", None)
        update_query_params(**{MEMBER_AUTH_QUERY_PARAM: token})


def complete_member_login(member):
    set_current_member(member)
    if is_bom_page_requested() and bool(st.session_state.get(BOM_PENDING_UPLOAD_WAITING_LOGIN_KEY)):
        st.session_state[BOM_POST_LOGIN_RESUME_STAGE_KEY] = BOM_POST_LOGIN_STAGE_LOGIN_COMPLETE
    if is_member_page_requested():
        update_query_params(member="", admin="")


def set_current_member_from_admin_login(username, password):
    if not no_match_admin_login_valid(username, password):
        return None
    ensure_configured_admin_member_account()
    lookup_username = NO_MATCH_ADMIN_DEFAULT_USERNAME if clean_text(username).lower() == NO_MATCH_ADMIN_DEFAULT_USERNAME.lower() else clean_text(username)
    member = get_member_by_username(lookup_username)
    if not member or normalize_member_status(member.get("status", "")) != "active":
        return None
    token = create_member_session(int(member["id"]))
    member = get_member_by_id(int(member["id"]))
    if member:
        member["_session_token"] = token
        set_current_member(member)
    return member


def logout_member():
    token = clean_text(st.session_state.get("_member_auth_token", "")) or clean_text(get_query_param_value(MEMBER_AUTH_QUERY_PARAM))
    if token:
        refresh_member_auth_remote_snapshot(force=True)
        ensure_member_auth_schema()
        with sqlite3.connect(MEMBER_AUTH_DB_PATH, timeout=30) as conn:
            conn.execute("DELETE FROM member_sessions WHERE token=?", (token,))
            conn.commit()
        flush_member_auth_remote_snapshot()
    st.session_state.pop("_member_auth_token", None)
    st.session_state.pop("_member_display_name", None)
    st.session_state.pop("_member_auth_prompt_action", None)
    st.session_state.pop(MEMBER_PENDING_SEARCH_QUERY_KEY, None)
    st.session_state.pop(MEMBER_PENDING_SEARCH_BRAND_MODE_KEY, None)
    st.session_state.pop(MEMBER_PENDING_SEARCH_BRANDS_KEY, None)
    st.session_state.pop(BOM_POST_LOGIN_RESUME_STAGE_KEY, None)
    st.session_state.pop(BOM_POST_LOGIN_AUTO_RESUME_AT_KEY, None)
    st.session_state["_member_auth_clear_browser_token"] = True
    update_query_params(**{MEMBER_AUTH_QUERY_PARAM: ""})


def is_member_page_requested():
    return get_query_param_value("member").lower() in {"1", "true", "yes", "on", "login", "center"}


def is_bom_page_requested():
    return get_query_param_value("bom").lower() in {"1", "true", "yes", "on", "upload", "match"}


def render_member_entry_button():
    if is_no_match_admin_page_requested():
        return
    member = current_member()
    if is_member_page_requested():
        label = "返回搜索"
        href = build_app_href(member="0", admin="0")
        css_class = "member-login-fixed secondary"
    elif member:
        label = "会员中心"
        href = build_app_href(member="1")
        css_class = "member-login-fixed active"
    else:
        label = "会员登录"
        href = build_app_href(member="1")
        css_class = "member-login-fixed"
    st.markdown(
        f'<a class="{css_class}" href="{href}" target="_self" role="button">{html.escape(label)}</a>',
        unsafe_allow_html=True,
    )


