def member_matches_admin_keyword(member, keyword):
    keyword = clean_text(keyword).lower()
    if not keyword:
        return True
    fields = [
        member.get("username", ""),
        member.get("display_name", ""),
        member.get("company", ""),
        member.get("email", ""),
        member.get("phone", ""),
    ]
    return any(keyword in clean_text(value).lower() for value in fields)


COST_PRICE_TARGET_COLUMNS = ("品牌", "型号", "规格参数", "成本", "更新时间", "MOQ", "L&T")
COST_PRICE_LOOKUP_COLUMNS = ("成本", "更新时间", "MOQ", "MOQ来源", "L&T")
_COST_PRICE_LOOKUP_CACHE = {"signature": None, "lookup": None}


def format_file_size(value):
    try:
        size = float(value or 0)
    except Exception:
        size = 0.0
    units = ["B", "KB", "MB", "GB"]
    for unit in units:
        if size < 1024 or unit == units[-1]:
            return f"{size:.0f}{unit}" if unit == "B" else f"{size:.1f}{unit}"
        size /= 1024


def normalize_cost_price_header(value):
    text = clean_text(value).lower()
    text = text.replace("＆", "&")
    for separator in (" ", "\t", "\r", "\n", "\u3000", "_", "\\", "/", "-", ":", "：", "(", ")", "（", "）", "[", "]", "【", "】"):
        text = text.replace(separator, "")
    return text


def cost_price_header_matches(header, keywords):
    raw = clean_text(header).lower()
    normalized = normalize_cost_price_header(header)
    for keyword in keywords:
        key_raw = clean_text(keyword).lower()
        key_norm = normalize_cost_price_header(keyword)
        if key_raw and key_raw in raw:
            return True
        if key_norm and key_norm in normalized:
            return True
    return False


def normalize_cost_price_tolerance_header(value):
    text = clean_text(value).replace("％", "%").strip()
    compact = text.replace(" ", "")
    if compact in {"5%", "5.0%"}:
        return "5"
    if compact in {"1%", "1.0%"}:
        return "1"
    try:
        numeric = float(compact.rstrip("%"))
    except Exception:
        return ""
    if compact.endswith("%"):
        numeric /= 100.0
    if abs(numeric - 0.05) <= 1e-9:
        return "5"
    if abs(numeric - 0.01) <= 1e-9:
        return "1"
    return ""


def find_cost_price_column(columns, include_keywords, exclude_keywords=()):
    for column in columns:
        if not cost_price_header_matches(column, include_keywords):
            continue
        if exclude_keywords and cost_price_header_matches(column, exclude_keywords):
            continue
        return column
    return None


def guess_cost_price_column_mapping(df):
    columns = list(df.columns) if isinstance(df, pd.DataFrame) else []
    return {
        "brand": find_cost_price_column(columns, ("品牌", "厂牌", "廠牌", "brand", "manufacturer", "mfr", "供应商")),
        "model": find_cost_price_column(
            columns,
            ("型号", "型號", "料号", "料號", "part number", "partno", "part no", "mpn", "model", "p/n", "pn"),
            ("规格", "描述", "description", "desc"),
        ),
        "spec": find_cost_price_column(columns, ("规格参数", "规格", "規格", "描述", "description", "desc", "参数", "品名")),
        "cost": find_cost_price_column(columns, ("成本", "单价", "單價", "价格", "價格", "price", "unit price", "cost", "含税", "rmb", "usd")),
        "moq": find_cost_price_column(columns, ("moq", "最小起订", "最低订购", "起订量", "package", "包装")),
        "lead_time": find_cost_price_column(columns, ("l&t", "lt", "leadtime", "lead time", "交期", "货期", "貨期", "delivery", "周期")),
    }


def init_cost_price_db():
    os.makedirs(os.path.dirname(COST_PRICE_DB_PATH), exist_ok=True)
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS cost_price_lists (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                file_name TEXT NOT NULL,
                file_sha256 TEXT NOT NULL DEFAULT '',
                file_size INTEGER NOT NULL DEFAULT 0,
                uploaded_at TEXT NOT NULL,
                uploaded_by TEXT NOT NULL DEFAULT '',
                row_count INTEGER NOT NULL DEFAULT 0,
                active INTEGER NOT NULL DEFAULT 0,
                note TEXT NOT NULL DEFAULT ''
            );

            CREATE TABLE IF NOT EXISTS cost_price_items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                list_id INTEGER NOT NULL,
                sheet_name TEXT NOT NULL DEFAULT '',
                row_index INTEGER NOT NULL DEFAULT 0,
                brand TEXT NOT NULL DEFAULT '',
                model TEXT NOT NULL DEFAULT '',
                model_clean TEXT NOT NULL DEFAULT '',
                spec_text TEXT NOT NULL DEFAULT '',
                cost TEXT NOT NULL DEFAULT '',
                cost_updated_at TEXT NOT NULL DEFAULT '',
                moq TEXT NOT NULL DEFAULT '',
                lead_time TEXT NOT NULL DEFAULT '',
                raw_json TEXT NOT NULL DEFAULT '',
                FOREIGN KEY(list_id) REFERENCES cost_price_lists(id)
            );

            CREATE TABLE IF NOT EXISTS cost_price_manual_items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                brand TEXT NOT NULL DEFAULT '',
                brand_key TEXT NOT NULL DEFAULT '',
                model TEXT NOT NULL DEFAULT '',
                model_clean TEXT NOT NULL DEFAULT '',
                spec_text TEXT NOT NULL DEFAULT '',
                cost TEXT NOT NULL DEFAULT '',
                moq TEXT NOT NULL DEFAULT '',
                lead_time TEXT NOT NULL DEFAULT '',
                note TEXT NOT NULL DEFAULT '',
                active INTEGER NOT NULL DEFAULT 1,
                cost_updated_at TEXT NOT NULL DEFAULT '',
                created_at TEXT NOT NULL DEFAULT '',
                created_by TEXT NOT NULL DEFAULT '',
                updated_at TEXT NOT NULL DEFAULT '',
                updated_by TEXT NOT NULL DEFAULT ''
            );

            CREATE INDEX IF NOT EXISTS idx_cost_price_lists_active
            ON cost_price_lists(active, uploaded_at);

            CREATE INDEX IF NOT EXISTS idx_cost_price_items_model
            ON cost_price_items(model_clean, list_id);

            CREATE UNIQUE INDEX IF NOT EXISTS idx_cost_price_manual_brand_model
            ON cost_price_manual_items(brand_key, model_clean);

            CREATE INDEX IF NOT EXISTS idx_cost_price_manual_active_updated
            ON cost_price_manual_items(active, updated_at, id);
            """
        )
        try:
            conn.execute("ALTER TABLE cost_price_items ADD COLUMN cost_updated_at TEXT NOT NULL DEFAULT ''")
        except sqlite3.OperationalError as exc:
            if "duplicate column" not in str(exc).lower():
                raise
        try:
            conn.execute("ALTER TABLE cost_price_manual_items ADD COLUMN cost_updated_at TEXT NOT NULL DEFAULT ''")
        except sqlite3.OperationalError as exc:
            if "duplicate column" not in str(exc).lower():
                raise
        conn.execute(
            """
            UPDATE cost_price_items
            SET cost_updated_at = COALESCE(
                (SELECT uploaded_at FROM cost_price_lists WHERE cost_price_lists.id = cost_price_items.list_id),
                ''
            )
            WHERE cost_updated_at = ''
            """
        )
        conn.commit()


def clear_cost_price_lookup_cache():
    _COST_PRICE_LOOKUP_CACHE["signature"] = None
    _COST_PRICE_LOOKUP_CACHE["lookup"] = None


def cost_price_file_signature(raw_bytes):
    try:
        return hashlib.sha256(raw_bytes or b"").hexdigest()
    except Exception:
        return ""


def normalize_cost_value_for_compare(value):
    text = clean_text(value)
    if text == "":
        return ""
    compact = (
        text.replace(",", "")
        .replace("￥", "")
        .replace("¥", "")
        .replace("$", "")
        .strip()
    )
    try:
        decimal_value = Decimal(compact)
        normalized = format(decimal_value.normalize(), "f")
        if "." in normalized:
            normalized = normalized.rstrip("0").rstrip(".")
        return normalized or "0"
    except Exception:
        return re.sub(r"\s+", "", text).upper()


def normalize_cost_price_spec_key(value):
    text = clean_text(value).upper()
    if text == "":
        return ""
    return re.sub(r"[\s\u3000;；,，/\\|_\-]+", "", text)


def canonical_cost_price_brand_label(value):
    brand = clean_brand(value)
    if brand == "":
        return ""
    brand_upper = brand.upper()
    for canonical, aliases in BRAND_QUERY_ALIAS_GROUPS:
        canonical_upper = clean_text(canonical).upper()
        if brand_upper == canonical_upper:
            return canonical
        for alias in aliases:
            alias_upper = clean_text(alias).upper()
            if alias_upper and (alias_upper in brand_upper or brand_upper in alias_upper):
                return canonical
    return brand


def normalize_cost_price_brand_key(value):
    brand = canonical_cost_price_brand_label(value).upper()
    return re.sub(r"[^A-Z0-9\u4e00-\u9fff]+", "", brand)


def cost_price_item_change_key(item):
    if not isinstance(item, dict):
        return None
    brand = clean_brand(item.get("brand", "")).upper()
    model = clean_model(item.get("model_clean", "") or item.get("model", ""))
    if model != "":
        return ("model", brand, model)
    spec_key = normalize_cost_price_spec_key(item.get("spec_text", ""))
    if spec_key != "":
        return ("spec", brand, spec_key)
    return None


def load_active_cost_price_change_map(conn):
    conn.row_factory = sqlite3.Row
    rows = conn.execute(
        """
        SELECT
            i.brand, i.model, i.model_clean, i.spec_text, i.cost, i.cost_updated_at,
            l.uploaded_at AS list_uploaded_at
        FROM cost_price_items i
        JOIN cost_price_lists l ON l.id = i.list_id
        WHERE l.active = 1
        ORDER BY i.id ASC
        """
    ).fetchall()
    change_map = {}
    for row in rows:
        item = dict(row)
        key = cost_price_item_change_key(item)
        if key is None:
            continue
        change_map[key] = {
            "cost_compare": normalize_cost_value_for_compare(item.get("cost", "")),
            "cost_updated_at": clean_text(item.get("cost_updated_at", "")) or clean_text(item.get("list_uploaded_at", "")),
        }
    return change_map


def apply_cost_price_item_update_times(items, previous_change_map, now_text):
    for item in items or []:
        key = cost_price_item_change_key(item)
        previous = previous_change_map.get(key) if key is not None and isinstance(previous_change_map, dict) else None
        cost_compare = normalize_cost_value_for_compare(item.get("cost", ""))
        previous_time = clean_text(previous.get("cost_updated_at", "")) if isinstance(previous, dict) else ""
        previous_cost = clean_text(previous.get("cost_compare", "")) if isinstance(previous, dict) else ""
        if previous is not None and previous_cost == cost_compare and previous_time != "":
            item["cost_updated_at"] = previous_time
        else:
            item["cost_updated_at"] = now_text
    return items


def cost_price_list_summary_dataframe(rows):
    if not rows:
        return pd.DataFrame(columns=["ID", "当前使用", "文件名", "上传时间", "上传人", "行数", "文件大小"])
    return pd.DataFrame(
        [
            {
                "ID": row.get("id", ""),
                "当前使用": "是" if int(row.get("active", 0) or 0) == 1 else "",
                "文件名": row.get("file_name", ""),
                "上传时间": row.get("uploaded_at", ""),
                "上传人": row.get("uploaded_by", ""),
                "行数": row.get("row_count", 0),
                "文件大小": format_file_size(row.get("file_size", 0)),
            }
            for row in rows
        ]
    )


def list_cost_price_lists():
    refresh_runtime_store_remote_snapshot("cost-price")
    init_cost_price_db()
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            """
            SELECT *
            FROM cost_price_lists
            ORDER BY active DESC, uploaded_at DESC, id DESC
            """
        ).fetchall()
    return [dict(row) for row in rows]


def get_active_cost_price_list():
    refresh_runtime_store_remote_snapshot("cost-price")
    init_cost_price_db()
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        row = conn.execute(
            """
            SELECT *
            FROM cost_price_lists
            WHERE active = 1
            ORDER BY uploaded_at DESC, id DESC
            LIMIT 1
            """
        ).fetchone()
    return dict(row) if row is not None else None


def set_cost_price_list_active(list_id):
    refresh_runtime_store_remote_snapshot("cost-price", force=True)
    init_cost_price_db()
    try:
        list_id = int(list_id)
    except Exception:
        return False, "清单 ID 无效。"
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        exists = conn.execute("SELECT id FROM cost_price_lists WHERE id=?", (list_id,)).fetchone()
        if exists is None:
            return False, "清单不存在。"
        conn.execute("UPDATE cost_price_lists SET active=0")
        conn.execute("UPDATE cost_price_lists SET active=1 WHERE id=?", (list_id,))
        conn.commit()
    clear_cost_price_lookup_cache()
    synced = flush_runtime_store_remote_snapshot("cost-price")
    _, _, remote_enabled = get_runtime_store_remote_config()
    suffix = "" if synced or not remote_enabled else "，但远端备份失败，请稍后重试"
    return True, f"已切换当前使用的成本清单{suffix}。"


def list_cost_price_items(list_id=None, limit=300):
    refresh_runtime_store_remote_snapshot("cost-price")
    init_cost_price_db()
    active = get_active_cost_price_list() if list_id is None else None
    if list_id is None:
        if not active:
            return []
        list_id = active.get("id")
    try:
        list_id = int(list_id)
    except Exception:
        return []
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            """
            SELECT brand, model, spec_text, cost, cost_updated_at, moq, lead_time, sheet_name, row_index
            FROM cost_price_items
            WHERE list_id=?
            ORDER BY id ASC
            LIMIT ?
            """,
            (list_id, int(limit or 300)),
        ).fetchall()
    return [dict(row) for row in rows]


