def list_manual_cost_price_items(active_only=None, limit=500):
    refresh_runtime_store_remote_snapshot("cost-price")
    init_cost_price_db()
    params = []
    where_sql = ""
    if active_only is not None:
        where_sql = "WHERE active=?"
        params.append(1 if bool(active_only) else 0)
    params.append(max(1, int(limit or 500)))
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            f"""
            SELECT
                id, brand, model, model_clean, spec_text, cost, moq, lead_time,
                note, active, cost_updated_at, created_at, created_by, updated_at, updated_by
            FROM cost_price_manual_items
            {where_sql}
            ORDER BY active DESC, updated_at DESC, id DESC
            LIMIT ?
            """,
            params,
        ).fetchall()
    return [dict(row) for row in rows]


def count_manual_cost_price_items(active_only=True):
    refresh_runtime_store_remote_snapshot("cost-price")
    init_cost_price_db()
    params = ()
    where_sql = ""
    if active_only is not None:
        where_sql = "WHERE active=?"
        params = (1 if bool(active_only) else 0,)
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        row = conn.execute(
            f"SELECT COUNT(*) FROM cost_price_manual_items {where_sql}",
            params,
        ).fetchone()
    return int(row[0] or 0) if row else 0


def manual_cost_price_items_dataframe(items):
    if not items:
        return pd.DataFrame(
            columns=["状态", "品牌", "型号", "成本", "更新时间", "MOQ", "L&T", "规格参数", "询价备注", "操作人"]
        )
    return pd.DataFrame(
        [
            {
                "状态": "使用中" if int(row.get("active", 0) or 0) == 1 else "已停用",
                "品牌": row.get("brand", ""),
                "型号": row.get("model", ""),
                "成本": row.get("cost", ""),
                "更新时间": row.get("cost_updated_at", "") or row.get("updated_at", ""),
                "MOQ": row.get("moq", ""),
                "L&T": row.get("lead_time", ""),
                "规格参数": row.get("spec_text", ""),
                "询价备注": row.get("note", ""),
                "操作人": row.get("updated_by", "") or row.get("created_by", ""),
            }
            for row in items
        ]
    )


def save_manual_cost_price_item(
    brand,
    model,
    cost,
    moq="",
    lead_time="",
    spec_text="",
    note="",
    updated_by="",
    item_id=None,
):
    refresh_runtime_store_remote_snapshot("cost-price", force=True)
    init_cost_price_db()
    brand = canonical_cost_price_brand_label(brand)
    model = normalize_fojan_frc_model_display(model, brand)
    model = clean_text(model)
    model_clean = clean_model(model)
    brand_key = normalize_cost_price_brand_key(brand)
    cost = clean_text(cost)
    if brand == "":
        return False, "请填写品牌。", None
    if model_clean == "":
        return False, "请填写准确型号/料号。", None
    if cost == "":
        return False, "请填写成本。", None
    now_text = current_timestamp_text()
    updated_by = clean_text(updated_by)
    try:
        parsed_item_id = int(item_id) if item_id not in (None, "") else None
    except Exception:
        return False, "单笔成本记录 ID 无效。", None
    try:
        with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
            conn.execute("PRAGMA busy_timeout = 30000")
            existing = None
            if parsed_item_id is not None:
                conn.row_factory = sqlite3.Row
                existing = conn.execute(
                    "SELECT * FROM cost_price_manual_items WHERE id=?",
                    (parsed_item_id,),
                ).fetchone()
                if existing is None:
                    return False, "要修改的单笔成本记录不存在。", None
                conflict = conn.execute(
                    """
                    SELECT id
                    FROM cost_price_manual_items
                    WHERE brand_key=? AND model_clean=? AND id<>?
                    LIMIT 1
                    """,
                    (brand_key, model_clean, parsed_item_id),
                ).fetchone()
                if conflict is not None:
                    return False, "相同品牌和型号的单笔成本已经存在，请选择原记录修改。", None
            else:
                conn.row_factory = sqlite3.Row
                existing = conn.execute(
                    """
                    SELECT *
                    FROM cost_price_manual_items
                    WHERE brand_key=? AND model_clean=?
                    LIMIT 1
                    """,
                    (brand_key, model_clean),
                ).fetchone()
                if existing is not None:
                    parsed_item_id = int(existing["id"])

            if parsed_item_id is not None:
                conn.execute(
                    """
                    UPDATE cost_price_manual_items
                    SET brand=?, brand_key=?, model=?, model_clean=?, spec_text=?,
                        cost=?, moq=?, lead_time=?, note=?, active=1,
                        cost_updated_at=?, updated_at=?, updated_by=?
                    WHERE id=?
                    """,
                    (
                        brand,
                        brand_key,
                        model,
                        model_clean,
                        clean_text(spec_text),
                        cost,
                        clean_text(moq),
                        clean_text(lead_time),
                        clean_text(note),
                        now_text,
                        now_text,
                        updated_by,
                        parsed_item_id,
                    ),
                )
                record_id = parsed_item_id
                action = "更新"
            else:
                cur = conn.execute(
                    """
                    INSERT INTO cost_price_manual_items (
                        brand, brand_key, model, model_clean, spec_text, cost, moq,
                        lead_time, note, active, cost_updated_at, created_at, created_by,
                        updated_at, updated_by
                    )
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?, ?, ?)
                    """,
                    (
                        brand,
                        brand_key,
                        model,
                        model_clean,
                        clean_text(spec_text),
                        cost,
                        clean_text(moq),
                        clean_text(lead_time),
                        clean_text(note),
                        now_text,
                        now_text,
                        updated_by,
                        now_text,
                        updated_by,
                    ),
                )
                record_id = int(cur.lastrowid)
                action = "新增"
            conn.commit()
    except sqlite3.IntegrityError:
        return False, "相同品牌和型号的单笔成本已经存在。", None
    clear_cost_price_lookup_cache()
    synced = flush_runtime_store_remote_snapshot("cost-price")
    _, _, remote_enabled = get_runtime_store_remote_config()
    suffix = "" if synced or not remote_enabled else "；远端备份失败，请稍后重试"
    return True, f"已{action}单笔成本：{brand} / {model}{suffix}。", record_id


def set_manual_cost_price_item_active(item_id, active, updated_by=""):
    refresh_runtime_store_remote_snapshot("cost-price", force=True)
    init_cost_price_db()
    try:
        item_id = int(item_id)
    except Exception:
        return False, "单笔成本记录 ID 无效。"
    active_value = 1 if bool(active) else 0
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        cur = conn.execute(
            """
            UPDATE cost_price_manual_items
            SET active=?, updated_at=?, updated_by=?
            WHERE id=?
            """,
            (active_value, current_timestamp_text(), clean_text(updated_by), item_id),
        )
        conn.commit()
    if cur.rowcount <= 0:
        return False, "单笔成本记录不存在。"
    clear_cost_price_lookup_cache()
    synced = flush_runtime_store_remote_snapshot("cost-price")
    _, _, remote_enabled = get_runtime_store_remote_config()
    suffix = "" if synced or not remote_enabled else "；远端备份失败，请稍后重试"
    action = "启用" if active_value == 1 else "停用"
    return True, f"已{action}单笔成本记录{suffix}。"


def build_fojan_cost_price_items_from_workbook(uploaded_file):
    raw_bytes = get_uploaded_file_bytes(uploaded_file)
    if not raw_bytes:
        return []
    try:
        excel_file = pd.ExcelFile(BytesIO(raw_bytes))
    except Exception:
        return []
    items = []
    for sheet_name in excel_file.sheet_names:
        try:
            raw_df = pd.read_excel(excel_file, sheet_name=sheet_name, header=None, dtype=object).fillna("")
        except Exception:
            continue
        header_index = None
        column_map = {}
        for idx in range(min(len(raw_df), 20)):
            row_values = [clean_text(value) for value in raw_df.iloc[idx].tolist()]
            normalized = [normalize_cost_price_header(value) for value in row_values]
            series_col = next((i for i, value in enumerate(normalized) if value == "series"), None)
            type_col = next((i for i, value in enumerate(normalized) if "typedimension" in value), None)
            range_col = next((i for i, value in enumerate(normalized) if "resistancerange" in value), None)
            package_col = next((i for i, value in enumerate(normalized) if value == "package"), None)
            if None in {series_col, type_col, range_col, package_col} or idx + 1 >= len(raw_df):
                continue
            subheaders = [normalize_cost_price_tolerance_header(value) for value in raw_df.iloc[idx + 1].tolist()]
            price_5_col = next((i for i, value in enumerate(subheaders) if value == "5"), None)
            price_1_col = next((i for i, value in enumerate(subheaders) if value == "1"), None)
            if price_5_col is None and price_1_col is None:
                continue
            header_index = idx
            column_map = {
                "series": series_col,
                "type_dimension": type_col,
                "range": range_col,
                "price_5": price_5_col,
                "price_1": price_1_col,
                "package": package_col,
            }
            break
        if header_index is None:
            continue
        last_series = ""
        for row_idx in range(header_index + 2, len(raw_df)):
            values = raw_df.iloc[row_idx].tolist()
            series = clean_text(values[column_map["series"]]).upper()
            if series:
                last_series = series
            else:
                series = last_series
            if series not in {"FRC", "FRL"}:
                continue
            type_dimension = clean_text(values[column_map["type_dimension"]])
            resistance_range = clean_text(values[column_map["range"]])
            package = clean_text(values[column_map["package"]])
            if type_dimension == "" or resistance_range == "":
                continue
            for tolerance, price_key in (("5", "price_5"), ("1", "price_1")):
                price_col = column_map.get(price_key)
                price = clean_text(values[price_col]) if price_col is not None else ""
                if price == "":
                    continue
                rule_data = {
                    "cost_rule_type": "fojan_resistor_series",
                    "series": series,
                    "type_dimension": type_dimension,
                    "resistance_range": resistance_range,
                    "tolerance": tolerance,
                    "package": package,
                }
                items.append(
                    {
                        "sheet_name": clean_text(sheet_name),
                        "row_index": row_idx + 1,
                        "brand": "FOJAN(富捷)",
                        "model": "",
                        "model_clean": "",
                        "spec_text": f"{series} {type_dimension} {resistance_range} {tolerance}%",
                        "cost": price,
                        "moq": package,
                        "lead_time": "",
                        "raw_json": json.dumps(rule_data, ensure_ascii=False, sort_keys=True),
                    }
                )
    return items


def build_cost_price_items_from_workbook(uploaded_file):
    fojan_items = build_fojan_cost_price_items_from_workbook(uploaded_file)
    if fojan_items:
        return fojan_items, ""
    workbook = read_uploaded_bom_workbook(uploaded_file)
    if workbook.get("read_error") and not workbook.get("sheet_frames"):
        return [], workbook.get("read_error", "成本清单读取失败。")
    items = []
    for sheet_info in workbook.get("sheet_frames", []) or []:
        sheet_name = clean_text(sheet_info.get("sheet_name", ""))
        df = sheet_info.get("df", pd.DataFrame())
        if not isinstance(df, pd.DataFrame) or df.empty:
            continue
        df = df.fillna("")
        mapping = guess_cost_price_column_mapping(df)
        for row_index, (_, row) in enumerate(df.iterrows(), start=2):
            raw_record = {clean_text(key): clean_text(value) for key, value in row.to_dict().items()}
            brand = clean_brand(row.get(mapping.get("brand"), "")) if mapping.get("brand") else ""
            model = clean_text(row.get(mapping.get("model"), "")) if mapping.get("model") else ""
            spec_text = clean_text(row.get(mapping.get("spec"), "")) if mapping.get("spec") else ""
            cost = clean_text(row.get(mapping.get("cost"), "")) if mapping.get("cost") else ""
            moq = clean_text(row.get(mapping.get("moq"), "")) if mapping.get("moq") else ""
            lead_time = clean_text(row.get(mapping.get("lead_time"), "")) if mapping.get("lead_time") else ""
            if clean_text(model) == "" and spec_text == "":
                continue
            if cost == "" and moq == "" and lead_time == "":
                continue
            items.append(
                {
                    "sheet_name": sheet_name,
                    "row_index": row_index,
                    "brand": brand,
                    "model": model,
                    "model_clean": clean_model(model),
                    "spec_text": spec_text,
                    "cost": cost,
                    "moq": moq,
                    "lead_time": lead_time,
                    "raw_json": json.dumps(json_safe_dict(raw_record), ensure_ascii=False, sort_keys=True),
                }
            )
    if not items:
        warning = clean_text(workbook.get("read_warning", ""))
        suffix = f"；{warning}" if warning else ""
        return [], f"未识别到可导入的成本数据，请确认清单中有型号/规格参数以及成本、MOQ 或 L&T 字段{suffix}"
    return items, ""


def import_cost_price_list_from_upload(uploaded_file, uploaded_by=""):
    if uploaded_file is None:
        return False, "请先选择要上传的成本清单。", None
    refresh_runtime_store_remote_snapshot("cost-price", force=True)
    init_cost_price_db()
    file_name = clean_text(getattr(uploaded_file, "name", "")) or "成本清单"
    raw_bytes = get_uploaded_file_bytes(uploaded_file)
    if not raw_bytes:
        return False, "上传文件内容为空。", None
    items, error = build_cost_price_items_from_workbook(uploaded_file)
    if not items:
        return False, error or "未识别到可导入的成本数据。", None
    now_text = current_timestamp_text()
    file_sha = cost_price_file_signature(raw_bytes)
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.execute("PRAGMA busy_timeout = 30000")
        previous_change_map = load_active_cost_price_change_map(conn)
        items = apply_cost_price_item_update_times(items, previous_change_map, now_text)
        conn.execute("UPDATE cost_price_lists SET active=0")
        cur = conn.execute(
            """
            INSERT INTO cost_price_lists (
                file_name, file_sha256, file_size, uploaded_at, uploaded_by, row_count, active
            )
            VALUES (?, ?, ?, ?, ?, ?, 1)
            """,
            (file_name, file_sha, len(raw_bytes), now_text, clean_text(uploaded_by), len(items)),
        )
        list_id = int(cur.lastrowid)
        conn.executemany(
            """
            INSERT INTO cost_price_items (
                list_id, sheet_name, row_index, brand, model, model_clean, spec_text,
                cost, cost_updated_at, moq, lead_time, raw_json
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            [
                (
                    list_id,
                    item.get("sheet_name", ""),
                    int(item.get("row_index", 0) or 0),
                    item.get("brand", ""),
                    item.get("model", ""),
                    item.get("model_clean", ""),
                    item.get("spec_text", ""),
                    item.get("cost", ""),
                    item.get("cost_updated_at", ""),
                    item.get("moq", ""),
                    item.get("lead_time", ""),
                    item.get("raw_json", ""),
                )
                for item in items
            ],
        )
        conn.commit()
    clear_cost_price_lookup_cache()
    synced = flush_runtime_store_remote_snapshot("cost-price")
    _, _, remote_enabled = get_runtime_store_remote_config()
    suffix = "" if synced or not remote_enabled else "；远端备份失败，请稍后重试"
    return True, f"已上传并启用成本清单：{file_name}，导入 {len(items)} 行{suffix}。", list_id


def get_cost_price_lookup_signature():
    active = get_active_cost_price_list()
    init_cost_price_db()
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        manual_row = conn.execute(
            """
            SELECT COUNT(*), COALESCE(MAX(id), 0), COALESCE(MAX(updated_at), '')
            FROM cost_price_manual_items
            WHERE active=1
            """
        ).fetchone()
    manual_count = int(manual_row[0] or 0) if manual_row else 0
    manual_max_id = int(manual_row[1] or 0) if manual_row else 0
    manual_updated_at = clean_text(manual_row[2]) if manual_row else ""
    if not active and manual_count <= 0:
        return None
    try:
        mtime = os.path.getmtime(COST_PRICE_DB_PATH)
    except Exception:
        mtime = 0
    return (
        int((active or {}).get("id", 0) or 0),
        int((active or {}).get("row_count", 0) or 0),
        clean_text((active or {}).get("uploaded_at", "")),
        manual_count,
        manual_max_id,
        manual_updated_at,
        mtime,
    )


def load_active_cost_price_lookup():
    signature = get_cost_price_lookup_signature()
    if signature is None:
        return {}
    if _COST_PRICE_LOOKUP_CACHE.get("signature") == signature and isinstance(_COST_PRICE_LOOKUP_CACHE.get("lookup"), dict):
        return _COST_PRICE_LOOKUP_CACHE["lookup"]
    active = get_active_cost_price_list()
    with sqlite3.connect(COST_PRICE_DB_PATH, timeout=30) as conn:
        conn.row_factory = sqlite3.Row
        rows = []
        if active:
            rows = conn.execute(
                """
                SELECT brand, model, model_clean, spec_text, cost, cost_updated_at, moq, lead_time, raw_json
                FROM cost_price_items
                WHERE list_id=?
                ORDER BY id ASC
                """,
                (int(active.get("id", 0)),),
            ).fetchall()
        manual_rows = conn.execute(
            """
            SELECT
                brand, model, model_clean, spec_text, cost,
                cost_updated_at, moq, lead_time
            FROM cost_price_manual_items
            WHERE active=1
            ORDER BY updated_at DESC, id DESC
            """
        ).fetchall()
    lookup = {}
    for row in manual_rows:
        item = dict(row)
        item["cost_source"] = "单笔成本"
        item["raw_json"] = ""
        model_clean = clean_model(item.get("model_clean", "") or item.get("model", ""))
        if model_clean != "":
            lookup.setdefault(model_clean, []).append(item)
    for row in rows:
        item = dict(row)
        item["cost_source"] = "当前启用成本清单"
        model_clean = clean_model(item.get("model_clean", "") or item.get("model", ""))
        if model_clean != "":
            lookup.setdefault(model_clean, []).append(item)
        try:
            rule_data = json.loads(clean_text(item.get("raw_json", "")) or "{}")
        except Exception:
            rule_data = {}
        if rule_data.get("cost_rule_type") == "fojan_resistor_series":
            rule_item = dict(item)
            rule_item.update(rule_data)
            rule_item["type_dimension_norm"] = normalize_resistor_pricing_type_dimension(
                rule_data.get("type_dimension", "")
            )
            lookup.setdefault("__fojan_resistor_rules__", []).append(rule_item)
    _COST_PRICE_LOOKUP_CACHE["signature"] = signature
    _COST_PRICE_LOOKUP_CACHE["lookup"] = lookup
    return lookup


def lookup_active_cost_price_for_row(row, lookup=None):
    if row is None:
        return {}
    lookup = load_active_cost_price_lookup() if lookup is None else lookup
    if not lookup:
        return {}
    model_clean = clean_model(row.get("型号", ""))
    entries = lookup.get(model_clean, []) if model_clean else []
    if entries:
        row_brand = clean_brand(row.get("品牌", ""))
        for entry in entries:
            entry_brand = clean_brand(entry.get("brand", ""))
            if entry_brand and brand_matches_loose(row_brand, entry_brand):
                return entry
        for entry in entries:
            if clean_brand(entry.get("brand", "")) == "":
                return entry
        return entries[0]

    series = normalize_resistor_pricing_series(row)
    if series == "":
        return {}
    size = clean_size(row.get("尺寸（inch）", "")) or infer_resistor_size_from_model(row.get("型号", ""))
    power = format_power_display(infer_resistor_power_text_from_record(row) or row.get("功率", "") or row.get("_power", ""))
    resistance_ohm = get_row_resistance_for_pricing(row)
    tolerance = clean_tol_for_match(row.get("容值误差", "") or row.get("_tol", ""))
    if size == "" or power == "" or resistance_ohm is None or tolerance not in {"1", "5"}:
        return {}
    pricing_resistance_ohm = resistance_ohm
    if series == "FRC" and tolerance == "1" and abs(float(resistance_ohm)) <= 1e-12:
        pricing_resistance_ohm = 10.0
    type_dimension = f"{size} {power}"
    for rule in lookup.get("__fojan_resistor_rules__", []):
        if clean_text(rule.get("series", "")).upper() != series:
            continue
        if clean_text(rule.get("type_dimension_norm", "")) != type_dimension:
            continue
        if clean_text(rule.get("tolerance", "")) != tolerance:
            continue
        selected_cost = select_resistor_segment_price(
            rule.get("resistance_range", ""), rule.get("cost", ""), pricing_resistance_ohm
        )
        if selected_cost != "":
            matched = dict(rule)
            matched["cost"] = selected_cost
            return matched
    return {}


def enrich_component_cost_columns(df):
    if df is None:
        return df
    out = df.copy()
    for column in COST_PRICE_LOOKUP_COLUMNS:
        if column not in out.columns:
            out[column] = ""
    if out.empty:
        return out
    lookup = load_active_cost_price_lookup()
    for idx, row in out.iterrows():
        price = lookup_active_cost_price_for_row(row, lookup=lookup) if lookup else {}
        manufacturer_packaging = lookup_manufacturer_packaging(row)
        price_source = clean_text(price.get("cost_source", "")) or "当前启用成本清单"
        updates = {
            "成本": clean_text(price.get("cost", "")),
            "更新时间": clean_text(price.get("cost_updated_at", "")),
            "MOQ": clean_text(price.get("moq", "")) or clean_text(manufacturer_packaging.get("MOQ", "")),
            "MOQ来源": (
                price_source
                if clean_text(price.get("moq", "")) != ""
                else clean_text(manufacturer_packaging.get("MOQ来源", ""))
            ),
            "L&T": clean_text(price.get("lead_time", "")),
        }
        for column, value in updates.items():
            if value != "":
                out.at[idx, column] = value
    return out


