BRAND_QUERY_FILTER_FLAG = "_brand_filter"
BRAND_QUERY_FILTER_ALIASES_KEY = "_brand_filter_aliases"
BRAND_QUERY_EXPLICIT_LIST_FLAG = "_brand_filter_explicit_list"
BRAND_QUERY_EXCLUDE_SOURCE_FLAG = "_brand_filter_exclude_source"
SEARCH_BRAND_MODE_AUTO = "自动匹配其他品牌"
SEARCH_BRAND_MODE_CUSTOM = "指定品牌"
SEARCH_BRAND_MAX_SELECTIONS = 5


def brand_query_aliases_for_label(label):
    label_text = clean_brand(label)
    if label_text == "":
        return ()
    label_upper = label_text.upper()
    for canonical, aliases in BRAND_QUERY_ALIAS_GROUPS:
        canonical_upper = clean_text(canonical).upper()
        if label_upper == canonical_upper or brand_alias_matches(label_text, aliases):
            return tuple(aliases)
    return (label_text,)


def extract_requested_brand_from_query(query_text):
    raw = clean_text(query_text)
    if raw == "":
        return ""
    upper = raw.upper()
    compact = normalize_component_keyword_compact(raw)
    for canonical, aliases in BRAND_QUERY_ALIAS_GROUPS:
        if any(alias_token_matches(upper, compact, alias) for alias in aliases):
            return canonical
    return ""


def canonical_brand_query_label(label):
    label_text = clean_brand(label)
    if label_text == "":
        return ""
    label_upper = label_text.upper()
    for canonical, aliases in BRAND_QUERY_ALIAS_GROUPS:
        canonical_upper = clean_text(canonical).upper()
        if label_upper == canonical_upper or brand_alias_matches(label_text, aliases):
            return canonical
    return ""


def extract_explicit_requested_brands_from_query(query_text):
    raw = clean_text(query_text)
    if raw == "":
        return ()
    match = re.search(r"(?:指定|目标|输出)品牌\s*[:：]\s*([^;；\r\n]+)$", raw, flags=re.I)
    if match is None:
        return ()
    labels = []
    for part in re.split(r"[/／、,，|]+", match.group(1)):
        canonical = canonical_brand_query_label(part.strip())
        if canonical != "":
            labels.append(canonical)
    return tuple(dict.fromkeys(labels))


def strip_explicit_requested_brand_clause(query_text):
    return re.sub(
        r"(?:指定|目标|输出)品牌\s*[:：]\s*[^;；\r\n]+$",
        " ",
        clean_text(query_text),
        flags=re.I,
    ).strip()


def apply_query_brand_hint_to_spec(spec, query_text):
    if spec is None:
        return spec
    explicit_brands = extract_explicit_requested_brands_from_query(query_text)
    source_brand = extract_requested_brand_from_query(
        strip_explicit_requested_brand_clause(query_text)
    )
    if not explicit_brands and source_brand == "":
        return spec
    merged = dict(spec)
    if source_brand != "" and clean_brand(merged.get("品牌", "")) == "":
        merged["品牌"] = source_brand
    if explicit_brands:
        aliases = []
        for requested_brand in explicit_brands:
            aliases.extend(brand_query_aliases_for_label(requested_brand))
        merged[BRAND_QUERY_FILTER_FLAG] = True
        merged[BRAND_QUERY_FILTER_ALIASES_KEY] = "|".join(dict.fromkeys(aliases))
        merged[BRAND_QUERY_EXPLICIT_LIST_FLAG] = True
    return merged


def apply_search_brand_scope_to_spec(spec, query_text, brand_mode="", selected_brands=None):
    if spec is None:
        return spec
    merged = apply_query_brand_hint_to_spec(spec, query_text)
    mode = clean_text(brand_mode)
    selected = []
    for value in selected_brands or []:
        canonical = canonical_brand_query_label(value) or clean_brand(value)
        if canonical != "" and canonical not in selected:
            selected.append(canonical)
        if len(selected) >= SEARCH_BRAND_MAX_SELECTIONS:
            break

    if mode == SEARCH_BRAND_MODE_CUSTOM:
        merged = dict(merged)
        merged.pop(BRAND_QUERY_FILTER_FLAG, None)
        merged.pop(BRAND_QUERY_FILTER_ALIASES_KEY, None)
        merged.pop(BRAND_QUERY_EXPLICIT_LIST_FLAG, None)
        merged.pop(BRAND_QUERY_EXCLUDE_SOURCE_FLAG, None)
        if selected:
            aliases = []
            for brand in selected:
                aliases.extend(brand_query_aliases_for_label(brand))
            merged[BRAND_QUERY_FILTER_FLAG] = True
            merged[BRAND_QUERY_FILTER_ALIASES_KEY] = "|".join(dict.fromkeys(aliases))
            merged[BRAND_QUERY_EXPLICIT_LIST_FLAG] = True
        return merged

    if mode == SEARCH_BRAND_MODE_AUTO and not extract_explicit_requested_brands_from_query(query_text):
        merged = dict(merged)
        merged.pop(BRAND_QUERY_FILTER_FLAG, None)
        merged.pop(BRAND_QUERY_FILTER_ALIASES_KEY, None)
        merged.pop(BRAND_QUERY_EXPLICIT_LIST_FLAG, None)
        merged.pop(BRAND_QUERY_EXCLUDE_SOURCE_FLAG, None)
    return merged


def clear_query_brand_filter_for_part_lookup(spec):
    if spec is None:
        return spec
    merged = dict(spec)
    if bool(merged.get(BRAND_QUERY_EXPLICIT_LIST_FLAG, False)):
        return merged
    merged.pop(BRAND_QUERY_FILTER_FLAG, None)
    merged.pop(BRAND_QUERY_FILTER_ALIASES_KEY, None)
    merged.pop(BRAND_QUERY_EXCLUDE_SOURCE_FLAG, None)
    return merged


def query_has_embedded_source_part_metadata(query_text):
    for token in extract_model_like_tokens(query_text):
        compact = clean_model(token)
        if len(compact) < 8:
            continue
        if re.fullmatch(r"[RCL]_[0-9]{4}", compact):
            continue
        if len(re.findall(r"[A-Z]", compact)) < 2:
            continue
        if len(re.findall(r"[0-9]", compact)) < 3:
            continue
        return True
    return False


def clear_query_brand_filter_for_embedded_part_metadata(spec, query_text):
    if spec is None or not query_has_embedded_source_part_metadata(query_text):
        return spec
    if bool(spec.get(BRAND_QUERY_EXPLICIT_LIST_FLAG, False)):
        return spec
    return clear_query_brand_filter_for_part_lookup(spec)


def merge_explicit_query_spec_into_part_spec(part_spec, query_spec):
    if part_spec is None:
        return part_spec
    if not isinstance(query_spec, dict):
        return part_spec
    merged = dict(part_spec)
    explicit_fields = (
        "尺寸（inch）",
        "材质（介质）",
        "容值_pf",
        "容值",
        "容值单位",
        "容值误差",
        "耐压（V）",
        "特殊用途",
        "_resistance_ohm",
        "_power",
        "_body_size",
        "_pitch",
        "_safety_class",
    )
    for field in explicit_fields:
        value = query_spec.get(field, None)
        if value is None:
            continue
        try:
            if pd.isna(value):
                continue
        except Exception:
            pass
        if clean_text(value) == "":
            continue
        merged[field] = value
    if clean_text(merged.get("器件类型", "")) == "" and clean_text(query_spec.get("器件类型", "")) != "":
        merged["器件类型"] = query_spec["器件类型"]
    for count_field in ("_core_param_count", "_param_count"):
        try:
            merged[count_field] = max(
                int(merged.get(count_field, 0) or 0),
                int(query_spec.get(count_field, 0) or 0),
            )
        except Exception:
            pass
    for filter_field in (
        BRAND_QUERY_FILTER_FLAG,
        BRAND_QUERY_FILTER_ALIASES_KEY,
        BRAND_QUERY_EXPLICIT_LIST_FLAG,
        BRAND_QUERY_EXCLUDE_SOURCE_FLAG,
    ):
        if filter_field in query_spec:
            merged[filter_field] = query_spec[filter_field]
    return merged


def requested_brand_aliases_from_spec(spec):
    if spec is None or not bool(spec.get(BRAND_QUERY_FILTER_FLAG, False)):
        return ()
    alias_text = clean_text(spec.get(BRAND_QUERY_FILTER_ALIASES_KEY, ""))
    if alias_text != "":
        aliases = tuple(clean_text(part) for part in alias_text.split("|") if clean_text(part) != "")
        if aliases:
            return aliases
    return brand_query_aliases_for_label(spec.get("品牌", ""))


def row_brand_matches_requested_brand(row_brand, spec):
    aliases = requested_brand_aliases_from_spec(spec)
    if not aliases:
        return True
    return brand_alias_matches(row_brand, aliases)


def filter_dataframe_by_requested_brand(df, spec):
    if not isinstance(df, pd.DataFrame) or df.empty or "品牌" not in df.columns:
        return df
    aliases = requested_brand_aliases_from_spec(spec)
    if not aliases:
        return df
    mask = df["品牌"].astype(str).apply(lambda value: brand_alias_matches(value, aliases))
    return df.loc[mask].copy()


def filter_candidate_pairs_by_requested_brand(pairs, spec):
    aliases = requested_brand_aliases_from_spec(spec)
    if not aliases or not pairs:
        return pairs
    filtered = [
        (brand, model)
        for brand, model in pairs
        if brand_alias_matches(brand, aliases)
    ]
    return filtered


JOYIN_DISPLAY_BRAND = "久尹（信昌PDC）"
