def display_brand_label(value):
    brand = clean_brand(value)
    if brand == "":
        return ""
    if "JOYIN" in brand.upper() or "久尹" in brand:
        return JOYIN_DISPLAY_BRAND
    return brand


def replace_brand_display_aliases_in_text(value):
    text = clean_text(value)
    if text == "" or JOYIN_DISPLAY_BRAND in text:
        return text
    marker = "__JOYIN_DISPLAY_BRAND__"
    text = re.sub(r"(?i)\bJOYIN\s*[\(（]\s*久尹\s*[\)）]", marker, text)
    text = re.sub(r"(?i)\bJOYIN\b", marker, text)
    text = text.replace("久尹", marker)
    return text.replace(marker, JOYIN_DISPLAY_BRAND)


def apply_brand_display_aliases(df):
    if df is None or df.empty:
        return df
    out = df.copy()
    for col in BRAND_DISPLAY_ALIAS_COLUMNS:
        if col in out.columns:
            out[col] = out[col].apply(display_brand_label)
    for col in BRAND_DISPLAY_ALIAS_TEXT_COLUMNS:
        if col in out.columns:
            out[col] = out[col].apply(replace_brand_display_aliases_in_text)
    return out

MODEL_WRAPPER_CHARS = "\ufeff'\"`´‘’“”＇＂"

def clean_model(x):
    text = clean_text(x).strip(MODEL_WRAPPER_CHARS)
    return text.upper().replace(" ", "")

def extract_model_like_tokens(text):
    raw = clean_text(text).upper()
    if raw == "":
        return []
    tokens = []
    seen = set()
    has_separators = re.search(r"[\s,;；|/\\]", raw) is not None
    whole = clean_model(raw)
    if (
        not has_separators
        and len(whole) >= 6
        and re.search(r"[A-Z]", whole)
        and re.search(r"\d", whole)
    ):
        tokens.append(whole)
        seen.add(whole)
    # Some BOMs join an Epson series name and its official product number with
    # an underscore, for example SG2520HGN_X1G0058910005.  Keep the compound
    # token for an exact lookup, but also expose each model-like segment so the
    # official product number can still resolve.
    if not has_separators:
        for segment in re.split(r"[_:]+", raw):
            compact = clean_model(segment.strip(".,;:|()[]{}'\"`´‘’“”＇＂"))
            if compact == "" or compact in seen or len(compact) < 6:
                continue
            if not (re.search(r"[A-Z]", compact) and re.search(r"\d", compact)):
                continue
            tokens.append(compact)
            seen.add(compact)
    for token in re.findall(r"[A-Z0-9][A-Z0-9._/+\\-]{4,}", raw):
        compact = clean_model(token.strip(".,;:|()[]{}'\"`´‘’“”＇＂"))
        if compact == "" or compact in seen or len(compact) < 6:
            continue
        if not (re.search(r"[A-Z]", compact) and re.search(r"\d", compact)):
            continue
        tokens.append(compact)
        seen.add(compact)
    return tokens

def load_component_rows_by_query_model_tokens(query_text):
    tokens = extract_model_like_tokens(query_text)
    if not tokens:
        return pd.DataFrame(), [], ""
    whole = clean_model(query_text)
    ordered_tokens = sorted(
        tokens,
        key=lambda token: (
            0 if token == whole else 1,
            0 if len(token) >= 12 and sum(char.isdigit() for char in token) >= 6 else 1,
            -len(token),
        ),
    )
    for token in ordered_tokens:
        rows = load_component_rows_by_clean_models_map([token], use_database=False).get(clean_model(token), pd.DataFrame())
        if isinstance(rows, pd.DataFrame) and not rows.empty:
            return rows, tokens, token
        prefix_rows, prefix = load_component_rows_by_known_model_prefix(token)
        if isinstance(prefix_rows, pd.DataFrame) and not prefix_rows.empty:
            return prefix_rows, tokens, prefix
        rows = load_component_rows_by_clean_model(token)
        if isinstance(rows, pd.DataFrame) and not rows.empty:
            return rows, tokens, token
    return pd.DataFrame(), tokens, ""


def should_try_model_token_lookup_before_fast_query(line, mode, spec, exact_part_rows=None):
    if isinstance(exact_part_rows, pd.DataFrame) and not exact_part_rows.empty:
        return False
    if clean_text(mode) == "料号":
        return False
    if spec is not None and bool(spec.get("_unsupported_component", False)):
        return False
    text = clean_text(line)
    if text == "" or not re.search(r"[\s,;；|/\\]", text):
        return False
    whole = clean_model(text)
    for token in extract_model_like_tokens(text):
        if token and token != whole:
            return True
    return False


def compound_model_suffix_looks_like_spec(suffix):
    suffix_text = clean_text(suffix).strip(" \t\r\n,;:|/()[]{}")
    if suffix_text == "":
        return False
    if find_resistance_in_text(suffix_text) is not None:
        return True
    if parse_resistor_value_code(suffix_text) is not None:
        return True
    if parse_tolerance_token(suffix_text) != "":
        return True
    if find_embedded_size(suffix_text) != "":
        return True
    return False


def load_component_rows_by_known_model_prefix(token):
    compact = clean_model(token)
    if len(compact) < 8:
        return pd.DataFrame(), ""
    prefix_candidates = []
    for end in range(len(compact) - 1, 5, -1):
        prefix = compact[:end]
        suffix = compact[end:]
        if not compound_model_suffix_looks_like_spec(suffix):
            continue
        prefix_candidates.append(prefix)
    if not prefix_candidates:
        return pd.DataFrame(), ""
    prefix_map = load_component_rows_by_clean_models_map(prefix_candidates, use_database=False)
    for prefix in prefix_candidates:
        rows = prefix_map.get(prefix, pd.DataFrame())
        if isinstance(rows, pd.DataFrame) and not rows.empty:
            return rows, prefix
    for prefix in prefix_candidates:
        rows = load_component_rows_by_clean_model(prefix)
        if isinstance(rows, pd.DataFrame) and not rows.empty:
            return rows, prefix
    return pd.DataFrame(), ""

def clean_material(x):
    x = clean_text(x).upper()
    x = x.replace("（", "(").replace("）", ")").replace(" ", "")
    x = x.replace("C0G", "COG")
    x = x.replace("NP0", "NPO")
    return x

def clean_size(x):
    s = clean_text(x).replace(" ", "")
    if re.fullmatch(r"\d+\.0+", s):
        s = s.split(".", 1)[0]
    if s.upper() in {"", "NONE", "NAN", "NULL", "N/A", "NA", "-", "--", "/"}:
        return ""
    pad_map = {
        "401": "0401",
        "402": "0402",
        "603": "0603",
        "805": "0805",
        "201": "0201",
        "1005": "01005",
        "8004": "008004",
        "102": "0102",
        "15008": "015008",
        "008004": "008004",
        "0401": "0401",
        "0102": "0102",
        "015008": "015008",
    }
    if s in pad_map:
        return pad_map[s]
    return s.upper()


