def build_pdc_mt_dimension_fields(size_code, thickness_code):
    fields = {}
    size_dims = PDC_MT_CASE_DIMENSION_MAP.get(clean_text(size_code), {})
    if size_dims:
        fields.update(size_dims)
    thickness = clean_text(PDC_MT_THICKNESS_CODE_MAP.get(clean_text(thickness_code).upper(), ""))
    if thickness != "":
        fields["高度（mm）"] = thickness
    return fields


def decode_pdc_general_mlcc_dimension_fields_from_model(model):
    model_key = clean_model(model)
    if len(model_key) < 14:
        return {}
    series_code = model_key[:2]
    if series_code not in {"FN", "FS", "FM", "FV", "FP", "FK", "FH"}:
        return {}

    # PDC FN/FS/FM/FV/FP/FK/FH suffix layout follows package + thickness + control.
    suffix = model_key[12:]
    if len(suffix) < 2:
        return {}
    thickness_code = suffix[1]
    thickness = clean_text(PDC_MT_THICKNESS_CODE_MAP.get(thickness_code, ""))
    if thickness == "":
        return {}
    return {"高度（mm）": thickness}


def pdc_mlcc_series_code_from_model(model):
    model_key = clean_model(model)
    if model_key == "":
        return ""
    for prefix in ("MS", "MG", "MT"):
        if model_key.startswith(prefix):
            return prefix
    return ""


def pdc_mlcc_series_meaning(series_code):
    return clean_text(PDC_MLCC_SERIES_MEANING.get(clean_text(series_code).upper(), ""))


def pdc_mlcc_series_class(series_code):
    return clean_text(PDC_MLCC_SERIES_CLASS.get(clean_text(series_code).upper(), ""))


def pdc_mlcc_series_profile(series_code):
    code = clean_text(series_code).upper()
    if code == "":
        return {"系列": "", "系列说明": "", "特殊用途": "", "_mlcc_series_class": ""}
    return {
        "系列": code,
        "系列说明": pdc_mlcc_series_meaning(code),
        "特殊用途": clean_text(PDC_MLCC_SERIES_SPECIAL_USE.get(code, "")),
        "_mlcc_series_class": pdc_mlcc_series_class(code),
    }


def pdc_general_mlcc_series_code_from_model(model):
    model_key = clean_model(model)
    if model_key == "":
        return ""
    for prefix in PDC_MLCC_SERIES_PREFIXES:
        if model_key.startswith(prefix):
            return prefix
    return ""


def pdc_mlcc_series_profile_from_model(model):
    model_key = clean_model(model)
    if model_key == "":
        return "", "", "", "", ""
    for prefix in ("MS", "MG", "MT"):
        match = re.fullmatch(
            rf"{prefix}(?P<size>\d{{2}})(?P<mat>[BCNXT])(?P<cap>(?:\d{{3,4}}|R\d+))(?P<tol>[FGJKMZ])(?P<volt>(?:6R3|\d{{3}}))(?P<rest>.*)",
            model_key,
        )
        if match is None:
            continue
        suffix = clean_text(match.group("rest"))
        package_code = suffix[0] if len(suffix) >= 1 else ""
        thickness_code = suffix[1] if len(suffix) >= 2 else ""
        special_code = suffix[2] if len(suffix) >= 3 else ""
        return prefix, pdc_mlcc_series_meaning(prefix), package_code, thickness_code, special_code
    return "", "", "", "", ""


def pdc_mlcc_special_control_meaning(code):
    return clean_text(PDC_MT_SPECIAL_CONTROL_MAP.get(clean_text(code).upper(), ""))

def cap_to_pf(value, unit):
    v = clean_text(value)
    u = clean_text(unit).upper().replace(" ", "")
    if v == "":
        return None
    try:
        num = float(v)
    except:
        return None
    if u == "PF":
        return num
    elif u == "NF":
        return num * 1000
    elif u == "UF":
        return num * 1000000
    return num

def pf_to_value_unit(pf):
    if pf is None:
        return "", ""
    if pf >= 1000000:
        value = pf / 1000000
        if float(value).is_integer():
            value = int(value)
        return str(value), "UF"
    elif pf >= 1000:
        value = pf / 1000
        if float(value).is_integer():
            value = int(value)
        return str(value), "NF"
    else:
        if float(pf).is_integer():
            pf = int(pf)
        return str(pf), "PF"


def ohm_to_value_unit(ohm_value):
    try:
        ohm = float(ohm_value)
    except:
        return "", ""
    if 0 < ohm < 1:
        value = ohm * 1000
        unit = "MILLIOHM"
    elif ohm >= 1000000:
        value = ohm / 1000000
        unit = "MOHM"
    elif ohm >= 1000:
        value = ohm / 1000
        unit = "KOHM"
    else:
        value = ohm
        unit = "OHM"
    return f"{value:.3f}".rstrip("0").rstrip("."), unit


def ohm_to_library_value_unit(ohm_value):
    value, unit = ohm_to_value_unit(ohm_value)
    display_unit_map = {
        "OHM": "Ω",
        "KOHM": "KΩ",
        "MOHM": "MΩ",
        "MILLIOHM": "mΩ",
    }
    return value, display_unit_map.get(unit, unit)


def parse_numeric_resistor_code(code):
    token = clean_text(code).upper()
    if token in {"0", "00", "000", "0000"}:
        return 0.0
    if len(token) == 3 and token.isdigit():
        return float(int(token[:2]) * (10 ** int(token[2])))
    if len(token) == 4 and token.isdigit():
        return float(int(token[:3]) * (10 ** int(token[3])))
    return None


UNIROYAL_LOW_OHM_LETTER_MULTIPLIERS = {
    "J": 0.1,
    "K": 0.01,
    "L": 0.001,
}


def parse_uniroyal_resistor_value_code(code):
    token = clean_text(code).upper().replace("Ω", "").replace("OHMS", "").replace("OHM", "")
    if token == "":
        return None
    low_ohm_match = re.fullmatch(r"(\d{2,4})([JKL])", token)
    if low_ohm_match is not None:
        multiplier = UNIROYAL_LOW_OHM_LETTER_MULTIPLIERS.get(low_ohm_match.group(2))
        if multiplier is None:
            return None
        return float(int(low_ohm_match.group(1)) * multiplier)
    return parse_resistor_value_code(token)


def looks_like_uniroyal_resistor_model(model, brand=""):
    compact = clean_model(model)
    if compact == "":
        return False
    brand_upper = clean_brand(brand).upper()
    if any(token in brand_upper for token in ["UNI-ROYAL", "UNIROYAL", "厚声"]):
        return True
    if re.match(r"^(?:01005|0201|0402|0603|0805|1206|1210|1812|2010|2512)", compact):
        return True
    return re.match(r"^(?:AS|CM|CQ|CS|ES|HP|HQ|HS|HV|LE|LT|NM|NQ|NS|PF|PS|TC|VS|WR)\d{2}", compact) is not None


def extract_uniroyal_resistor_size_from_model(model):
    compact = clean_model(model)
    if compact == "":
        return ""
    if compact.startswith("01005"):
        return "01005"
    size_match = re.match(r"^(0201|0402|0603|0805|1206|1210|1812|2010|2512)", compact)
    if size_match is not None:
        return clean_size(size_match.group(1))
    prefix_match = re.match(r"^(?:AS|CM|CQ|CS|ES|HP|HQ|HS|HV|LE|LT|NM|NQ|NS|PF|PS|TC|VS|WR)(\d{2})", compact)
    if prefix_match is None:
        return ""
    return clean_size(UNIROYAL_RESISTOR_SIZE_MAP.get(prefix_match.group(1), ""))


def extract_uniroyal_resistor_value_from_model(model):
    compact = clean_model(model)
    if compact == "":
        return None, ""
    value_pattern = r"(?P<value>R\d{3,}|\d+R\d*|\d{2,4}[JKL]|\d{3,4})"
    structure_patterns = [
        rf"^(?:01005|0201|0402|0603|0805|1206|1210|1812|2010|2512)[A-Z0-9]{{2}}[BCDFGJKM]{value_pattern}",
        rf"^(?:01005|0201|0402|0603|0805|1206|1210|1812|2010|2512)[BCDFGJKM]{value_pattern}",
        rf"^(?:AS|CM|CQ|CS|ES|HP|HQ|HS|HV|LE|LT|NM|NQ|NS|PF|PS|TC|VS|WR)\d{{2}}[A-Z0-9]{{2}}[BCDFGJKM]{value_pattern}",
        rf"^(?:AS|CM|CQ|CS|ES|HP|HQ|HS|HV|LE|LT|NM|NQ|NS|PF|PS|TC|VS|WR)\d{{2}}[BCDFGJKM]{value_pattern}",
    ]
    for pattern in structure_patterns:
        match = re.match(pattern, compact)
        if match is None:
            continue
        value_code = clean_text(match.group("value")).upper()
        resistance_ohm = parse_uniroyal_resistor_value_code(value_code)
        if resistance_ohm is not None:
            return resistance_ohm, value_code
    return None, ""


def parse_eia96_resistor_code(code):
    token = clean_text(code).upper()
    if not re.fullmatch(r"\d{2}[A-Z]", token):
        return None
    base_index = int(token[:2])
    if not (1 <= base_index <= len(RESISTOR_EIA96_VALUES)):
        return None
    multiplier = RESISTOR_EIA96_MULTIPLIERS.get(token[2], None)
    if multiplier is None:
        return None
    return float(RESISTOR_EIA96_VALUES[base_index - 1] * multiplier)


def parse_resistor_value_code(code):
    token = clean_text(code).upper().replace("Ω", "").replace("OHMS", "").replace("OHM", "")
    if token == "":
        return None
    if token.isdigit():
        numeric = parse_numeric_resistor_code(token)
        if numeric is not None:
            return numeric
    direct = parse_resistance_token_to_ohm(token)
    if direct is not None:
        return direct
    return parse_eia96_resistor_code(token)


def match_tai_resistor_prefix(model):
    compact = clean_model(model)
    if compact == "":
        return ""
    for prefix in TAI_RESISTOR_PREFIXES:
        if compact.startswith(prefix):
            return prefix
    return ""


def parse_tai_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    prefix = match_tai_resistor_prefix(compact)
    if prefix == "":
        return None
    rest = compact[len(prefix):]
    if len(rest) < 4:
        return None
    size_code = clean_text(rest[:2])
    size = clean_size(TAI_RESISTOR_SIZE_MAP.get(size_code, ""))
    tol_code = clean_text(rest[2:3]).upper()
    tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(tol_code, ""))
    if size == "" or tol == "":
        return None
    packaging_code = clean_text(rest[3:4]).upper()
    tail = rest[4:] if len(rest) > 4 else ""
    resistance_ohm, value_code = extract_resistor_value_from_model(tail or rest, size_hint=size)
    if resistance_ohm is None:
        resistance_ohm, value_code = extract_resistor_value_from_model(compact, size_hint=size)
    if resistance_ohm is None:
        return None

    brand_hint = clean_brand(brand) or "大毅科技"
    fallback_component_type = "合金电阻" if prefix == "RLS" else (normalize_component_type(component_type) or "厚膜电阻")
    if prefix == "RLS":
        series_profile = dict(TAI_RLS_OFFICIAL_PROFILE)
    else:
        series_profile = infer_resistor_series_profile(
            compact,
            brand=brand_hint,
            component_type=fallback_component_type,
        )
    resolved_component_type = normalize_component_type(series_profile.get("器件类型", "")) or fallback_component_type
    resolved_special_use = clean_text(series_profile.get("特殊用途", ""))
    power_text = RESISTOR_POWER_BY_SIZE.get(size, "")

    return {
        "品牌": clean_brand(brand),
        "型号": compact,
        "器件类型": resolved_component_type,
        "系列": clean_text(series_profile.get("系列", "")) or prefix,
        "系列说明": clean_text(series_profile.get("系列说明", "")),
        "特殊用途": resolved_special_use,
        "尺寸（inch）": size,
        "容值误差": tol,
        "_resistance_ohm": resistance_ohm,
        "_power": power_text,
        "_model_rule_authority": "tai_resistor_model",
        "_value_code": value_code,
        "_packaging_code": packaging_code,
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0]),
    }


def extract_resistor_value_from_model(model, size_hint=""):
    compact = clean_model(model)
    if compact == "":
        return None, ""
    size_hint = clean_size(size_hint)
    segments = [seg for seg in re.split(r"[-_/]", compact) if seg]
    if not segments:
        segments = [compact]

    best = (None, "", -1, -1)
    candidate_pattern = re.compile(r"R\d+(?:\d+)?|\d+[RKM]\d*|\d{4}|\d{3}|\d{2}[A-Z]")
    size_tokens = {size_hint} if size_hint else set()
    size_tokens |= {"01005", "0201", "0401", "0402", "0603", "0805", "1206", "1210", "1812", "2010", "2512", "3225"}

    for segment in segments:
        for match in candidate_pattern.finditer(segment):
            token = match.group(0)
            if token in size_tokens:
                continue
            ohm_value = parse_resistor_value_code(token)
            if ohm_value is None:
                continue
            score = 1
            if any(ch in token for ch in "RKM"):
                score += 4
            if token.isdigit():
                score += 2
            if match.end() == len(segment) or re.fullmatch(r"[A-Z0-9]{0,3}", segment[match.end():]):
                score += 1
            if score > best[2] or (score == best[2] and match.start() > best[3]):
                best = (ohm_value, token, score, match.start())
    return best[0], best[1]


def infer_resistor_size_from_model(model):
    compact = clean_model(model)
    if compact == "":
        return ""
    tai_prefix = match_tai_resistor_prefix(compact)
    if tai_prefix != "":
        size_code = compact[len(tai_prefix):len(tai_prefix) + 2]
        mapped = clean_size(TAI_RESISTOR_SIZE_MAP.get(size_code, ""))
        if mapped != "":
            return mapped
    walsin_series_code = resolve_walsin_resistor_series_code_from_model(compact)
    if walsin_series_code != "":
        if walsin_series_code.startswith("WM04B"):
            return "0204"
        if walsin_series_code.startswith("FVF06F"):
            return "1206"
        match = re.match(r"^(?:WW|WR|WF|MR|SR|WK|WM)(?P<size>\d{2})", walsin_series_code)
        if match is not None:
            mapped = clean_size(WALSIN_RESISTOR_SIZE_MAP.get(match.group("size"), ""))
            if mapped != "":
                return mapped
    size = find_embedded_size(compact)
    if size != "":
        return size
    prefix_maps = [
        (("WR", "WF", "MR"), WALSIN_RESISTOR_SIZE_MAP),
        (("CR", "TR", "QR"), EVER_OHMS_RESISTOR_SIZE_MAP),
        (("CQ", "NQ", "LE", "TC"), UNIROYAL_RESISTOR_SIZE_MAP),
    ]
    for prefixes, size_map in prefix_maps:
        prefix = next((p for p in prefixes if compact.startswith(p)), None)
        if prefix is None:
            continue
        size_code = compact[len(prefix):len(prefix) + 2]
        mapped = clean_size(size_map.get(size_code, ""))
        if mapped != "":
            return mapped
    return ""


def infer_resistor_tolerance_from_model(model, size_hint=""):
    compact = clean_model(model)
    if compact == "":
        return ""
    tai_prefix = match_tai_resistor_prefix(compact)
    if tai_prefix != "":
        tol_idx = len(tai_prefix) + 2
        if tol_idx < len(compact):
            tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(compact[tol_idx], ""))
            if tol != "":
                return tol
    if len(compact) >= 7 and compact[2:6].isdigit() and compact[6] in RESISTOR_TOLERANCE_CODE_MAP:
        return clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP[compact[6]])
    value_ohm, value_code = extract_resistor_value_from_model(compact, size_hint=size_hint)
    if value_ohm is None or value_code == "":
        return ""
    segment = clean_model(compact.rsplit("-", 1)[0])
    if value_code in compact:
        idx = compact.find(value_code)
        if idx > 0:
            prev = compact[idx - 1]
            if prev in RESISTOR_TOLERANCE_CODE_MAP:
                return clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP[prev])
    if segment and segment[-1] in RESISTOR_TOLERANCE_CODE_MAP:
        return clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP[segment[-1]])
    return ""


def resistor_model_rule_candidate(model, brand="", component_type=""):
    compact = clean_model(model)
    if compact == "":
        return False
    normalized_type = normalize_component_type(component_type)
    if normalized_type != "" and normalized_type not in ALL_RESISTOR_TYPES:
        return False
    if normalized_type in ALL_RESISTOR_TYPES:
        return True
    if RESISTOR_MODEL_PREFIX_PATTERN.match(compact):
        return True
    upper_brand = clean_brand(brand).upper()
    return upper_brand != "" and any(
        token in upper_brand
        for token in ["YAGEO", "MURATA", "WALSIN", "UNI-ROYAL", "EVER OHMS", "RALEC", "FOJAN", "富捷"]
    )


def parse_yageo_chip_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    mlcc_candidate = parse_yageo_common(compact)
    if mlcc_candidate is not None:
        return None
    if not re.match(r"^(AA|AC|AF|AR|AT|RC|RT)\d{4}[A-Z]", compact):
        return None
    series_profile = infer_resistor_series_profile(compact, brand=brand, component_type=normalize_component_type(component_type) or "厚膜电阻")
    resolved_component_type = normalize_component_type(series_profile.get("器件类型", "")) or normalize_component_type(component_type) or "厚膜电阻"
    resolved_special_use = clean_text(series_profile.get("特殊用途", ""))
    size = clean_size(compact[2:6])
    tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(compact[6], ""))
    right_segment = compact.rsplit("-", 1)[-1] if "-" in compact else compact[7:]
    resistance_ohm, value_code = extract_resistor_value_from_model(right_segment[2:], size_hint=size)
    if resistance_ohm is None:
        resistance_ohm, value_code = extract_resistor_value_from_model(compact, size_hint=size)
    if size == "" and resistance_ohm is None and tol == "":
        return None
    return {
        "品牌": clean_brand(brand),
        "型号": compact,
        "器件类型": resolved_component_type,
        "系列": series_profile["系列"],
        "系列说明": series_profile["系列说明"],
        "特殊用途": resolved_special_use,
        "尺寸（inch）": size,
        "容值误差": tol,
        "_resistance_ohm": resistance_ohm,
        "_model_rule_authority": "yageo_chip_resistor_model",
        "_value_code": value_code,
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0]),
    }


def parse_murata_mhr_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    match = re.fullmatch(r"MHR(\d{4})SA(\d{3})([BCDFGJKM])([A-Z0-9]{2,})", compact)
    if not match:
        return None
    series_profile = infer_resistor_series_profile(compact, brand=brand, component_type=normalize_component_type(component_type) or "厚膜电阻")
    resolved_component_type = normalize_component_type(series_profile.get("器件类型", "")) or normalize_component_type(component_type) or "厚膜电阻"
    resolved_special_use = clean_text(series_profile.get("特殊用途", ""))
    resistance_ohm = parse_resistor_value_code(match.group(2))
    tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(match.group(3), ""))
    if resistance_ohm is None:
        return None
    return {
        "品牌": clean_brand(brand),
        "型号": compact,
        "器件类型": resolved_component_type,
        "系列": series_profile["系列"],
        "系列说明": series_profile["系列说明"],
        "特殊用途": resolved_special_use,
        "容值误差": tol,
        "_resistance_ohm": resistance_ohm,
        "_model_rule_authority": "murata_mhr_model",
        "_value_code": match.group(2),
        "_param_count": sum([1 if tol else 0, 1 if resistance_ohm is not None else 0]),
    }


def parse_walsin_chip_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    series_code = resolve_walsin_resistor_series_code_from_model(compact)
    if series_code == "":
        return None
    if not re.match(r"^(?:WW|WR|WF|MR|SR|WK|WM|FVF)\d", series_code):
        return None

    tail = compact[len(series_code):].lstrip("-_")
    if tail == "":
        return None
    size = infer_resistor_size_from_model(compact)
    value_code = ""
    tolerance_code = ""
    resistance_ohm = None

    value_token_pattern = re.compile(r"(R\d+(?:\d+)?|\d+[RKM]\d*|\d{4}|\d{3}|\d{2}[A-Z])(?P<tol>[BCDFGJKM])")
    for match in value_token_pattern.finditer(tail):
        candidate_code = clean_text(match.group(1)).upper()
        candidate_ohm = parse_resistor_value_code(candidate_code)
        if candidate_ohm is None:
            continue
        resistance_ohm = candidate_ohm
        value_code = candidate_code
        tolerance_code = clean_text(match.group("tol")).upper()
        break

    if resistance_ohm is None:
        for idx, char in enumerate(tail):
            if char not in RESISTOR_TOLERANCE_CODE_MAP:
                continue
            candidate_code = clean_text(tail[:idx]).upper()
            candidate_ohm = parse_resistor_value_code(candidate_code)
            if candidate_ohm is None:
                continue
            resistance_ohm = candidate_ohm
            value_code = candidate_code
            tolerance_code = char
            break

    if resistance_ohm is None:
        return None

    series_profile = infer_resistor_series_profile(
        compact,
        brand=brand,
        component_type=normalize_component_type(component_type) or "厚膜电阻",
    )
    resolved_component_type = normalize_component_type(series_profile.get("器件类型", "")) or normalize_component_type(component_type) or "厚膜电阻"
    resolved_special_use = clean_text(series_profile.get("特殊用途", ""))
    tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(tolerance_code, ""))
    power_text = RESISTOR_POWER_BY_SIZE.get(size, "")

    return {
        "品牌": clean_brand(brand),
        "型号": compact,
        "器件类型": resolved_component_type,
        "系列": clean_text(series_profile.get("系列", "")) or series_code,
        "系列说明": clean_text(series_profile.get("系列说明", "")),
        "特殊用途": resolved_special_use,
        "尺寸（inch）": size,
        "容值误差": tol,
        "_resistance_ohm": resistance_ohm,
        "_power": power_text,
        "_model_rule_authority": "walsin_chip_resistor_model",
        "_value_code": value_code,
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0]),
    }


def parse_ralec_lr_alloy_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    match = re.fullmatch(
        r"(?P<series>LRE|LR)(?P<size>0603|0805|1206|1210|2010|2512H|2512|2725|2728|4527S|4527)"
        r"-?2(?P<power>[C1A2345B])(?P<res>R\d{3,6})(?P<tol>[DFGJ])(?P<pack>[A1245])",
        compact,
    )
    if match is None:
        return None

    resistance_ohm = parse_resistor_value_code(match.group("res"))
    if resistance_ohm is None:
        return None

    series_code = match.group("series")
    size = clean_size(match.group("size"))
    tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(match.group("tol"), ""))
    power_text = clean_text(RALEC_LR_POWER_CODE_MAP.get(match.group("power"), ""))
    value_text, unit_text = ohm_to_library_value_unit(resistance_ohm)
    resistance_ohm_text = f"{resistance_ohm:g}"
    dimensions = RALEC_LR_DIMENSIONS_MM.get(size, ("", "", ""))
    series_profile = infer_resistor_series_profile(
        compact,
        brand=clean_brand(brand) or "旺诠RALEC",
        component_type="合金电阻",
        special_use="电流检测 | 低阻 | 金属合金",
    )
    series_desc = clean_text(series_profile.get("系列说明", ""))
    if series_desc == "":
        series_desc = f"RALEC {series_code} metal alloy low-resistance current sense resistor"
    summary_parts = [
        f"{value_text}{unit_text}" if value_text != "" and unit_text != "" else "",
        f"±{tol}%" if tol != "" else "",
        format_power_display(power_text),
        size,
        "metal alloy low-resistance current sense resistor",
    ]

    return {
        "品牌": clean_brand(brand) or "旺诠RALEC",
        "型号": compact,
        "器件类型": "合金电阻",
        "系列": series_code,
        "系列说明": series_desc,
        "特殊用途": "电流检测 | 低阻 | 金属合金",
        "尺寸（inch）": size,
        "尺寸（mm）": "6.25*3.20mm" if size == "2512" else "",
        "长度（mm）": dimensions[0],
        "宽度（mm）": dimensions[1],
        "高度（mm）": dimensions[2],
        "容值": value_text,
        "容值单位": unit_text,
        "容值误差": tol,
        "阻值@25C": resistance_ohm_text,
        "阻值单位": "Ω",
        "阻值误差": tol,
        "功率": format_power_display(power_text),
        "安装方式": "贴片",
        "封装代码": size,
        "规格摘要": " ".join(part for part in summary_parts if clean_text(part) != ""),
        "_resistance_ohm": resistance_ohm,
        "_power": power_text,
        "_model_rule_authority": "ralec_lr_alloy_resistor_model",
        "_value_code": match.group("res"),
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0, 1 if power_text else 0]),
    }


def parse_pdc_fmf_alloy_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    match = re.fullmatch(
        r"FMF(?P<size_code>05|06|25|59)"
        r"(?P<tol>[FGJ])(?P<pack>[TPQ])(?P<power>[DFHJKM])"
        r"(?P<res>R\d{3,6})(?:X)?(?P<special>LHM|BHM|LH|BH)?",
        compact,
    )
    if match is None:
        return None

    resistance_ohm = parse_resistor_value_code(match.group("res"))
    if resistance_ohm is None:
        return None

    size = clean_size(PDC_FMF_SIZE_CODE_MAP.get(match.group("size_code"), ""))
    tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP.get(match.group("tol"), ""))
    power_text = clean_text(PDC_FMF_POWER_CODE_MAP.get(match.group("power"), ""))
    value_text, unit_text = ohm_to_library_value_unit(resistance_ohm)
    dimensions = PDC_FMF_DIMENSIONS_MM.get(size, ("", "", ""))
    special_code = clean_text(match.group("special") or "")
    special_meaning = clean_text(PDC_FMF_SPECIAL_CODE_MAP.get(special_code, ""))
    special_use_parts = ["电流检测", "金属条", "低阻"]
    if "AEC-Q200" in special_meaning:
        special_use_parts.append("AEC-Q200")
    if "Low EMF" in special_meaning:
        special_use_parts.append("低热电势")
    series_profile = infer_resistor_series_profile(
        compact,
        brand=clean_brand(brand) or "信昌PDC",
        component_type="合金电阻",
        special_use=" | ".join(special_use_parts),
    )
    series_desc = clean_text(series_profile.get("系列说明", ""))
    if series_desc == "":
        series_desc = "PDC FMF metal strip lead-free current sensing resistor"
    summary_parts = [
        f"{value_text}{unit_text}" if value_text != "" and unit_text != "" else "",
        f"±{tol}%" if tol != "" else "",
        format_power_display(power_text),
        size,
        "metal strip current sensing resistor",
        special_meaning,
    ]
    size_mm = ""
    if dimensions[0] != "" and dimensions[1] != "":
        size_mm = f"{dimensions[0]}*{dimensions[1]}mm"

    return {
        "品牌": clean_brand(brand) or "信昌PDC",
        "型号": compact,
        "器件类型": "合金电阻",
        "系列": "FMF",
        "系列说明": series_desc,
        "特殊用途": " | ".join(special_use_parts),
        "尺寸（inch）": size,
        "尺寸（mm）": size_mm,
        "长度（mm）": dimensions[0],
        "宽度（mm）": dimensions[1],
        "高度（mm）": dimensions[2],
        "容值": value_text,
        "容值单位": unit_text,
        "容值误差": tol,
        "功率": format_power_display(power_text),
        "工作温度": "-55~170℃",
        "安装方式": "贴片",
        "封装代码": size,
        "规格摘要": " ".join(part for part in summary_parts if clean_text(part) != ""),
        "数据来源": "PDC FMF Series datasheet; HQonline/DigiKey/LCSC cross-reference",
        "数据状态": "规格书/代理可查",
        "校验时间": "2026-05-27 22:50",
        "校验备注": "FMF25=2512; F=±1%; P=plastic tape; J=2W; R001=1mΩ; BHM=Low EMF AEC-Q200",
        "_resistance_ohm": resistance_ohm,
        "_power": power_text,
        "_model_rule_authority": "pdc_fmf_alloy_resistor_model",
        "_value_code": match.group("res"),
        "_packing_code": match.group("pack"),
        "_special_code": special_code,
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0, 1 if power_text else 0]),
    }


FOJAN_ALLOY_MODEL_PATTERN = re.compile(
    r"^(?P<series>FMB|FRM|FPM)(?P<size_code>06|08|12|20|25)"
    r"(?P<power>02|05|07|15|[123]W)"
    r"(?P<tol>[DFGJ])(?P<res>R\d{3,4})T(?P<suffix>ML|M|N|K)$"
)
FOJAN_ALLOY_TOLERANCE_CODE_MAP = {"D": "0.5", "F": "1", "G": "2", "J": "5"}
FOJAN_ALLOY_SIZE_CODE_TO_INCH = {
    "06": "0603",
    "08": "0805",
    "12": "1206",
    "20": "2010",
    "25": "2512",
}
FOJAN_ALLOY_SIZE_INCH_TO_CODE = {
    value: key for key, value in FOJAN_ALLOY_SIZE_CODE_TO_INCH.items()
}
FOJAN_ALLOY_POWER_CODE_TO_DISPLAY = {
    "02": "0.25W",
    "05": "0.5W",
    "07": "0.75W",
    "15": "1.5W",
    "1W": "1W",
    "2W": "2W",
    "3W": "3W",
}
FOJAN_ALLOY_POWER_DISPLAY_TO_CODE = {
    value: key for key, value in FOJAN_ALLOY_POWER_CODE_TO_DISPLAY.items()
}
FOJAN_FMB_DATASHEET_SOURCE = (
    "FMB Series Thin-film Chip Resistance Product Specifications "
    "FJ-JS-3001-V1.0/2025.09.24"
)
FOJAN_FPM_DATASHEET_SOURCE = (
    "FPM Series Low Resistance High Power Alloy Resistor Product Specifications "
    "FJ-JS-3001-V1.0/2025.09.24"
)
FOJAN_FRM_1206_EVIDENCE_SOURCE = (
    "FRM Series Low Resistance Alloy Resistor Product Specifications "
    "FJ-JS-3001-V1.0/2025.09.24"
)


def fojan_alloy_resistance_mohm(resistance_ohm):
    try:
        value = float(resistance_ohm)
    except Exception:
        return None
    if not math.isfinite(value) or value <= 0:
        return None
    mohm = value * 1000.0
    if mohm <= 0:
        return None
    return mohm


def fojan_alloy_value_code(resistance_ohm):
    mohm = fojan_alloy_resistance_mohm(resistance_ohm)
    if mohm is None:
        return ""
    scaled = round(mohm * 10)
    if abs(mohm * 10 - scaled) < 1e-9 and scaled % 10 != 0:
        if 1 <= scaled <= 9999:
            return f"R{scaled:04d}"
        return ""
    rounded = round(mohm)
    if abs(mohm - rounded) > 1e-9 or not (1 <= rounded <= 999):
        return ""
    return f"R{rounded:03d}"


def fojan_alloy_code_is_in_series_range(series, size, power, mohm, suffix):
    series = clean_text(series).upper()
    size = clean_size(size)
    power = format_power_display(power)
    suffix = clean_text(suffix).upper()
    if mohm is None:
        return False
    if series == "FMB":
        official_power = {
            "0603": "0.25W",
            "0805": "0.5W",
            "1206": "0.5W",
            "2010": "0.75W",
            "2512": "1W",
        }.get(size, "")
        return suffix == "M" and power == format_power_display(official_power) and 10.0 <= mohm <= 91.0
    if series == "FPM":
        if size != "2512" or power != "3W":
            return False
        if suffix == "ML":
            return 0.5 <= mohm <= 4.0
        if suffix == "M":
            return 1.0 <= mohm <= 100.0
        return False
    if series == "FRM":
        if size == "0805" and power == format_power_display("0.5W"):
            return 1.0 <= mohm <= 2.0 if suffix == "ML" else 3.0 <= mohm <= 25.0 if suffix == "M" else False
        if size == "1206" and power == format_power_display("0.5W"):
            return suffix == "M" and 101.0 <= mohm <= 200.0
        if size == "1206" and power == "1W":
            return mohm == 1.0 if suffix == "ML" else 1.0 <= mohm <= 100.0 if suffix == "M" else False
        if size == "2010" and power == format_power_display("1.5W"):
            return 1.0 <= mohm <= 3.0 if suffix == "ML" else 1.0 <= mohm <= 100.0 if suffix == "M" else False
        if size == "2512" and power == "2W":
            return 0.5 <= mohm <= 4.0 if suffix == "ML" else 1.0 <= mohm <= 680.0 if suffix == "M" else False
    return False


def fojan_alloy_model_fields(series, size, power, tol, value_code, suffix):
    resistance_ohm = parse_resistor_value_code(value_code)
    mohm = fojan_alloy_resistance_mohm(resistance_ohm)
    if resistance_ohm is None or not fojan_alloy_code_is_in_series_range(series, size, power, mohm, suffix):
        return None
    value_text, unit_text = ohm_to_library_value_unit(resistance_ohm)
    dimensions = {
        "0603": ("1.60", "0.90", ""),
        "0805": ("2.00", "1.30", ""),
        "1206": ("3.20", "1.60", ""),
        "2010": ("5.00", "2.60", ""),
        "2512": ("6.40", "3.20", ""),
    }.get(size, ("", "", ""))
    special_parts = ["电流检测", "分流器", "低阻", "合金"]
    if series == "FPM":
        series_desc = "低阻值高功率合金电阻"
        data_source = FOJAN_FPM_DATASHEET_SOURCE
    elif series == "FMB":
        series_desc = "薄膜合金贴片电阻"
        data_source = FOJAN_FMB_DATASHEET_SOURCE
        special_parts.extend(["低温漂", "薄膜"])
    else:
        series_desc = "合金低阻贴片电阻"
        data_source = FOJAN_FRM_1206_EVIDENCE_SOURCE
    if suffix == "ML":
        special_parts.append("大电极")
        series_desc += "（大电极）"
    summary_parts = [
        f"{value_text}{unit_text}" if value_text and unit_text else "",
        clean_tol_for_display(tol),
        format_power_display(power),
        size,
        series_desc,
    ]
    return {
        "品牌": "FOJAN(富捷)",
        "器件类型": "合金电阻",
        "系列": series,
        "系列说明": series_desc,
        "特殊用途": " | ".join(special_parts),
        "尺寸（inch）": size,
        "尺寸（mm）": f"{dimensions[0]}*{dimensions[1]}mm" if dimensions[0] and dimensions[1] else "",
        "长度（mm）": dimensions[0],
        "宽度（mm）": dimensions[1],
        "高度（mm）": dimensions[2],
        "容值": value_text,
        "容值单位": unit_text,
        "容值误差": tol,
        "阻值@25C": f"{float(resistance_ohm):g}",
        "阻值单位": "Ω",
        "阻值误差": tol,
        "功率": format_power_display(power),
        "安装方式": "贴片",
        "封装代码": size,
        "规格摘要": " ".join(part for part in summary_parts if clean_text(part) != ""),
        "数据来源": data_source,
        "数据状态": "规格书/平台可查",
        "_resistance_ohm": float(resistance_ohm),
        "_power": format_power_display(power),
        "_model_rule_authority": "fojan_alloy_resistor_model",
        "_value_code": value_code,
        "_fojan_suffix": suffix,
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0, 1 if power else 0]),
    }


def parse_fojan_alloy_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model).upper()
    match = FOJAN_ALLOY_MODEL_PATTERN.fullmatch(compact)
    if match is None:
        return None
    size = FOJAN_ALLOY_SIZE_CODE_TO_INCH.get(match.group("size_code"), "")
    power = FOJAN_ALLOY_POWER_CODE_TO_DISPLAY.get(match.group("power"), "")
    tol = FOJAN_ALLOY_TOLERANCE_CODE_MAP.get(match.group("tol"), "")
    if size == "" or power == "" or tol == "":
        return None
    parsed = fojan_alloy_model_fields(
        match.group("series"),
        size,
        power,
        tol,
        match.group("res"),
        match.group("suffix"),
    )
    if parsed is None:
        return None
    parsed["型号"] = compact
    return parsed


def parse_milliohm_holr_alloy_resistor_model(model, brand="", component_type=""):
    compact = clean_model(model)
    match_2010 = re.fullmatch(
        r"(?:HO)?LLR2010-?(?P<power>1(?:\.5)?W)-?(?P<res>\d+(?:\.\d+)?)MR-?(?P<tol>\d+(?:\.\d+)?)%?",
        compact,
    )
    match_2512d = re.fullmatch(
        r"(?:HO)?LR2512D-?(?P<power>2W|3W|3\.5W)-?(?P<res>\d+(?:\.\d+)?)MR-?(?P<tol>\d+(?:\.\d+)?)%?",
        compact,
    )
    match_6568 = re.fullmatch(
        r"(?:HO)?LRS6568-?(?P<power>5W)-?(?P<res>\d+(?:\.\d+)?)MR-?(?P<tol>\d+(?:\.\d+)?)%?",
        compact,
    )
    if match_2010 is None and match_2512d is None and match_6568 is None:
        return None

    match = match_2010 or match_2512d or match_6568
    try:
        resistance_ohm_decimal = Decimal(match.group("res")) / Decimal("1000")
        resistance_ohm = float(resistance_ohm_decimal)
    except Exception:
        return None
    resistance_ohm_field = format(resistance_ohm_decimal.normalize(), "f")
    if "." in resistance_ohm_field:
        resistance_ohm_field = resistance_ohm_field.rstrip("0").rstrip(".")
    power_text = clean_text(match.group("power")).replace(".0W", "W")
    tol = clean_tol_for_match(f"{match.group('tol')}%")
    value_text, unit_text = ohm_to_library_value_unit(resistance_ohm)

    if match_2010 is not None:
        series = "HoLLR"
        size = "2010"
        series_desc = "封体合金电流检测电阻（2010 1.5W AEC-Q200）"
        special_use = "电流检测 | 低阻 | 封体合金 | 车规 | AEC-Q200"
        body_size = "5.00*2.50*0.60mm"
        package_code = "2010"
        model_family = "milliohm_hollr2010_model"
    elif match_2512d is not None:
        series = "HoLR"
        size = "2512"
        series_desc = "封体合金电流检测电阻（车规 AEC-Q200）"
        special_use = "电流检测 | 低阻 | 封体合金 | 车规 | AEC-Q200"
        body_size = "6.40*3.20*0.80mm" if power_text != "3.5W" else "6.40*3.20mm"
        package_code = "2512D"
        model_family = "milliohm_holr2512d_model"
    else:
        series = "HoLRS"
        size = "6568"
        series_desc = "裸露合金电流采样电阻（5W 6568）"
        special_use = "电流检测 | 分流器 | 裸露合金 | 低阻 | 高功率"
        body_size = "6.90*6.60mm"
        package_code = "6568"
        model_family = "milliohm_holrs6568_model"

    summary_parts = [
        series_desc,
        size,
        f"{value_text}{unit_text}" if value_text != "" and unit_text != "" else "",
        clean_tol_for_display(tol) if tol != "" else "",
        format_power_display(power_text),
    ]
    return {
        "品牌": clean_brand(brand) or "Milliohm(毫欧)",
        "型号": compact,
        "器件类型": "合金电阻",
        "系列": series,
        "系列说明": series_desc,
        "特殊用途": special_use,
        "尺寸（inch）": size,
        "尺寸（mm）": body_size,
        "容值": value_text,
        "容值单位": unit_text,
        "容值误差": tol,
        "阻值@25C": resistance_ohm_field,
        "阻值单位": "Ω",
        "阻值误差": tol,
        "功率": format_power_display(power_text),
        "安装方式": "贴片",
        "封装代码": package_code,
        "规格摘要": " ".join(part for part in summary_parts if clean_text(part) != ""),
        "_resistance_ohm": resistance_ohm,
        "_power": power_text,
        "_model_rule_authority": model_family,
        "_param_count": sum([1 if size else 0, 1 if tol else 0, 1 if resistance_ohm is not None else 0, 1 if power_text else 0]),
    }


def parse_bourns_crf0805_current_sense_model(model, brand="", component_type=""):
    compact = clean_model(model)
    match = re.fullmatch(r"CRF0805-(?P<tol>[FJ])Z-(?P<res>R\d{3})ELF", compact)
