def build_generic_model_rule_breakdown(model, parsed=None):
    model_clean = clean_model(model)
    rows = [{"段位": "型号", "原始片段": model_clean, "含义": "当前未命中更细的系列拆分规则，显示已识别字段", "结果": ""}]
