def parse_pdc_fh(model):
    model = clean_model(model)
    if not re.match(r"^FH\d{2}", model) or len(model) < 12:
        return None
    size_map = {"08": "1808", "12": "1812", "20": "2220"}
    material_map = {"N": "COG(NPO)", "X": "X7R"}
    tol_map = {"J": "5", "K": "10"}
    voltage_map = {"302": "250"}
    try:
        series_profile = pdc_mlcc_series_profile("FH")
        return {
            "品牌": "信昌PDC",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": size_map.get(model[2:4], ""),
            "材质（介质）": clean_material(material_map.get(model[4], "")),
            "容值_pf": eia_code_to_pf(model[5:8]),
            "容值误差": clean_tol_for_match(tol_map.get(model[8], "")),
            "耐压（V）": clean_voltage(voltage_map.get(model[9:12], "")),
            **decode_pdc_general_mlcc_dimension_fields_from_model(model),
            "_model_rule_authority": "pdc_fh_series",
        }
    except:
        return None


def parse_pdc_mlcc_core(model, family_prefix="MT", allow_partial=False):
    model = clean_model(model)
    family_prefix = clean_text(family_prefix).upper()
    if family_prefix not in {"MT", "MG", "MS"}:
        return None
    mt_match = re.fullmatch(
        rf"{family_prefix}(?P<size>\d{{2}})(?P<mat>[BCNXT])(?P<cap>(?:\d{{3,4}}|R\d+))(?P<tol>[FGJKMZ])(?P<volt>(?:6R3|\d{{3}}))(?P<rest>.*)",
        model,
    )
    if mt_match is None:
        return None

    material_map = {"B": "X5R", "X": "X7R", "T": "X7T", "N": "COG(NPO)"}
    tol_map = {"F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"}

    try:
        size_code = mt_match.group("size")
        size = clean_size(PDC_MT_SIZE_CODE_MAP.get(size_code, ""))
        mat = clean_material(material_map.get(mt_match.group("mat"), ""))
        cap_pf = murata_cap_code_to_pf(mt_match.group("cap"))
        tol = clean_tol_for_match(tol_map.get(mt_match.group("tol"), ""))
        volt = decode_pdc_voltage_code(mt_match.group("volt"))
        suffix = clean_text(mt_match.group("rest"))
        package_code = suffix[0] if len(suffix) >= 1 else ""
        thickness_code = suffix[1] if len(suffix) >= 2 else ""
        special_code = suffix[2] if len(suffix) >= 3 else ""
        special_meaning = pdc_mlcc_special_control_meaning(special_code)
        series_code, series_meaning, _, _, _ = pdc_mlcc_series_profile_from_model(model)
        if series_code == "":
            series_code = family_prefix
        if series_meaning == "":
            series_meaning = pdc_mlcc_series_meaning(series_code)
        series_profile = pdc_mlcc_series_profile(series_code)
        if special_meaning != "":
            series_desc = f"{series_meaning} / {special_meaning}" if series_meaning else special_meaning
        else:
            series_desc = series_meaning
        special_use = clean_text(series_profile.get("特殊用途", ""))
        if special_meaning != "":
            special_use = f"{special_use}/{special_meaning}" if special_use else special_meaning

        param_count = sum([
            1 if size else 0,
            1 if mat else 0,
            1 if cap_pf is not None else 0,
            1 if tol else 0,
            1 if volt else 0,
        ])
        if param_count < 3:
            return None

        cap_value, cap_unit = pf_to_value_unit(cap_pf)
        result = {
            "品牌": "信昌PDC",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_code,
            "系列说明": series_desc,
            "尺寸（inch）": size,
            "材质（介质）": mat,
            "容值_pf": cap_pf,
            "容值": cap_value,
            "容值单位": cap_unit,
            "容值误差": tol,
            "耐压（V）": clean_voltage(volt),
            "安装方式": "贴片",
            "特殊用途": special_use,
            "_mlcc_series_class": normalize_mlcc_series_class(
                "/".join(
                    part for part in [
                        clean_text(series_profile.get("_mlcc_series_class", "")),
                        series_desc,
                        special_use,
                    ]
                    if clean_text(part) != ""
                )
            ),
            "_pdc_package_code": package_code,
            "_pdc_thickness_code": thickness_code,
            "_pdc_control_code": special_code,
        }
        result.update(build_pdc_mt_dimension_fields(size_code, thickness_code))
        if allow_partial:
            result["_param_count"] = param_count
            result["_partial_part"] = True
        else:
            result["_model_rule_authority"] = f"pdc_{series_code.lower()}_series" if series_code else "pdc_mlcc_series"
        return result
    except:
        return None


def parse_pdc_mt_core(model, allow_partial=False):
    return parse_pdc_mlcc_core(model, family_prefix="MT", allow_partial=allow_partial)


def parse_pdc_mg_core(model, allow_partial=False):
    return parse_pdc_mlcc_core(model, family_prefix="MG", allow_partial=allow_partial)


def parse_pdc_ms_core(model, allow_partial=False):
    return parse_pdc_mlcc_core(model, family_prefix="MS", allow_partial=allow_partial)



def parse_murata_core(model, allow_partial=False):
    model = clean_model(model)
    prefixes = ["GRM", "GCM", "GCJ", "GJM", "GQM", "GRT", "GCG", "GCQ"]
    prefix = next((p for p in prefixes if model.startswith(p)), None)
    if prefix is None:
        return None

    # Murata official order:
    # series + 2-char size + 1-char thickness + 2-char dielectric + 2-char voltage + 3-char capacitance + 1-char tolerance ...
    size_map = {
        "01": "008004",
        "02": "01005", "03": "0201", "15": "0402", "18": "0603",
        "21": "0805", "31": "1206", "32": "1210", "42": "1808",
        "43": "1812", "55": "2220"
    }
    material_map = {
        "B1": "COG(NPO)", "C1": "COG(NPO)", "5C": "COG(NPO)",
        "R6": "X5R", "R7": "X7R", "R9": "X8R",
        "C6": "X5S", "C7": "X7S", "C8": "X6S",
        "D6": "X5T", "D7": "X7T", "D8": "X6T",
        "E7": "X7U", "L8": "X8L", "M8": "X8M", "N8": "X8N",
        "U2": "U2J", "7U": "U2J", "Z7": "X7R"
    }
    voltage_map = {
        "0E": "2.5", "0G": "4", "0J": "6.3", "1A": "10",
        "1C": "16", "1E": "25", "1H": "50", "2A": "100",
        "2D": "200", "2E": "250", "2J": "630", "2K": "1000",
        "YA": "35"
    }
    tol_map = {
        "B": "0.1pF", "C": "0.25pF", "D": "0.5pF", "W": "0.05pF",
        "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"
    }

    p = len(prefix)
    if len(model) < p + 11:
        return None

    try:
        size_code = model[p:p+2]
        mat_code = model[p+3:p+5]
        volt_code = model[p+5:p+7]
        cap_code = model[p+7:p+10]
        tol_code = model[p+10]
        series_profile = murata_series_profile(prefix)

        size = clean_size(size_map.get(size_code, ""))
        mat = clean_material(material_map.get(mat_code, ""))
        pf = murata_cap_code_to_pf(cap_code)
        tol = clean_tol_for_match(tol_map.get(tol_code, ""))
        volt = clean_voltage(voltage_map.get(volt_code, ""))
        dimension_fields = decode_murata_dimension_fields_from_model(model)
        param_count = sum([
            1 if size else 0,
            1 if mat else 0,
            1 if pf is not None else 0,
            1 if tol else 0,
            1 if volt else 0,
        ])
        if allow_partial and param_count < 3:
            return None

        return {
            "品牌": "村田Murata",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": size,
            "材质（介质）": mat,
            "容值_pf": pf,
            "容值误差": tol,
            "耐压（V）": volt,
            "_model_rule_authority": "murata_core_series",
            "_param_count": param_count,
            "_partial_part": True,
            **dimension_fields,
        }
    except:
        return None


def parse_murata_common(model):
    parsed = parse_murata_core(model, allow_partial=False)
    if parsed is None:
        return None
    parsed.pop("_param_count", None)
    parsed.pop("_partial_part", None)
    return parsed


def parse_prefixed_eia_size_first_mlcc(model, brand=""):
    model = clean_model(model)
    match = re.fullmatch(
        r"(?P<prefix>C)(?P<size>01005|\d{4})(?P<mat>[X])"
        r"(?P<cap>(?:\d{3,4}|R\d+|\dR\d+))(?P<tol>[BCDFGJKMZ])"
        r"(?P<volt>(?:6R3|\d{3}))(?P<rest>[A-Z0-9]*)",
        model,
    )
    if not match:
        return None

    size_map = {
        "01005": "01005", "0201": "0201", "0402": "0402", "0603": "0603",
        "0805": "0805", "1206": "1206", "1210": "1210", "1808": "1808",
        "1812": "1812", "1825": "1825", "2220": "2220", "2225": "2225",
    }
    material_map = {"X": "X7R"}
    tol_map = {
        "B": "0.1PF", "C": "0.25PF", "D": "0.5PF",
        "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20",
    }

    size = clean_size(size_map.get(match.group("size"), match.group("size")))
    material = clean_material(material_map.get(match.group("mat"), ""))
    cap_pf = murata_cap_code_to_pf(match.group("cap"))
    tol = clean_tol_for_match(tol_map.get(match.group("tol"), ""))
    voltage = clean_voltage(decode_pdc_voltage_code(match.group("volt")))
    if size == "" or material == "" or cap_pf is None or tol == "" or voltage == "":
        return None

    brand_text = clean_brand(brand)
    series_profile = generic_mlcc_series_profile("C")
    cap_value, cap_unit = pf_to_value_unit(cap_pf)
    return {
        "品牌": brand_text,
        "型号": model,
        "器件类型": "MLCC",
        "系列": "C",
        "系列说明": series_profile["系列说明"],
        "特殊用途": series_profile["特殊用途"],
        "_mlcc_series_class": series_profile["_mlcc_series_class"],
        "尺寸（inch）": size,
        "材质（介质）": material,
        "容值_pf": cap_pf,
        "容值": cap_value,
        "容值单位": cap_unit,
        "容值误差": tol,
        "耐压（V）": voltage,
        "_model_rule_authority": "prefixed_eia_size_first_mlcc",
        "_param_count": 5,
    }


def parse_tdk_c_series(model):
    model = clean_model(model)
    if not model.startswith("C") or len(model) < 14:
        return None

    size_map = {
        "0402": "0402", "0603": "0603", "0805": "0805", "1206": "1206",
        "1210": "1210", "1808": "1808", "1812": "1812", "2220": "2220",
        "0816": "0306",
        "1005": "0402", "1608": "0603", "2012": "0805", "3216": "1206",
        "3225": "1210", "4520": "1808", "4532": "1812", "5750": "2220",
        "7563": "3025",
    }
    material_map = {
        "C0G": "COG(NPO)", "COG": "COG(NPO)", "NP0": "COG(NPO)", "NPO": "COG(NPO)",
        "X5R": "X5R", "X7R": "X7R", "X7S": "X7S", "X6S": "X6S", "X7T": "X7T",
        "X8R": "X8R", "X8L": "X8L"
    }
    voltage_map = {
        "0E": "2.5", "0G": "4", "0J": "6.3", "1A": "10", "1C": "16",
        "1E": "25", "1H": "50", "2A": "100", "2D": "200", "2E": "250", "2J": "630"
    }
    tol_map = {
        "C": "0.25pF", "D": "0.5pF", "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"
    }

    try:
        parsed_fields = None
        for mat_start, mat_end, volt_start, volt_end, cap_start, cap_end, tol_index in (
            (5, 8, 8, 10, 10, 13, 13),
            (5, 7, 7, 9, 9, 12, 12),
        ):
            if len(model) <= tol_index:
                continue
            size_code = model[1:5]
            mat_code = model[mat_start:mat_end]
            volt_code = model[volt_start:volt_end]
            cap_code = model[cap_start:cap_end]
            tol_code = model[tol_index]
            size = size_map.get(size_code, "")
            material = clean_material(material_map.get(mat_code, ""))
            cap_pf = murata_cap_code_to_pf(cap_code)
            tol = clean_tol_for_match(tol_map.get(tol_code, ""))
            voltage = clean_voltage(voltage_map.get(volt_code, ""))
            if size == "" or cap_pf is None or tol == "" or voltage == "":
                continue
            parsed_fields = {
                "size": size,
                "material": material,
                "cap_pf": cap_pf,
                "tol": tol,
                "voltage": voltage,
                "dimension_fields": decode_tdk_dimension_fields_from_model(model) if mat_end - mat_start == 3 else {},
            }
            break
        if parsed_fields is None:
            return None
        series_profile = tdk_mlcc_series_profile_from_model(model)

        return {
            "品牌": "TDK",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": parsed_fields["size"],
            "材质（介质）": parsed_fields["material"],
            "容值_pf": parsed_fields["cap_pf"],
            "容值误差": parsed_fields["tol"],
            "耐压（V）": parsed_fields["voltage"],
            "_model_rule_authority": "tdk_c_series",
            **parsed_fields["dimension_fields"],
        }
    except:
        return None


def parse_tdk_cga_series(model):
    model = clean_model(model)
    if not model.startswith("CGA") or len(model) < 12:
        return None

    size_map = {
        "1": "0201", "2": "0402", "3": "0603", "4": "0805",
        "5": "1206", "6": "1210", "7": "1808", "8": "1812",
        "9": "2220", "D": "7563",
    }
    material_map = {
        "C0G": "COG(NPO)", "COG": "COG(NPO)", "NP0": "COG(NPO)", "NPO": "COG(NPO)",
        "X5R": "X5R", "X7R": "X7R", "X7S": "X7S", "X7T": "X7T",
        "X6S": "X6S", "X8R": "X8R", "X8L": "X8L",
    }
    voltage_map = {
        "0E": "2.5", "0G": "4", "0J": "6.3", "1A": "10", "1B": "16",
        "1C": "25", "1D": "50", "1E": "100", "1H": "50", "2A": "100",
        "2D": "200", "2E": "250", "2J": "630"
    }
    tol_map = {
        "C": "0.25PF", "D": "0.5PF", "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"
    }

    match = re.fullmatch(
        r"CGA([1-9D])([A-Z])([0-3])?(C0G|COG|NP0|NPO|X5R|X7R|X7S|X7T|X6S|X8R|X8L)([0-3][A-Z])(\d{3,4}|R\d+)([BCDFGJKMZ])(.*)",
        model,
    )
    if not match:
        return None

    try:
        series_profile = tdk_mlcc_series_profile_from_model(model)
        return {
            "品牌": "TDK",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": size_map.get(match.group(1), ""),
            "材质（介质）": clean_material(material_map.get(match.group(4), "")),
            "容值_pf": murata_cap_code_to_pf(match.group(6)),
            "容值误差": clean_tol_for_match(tol_map.get(match.group(7), "")),
            "耐压（V）": clean_voltage(voltage_map.get(match.group(5), "")),
            "_model_rule_authority": "tdk_cga_series",
            **decode_tdk_dimension_fields_from_model(model),
        }
    except:
        return None


def parse_walsin_common(model, brand=""):
    model = clean_model(model)
    brand_text = clean_brand(brand)
    brand_upper = clean_text(brand_text).upper()
    if "WALSIN" not in brand_upper and "华新科" not in brand_text:
        return None
    if len(model) < 11:
        return None

    size_map = {
        "0201": "0201", "0402": "0402", "0603": "0603", "0805": "0805",
        "1206": "1206", "1210": "1210", "1808": "1808", "1812": "1812", "2220": "2220",
        "03": "0201", "05": "0402", "06": "0603", "09": "0805", "11": "0505", "12": "1206",
        "15": "0402", "18": "0603", "21": "0805", "31": "1206", "32": "1210",
        "42": "1808", "43": "1812", "56": "2225",
    }
    material_map = {
        "B": "X7R", "C": "COG(NPO)", "F": "Y5V", "N": "COG(NPO)", "S": "X6S", "T": "X7T", "X": "X5R"
    }
    tol_map = {
        "A": "0.25PF", "B": "0.1PF", "C": "0.25PF", "D": "0.5PF",
        "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20",
    }

    special_01005_match = re.fullmatch(
        r"01R5(?P<mat>[BCNXT])(?P<cap>(?:\d{3,4}|R\d+))(?P<tol>[FGJKMZ])(?P<volt>(?:6R3|\d{3}))(?P<rest>.*)",
        model,
    )
    if special_01005_match:
        volt = special_01005_match.group("volt")
        vmap = {"6R3": "6.3"}
        series_profile = walsin_mlcc_series_profile("01R5")
        return {
            "品牌": "华新科Walsin",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": "01005",
            "材质（介质）": clean_material(material_map.get(special_01005_match.group("mat"), "")),
            "容值_pf": murata_cap_code_to_pf(special_01005_match.group("cap")),
            "容值误差": clean_tol_for_match(tol_map.get(special_01005_match.group("tol"), "")),
            "耐压（V）": clean_voltage(vmap.get(volt, decode_walsin_numeric_mlcc_voltage_code(volt))),
            "_model_rule_authority": "walsin_01005_series",
        }

    alpha_match = re.fullmatch(
        r"(?P<prefix>[A-Z]{2})(?P<size>\d{2})(?P<mat>[BCNXT])(?P<cap>(?:\d{3,4}|R\d+|\dR\d+))(?P<tol>[ABCDEFGJKMZ])(?P<volt>(?:6R3|\d{3}))(?P<rest>.*)",
        model,
    )
    if alpha_match:
        volt = alpha_match.group("volt")
        vmap = {"6R3": "6.3"}
        series_profile = walsin_mlcc_series_profile(alpha_match.group("prefix"))
        return {
            "品牌": "华新科Walsin",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": size_map.get(alpha_match.group("size"), clean_size(alpha_match.group("size"))),
            "材质（介质）": clean_material(material_map.get(alpha_match.group("mat"), "")),
            "容值_pf": murata_cap_code_to_pf(alpha_match.group("cap")),
            "容值误差": clean_tol_for_match(tol_map.get(alpha_match.group("tol"), "")),
            "耐压（V）": clean_voltage(vmap.get(volt, decode_walsin_numeric_mlcc_voltage_code(volt))),
            "_model_rule_authority": "walsin_alpha_prefix",
        }

    size_code = model[:4]
    if not size_code.isdigit():
        return None

    try:
        mat_code = model[4]
        cap_code = model[5:8]
        tol_code = model[8]
        rest = model[9:]
        volt = ""
        if rest.startswith("6R3"):
            volt = "6.3"
        elif len(rest) >= 3 and rest[:3].isdigit():
            vcode = rest[:3]
            volt = decode_walsin_numeric_mlcc_voltage_code(vcode)

        series_profile = walsin_mlcc_series_profile("常规")
        return {
            "品牌": "华新科Walsin",
            "型号": model,
            "器件类型": "MLCC",
            "系列": series_profile["系列"],
            "系列说明": series_profile["系列说明"],
            "特殊用途": series_profile["特殊用途"],
            "_mlcc_series_class": series_profile["_mlcc_series_class"],
            "尺寸（inch）": size_map.get(size_code, ""),
            "材质（介质）": clean_material(material_map.get(mat_code, "")),
            "容值_pf": murata_cap_code_to_pf(cap_code),
            "容值误差": clean_tol_for_match(tol_map.get(tol_code, "")),
            "耐压（V）": clean_voltage(volt),
            "_model_rule_authority": "walsin_numeric_series",
        }
    except:
        return None


def parse_fenghua_am_series(model):
    model = clean_model(model)
    match = FENGHUA_AM_MODEL_PATTERN.fullmatch(model)
    if match is None:
        return None

    size_code = match.group("size")
    dielectric_code = match.group("dielectric")
    cap_code = match.group("cap")
    tol_code = match.group("tol")
    volt_code = match.group("volt")

    size = clean_size(FENGHUA_AM_SIZE_CODE_MAP.get(size_code, ""))
    material = clean_material(FENGHUA_AM_DIELECTRIC_CODE_MAP.get(dielectric_code, ""))
    cap_pf = murata_cap_code_to_pf(cap_code)
    cap_value, cap_unit = pf_to_value_unit(cap_pf) if cap_pf is not None else ("", "")
    tol = clean_tol_for_match(FENGHUA_AM_TOLERANCE_CODE_MAP.get(tol_code, ""))
    volt = clean_voltage(FENGHUA_AM_VOLTAGE_CODE_MAP.get(volt_code, volt_code))
    dimension_fields = fenghua_am_dimension_fields_from_model(model)
    param_count = sum([
        1 if size != "" else 0,
        1 if material != "" else 0,
        1 if cap_pf is not None else 0,
        1 if tol != "" else 0,
        1 if volt != "" else 0,
    ])

    result = {
        "品牌": "风华Fenghua",
        "型号": model,
        "器件类型": "MLCC",
        "系列": "AM",
        "系列说明": fenghua_am_series_meaning("AM"),
        "尺寸（inch）": size,
        "材质（介质）": material,
        "容值_pf": cap_pf,
        "容值": clean_text(cap_value),
        "容值单位": clean_text(cap_unit).upper(),
        "容值误差": tol,
        "耐压（V）": volt,
        "安装方式": "贴片",
        "_model_rule_authority": "fenghua_am_series",
        "_param_count": param_count,
    }
    if dimension_fields:
        result.update(dimension_fields)
    return result



def parse_cap_token_to_pf(token):
    t = clean_text(token).lower().replace(" ", "")
    t = t.replace("μf", "uf")
    if t == "":
        return None

    m = re.match(r"^(\d+(?:\.\d+)?)(pf|nf|uf)$", t)
    if m:
        val = float(m.group(1))
        unit = m.group(2).upper()
        return cap_to_pf(val, unit)

    if re.fullmatch(r"\d{3,4}", t):
        return eia_code_to_pf(t)

    return None




def looks_like_spec_query(line):
    raw = clean_text(line).upper()
    if raw == "":
        return False
    if re.search(r"[\s,/\\|;:%]", raw):
        return True
    spec_keywords = [
        "X5R", "X7R", "X7S", "X7T", "Y5V", "COG", "NPO", "C0G", "NP0", "X6S",
        "UF", "NF", "PF", "6R3", "10%", "5%", "20%", "630V", "6.3V",
        "OHM", "Ω", "电阻", "电解", "脚距", "PITCH"
    ]
    if any(k in raw for k in spec_keywords):
        return True
    if any(size_code in raw for size_code in {"008004", "01005", "015008"}):
        return True
    if raw[:4].isdigit() and raw[:4] in {"0100", "0102", "0201", "0401", "0402", "0603", "0805", "1206", "1210", "1808", "1812", "1825", "2220"}:
        return True
    if re.fullmatch(r"\d{3,4}[FGJKMZ]?", raw):
        return True
    return False


def count_core_params(spec):
    if spec is None:
        return 0
    explicit_count = spec.get("_core_param_count")
    if explicit_count is not None:
        try:
            return int(explicit_count)
        except:
            pass
    return sum([
        1 if clean_text(spec.get("尺寸（inch）", "")) != "" else 0,
        1 if clean_text(spec.get("材质（介质）", "")) != "" else 0,
        1 if spec.get("容值_pf", None) is not None else 0,
        1 if clean_text(spec.get("容值误差", "")) != "" else 0,
        1 if clean_text(spec.get("耐压（V）", "")) != "" else 0,
    ])


def count_query_params(spec):
    if spec is None:
        return 0
    explicit_count = spec.get("_param_count")
    if explicit_count is not None:
        try:
            return int(explicit_count)
        except:
            pass
    return count_core_params(spec)


def other_passive_min_required_params(spec):
    if spec is None:
        return 2
    component_type = normalize_component_type(spec.get("器件类型", ""))
    if component_type in SEMICONDUCTOR_COMPONENT_TYPES:
        return 2
    if component_type in TIMING_COMPONENT_TYPES:
        return 2
    if component_type in (RESISTOR_COMPONENT_TYPES | {"热敏电阻"}):
        return 1 if spec.get("_resistance_ohm") is not None else 2
    if component_type in VARISTOR_COMPONENT_TYPES:
        varistor_voltage = clean_voltage(spec.get("_varistor_voltage", "")) or clean_voltage(spec.get("耐压（V）", ""))
        disc_size = clean_text(spec.get("_disc_size", ""))
        return 1 if (varistor_voltage != "" or disc_size != "") else 2
    if component_type in {"铝电解电容", "薄膜电容", "钽电容"}:
        return 2
    return 2


OTHER_PASSIVE_TYPES = ALL_PASSIVE_COMPONENT_TYPES - {"MLCC"}


def is_other_passive_mode(mode):
    return clean_text(mode) in OTHER_PASSIVE_TYPES or clean_text(mode) == "其他器件"


def normalized_other_passive_mode(spec, fallback="其他器件"):
    component_type = normalize_component_type(spec.get("器件类型", "")) if spec else ""
    if component_type in OTHER_PASSIVE_TYPES:
        return component_type
    fallback_text = clean_text(fallback)
    if fallback_text in OTHER_PASSIVE_TYPES:
        return fallback_text
    return fallback_text or "其他器件"


def looks_like_compact_part_query(line):
    raw = clean_model(line)
    if raw == "":
        return False
    source_text = clean_text(line).upper()
    spaced_suffix_model = bool(
        re.fullmatch(r"[A-Z][A-Z0-9._-]{5,}\s+[A-Z0-9._-]{1,6}", source_text)
        and len(re.findall(r"[A-Z]", raw)) >= 3
        and len(re.findall(r"\d", raw)) >= 3
    )
    if re.search(r"[,/\\|;:]", source_text) or (re.search(r"\s", source_text) and not spaced_suffix_model):
        return False
    if not (re.search(r"[A-Z]", raw) and re.search(r"\d", raw)):
        return False

    # Short industrial/inductor model names such as ICM2020-A or ILHB-1206
    # are valid compact part queries, but they used to miss the older length-only
    # heuristic and fall all the way back to the full dataframe path.
    if len(raw) >= 8 and (
        re.fullmatch(r"[A-Z]{2,8}\d{3,6}[A-Z0-9-]*", raw)
        or re.fullmatch(r"[A-Z]{2,8}-\d{3,6}[A-Z0-9-]*", raw)
    ):
        return True

    known_prefixes = (
        "CL", "AM", "FP", "FS", "FN", "FM", "FV", "FK", "FH",
        "GRM", "GCM", "GCJ", "GJM", "GQM",
        "TCC", "TMK", "JMK", "EMK", "LMK", "AMK", "CC",
        "ECG2", "ECR", "ECS1", "ECS2", "ECA1", "ECC1", "ECV", "PHR1", "PHV1", "PCP",
    )
    if raw.startswith(known_prefixes):
        return True
    if raw.startswith("C") and len(raw) >= 14:
        return True
    if len(raw) >= 11 and raw[:4].isdigit():
        return True
    alpha_count = len(re.findall(r"[A-Z]", raw))
    digit_count = len(re.findall(r"\d", raw))
    if len(raw) >= 12 and alpha_count >= 3 and digit_count >= 3:
        return True
    return False

def parse_cap_token_to_pf(token):
    t = clean_text(token).lower().replace(" ", "")
    t = t.replace("μf", "uf").replace("µf", "uf")
    if t == "":
        return None

    # 1uf / 100nf / 47pf / 0.1uf
    m = re.match(r"^(\d+(?:\.\d+)?)(pf|nf|uf)$", t)
    if m:
        val = float(m.group(1))
        unit = m.group(2).upper()
        return cap_to_pf(val, unit)

    # 105 / 104 / 474 / 1005
    if re.fullmatch(r"\d{3,4}", t):
        return eia_code_to_pf(t)

    # 102P / 224P 常见 BOM 写法：视为 EIA 容值码
    if re.fullmatch(r"\d{3,4}p", t):
        return eia_code_to_pf(t[:-1])

    # 22P / 4N7 / 1U0 这类紧凑写法
    compact_suffix_match = re.fullmatch(r"(\d+(?:\.\d+)?)([PNU])", t.upper())
    if compact_suffix_match:
        num = float(compact_suffix_match.group(1))
        unit = {"P": "PF", "N": "NF", "U": "UF"}[compact_suffix_match.group(2)]
        return cap_to_pf(num, unit)

    # 1U0 / 4N7 / 2P2 style (optional support)
    m2 = re.match(r"^(\d+)([UPN])(\d+)$", t.upper())
    if m2:
        a, u, b = m2.groups()
        num = float(f"{a}.{b}")
        unit = {"P": "PF", "N": "NF", "U": "UF"}[u]
        return cap_to_pf(num, unit)

    m3 = re.match(r"^(\d*)R(\d+)$", t.upper())
    if m3:
        a, b = m3.groups()
        num = float(f"{a or '0'}.{b}")
        return cap_to_pf(num, "PF")

    return None

def parse_spec_query(line):
    raw = clean_text(line)
    if raw == "":
        return None

    s = raw.upper()
    s = s.replace("μF", "UF").replace("µF", "UF")
    s = s.replace("％", "%").replace("﹪", "%")
    s = s.replace("＋", "+").replace("﹢", "+")
    s = s.replace("／", "/").replace("\\", "/")
    s = s.replace("±", "+/-").replace("卤", "+/-")
    s = s.replace("_", " ")

    # 把连写的 “容值/电压 + 容差” 拆开，避免 6.3V±20% / 1PF±0.1PF 这类格式被误判
    s = re.sub(r"(\d+(?:\.\d+)?(?:PF|NF|UF|V))(\+/-)", r"\1 \2", s)
    s = re.sub(r"(\+/-\s*\d+(?:\.\d+)?%?)(?=\d+(?:\.\d+)?V\b)", r"\1 ", s)
    s = re.sub(r"(\d+R\d+)(\+/-)", r"\1 \2", s)
    s = re.sub(r"(\d{3,4}P)(\+/-)", r"\1 \2", s)

    s = s.replace("+/-", " PLUSMINUS ")
    for old in ["，", ",", "/", "|", ";", "；", "(", ")", "（", "）", "：", ":", "OR", "或"]:
        s = s.replace(old, " ")
    s = s.replace("PLUSMINUS", "+/-")
    s = re.sub(r"(\+/-)\s*(\d+(?:\.\d+)?(?:PF|%))", r"\1\2", s)

    # split combined patterns like 105K / 474K / 104J / 6R3V
    s = re.sub(r"(\d{3,4})([FGJKMZ])\b", r"\1 \2", s)
    s = re.sub(r"(\d+R\d+)(V)\b", r"\1 \2", s)
    s = re.sub(r"\s+", " ", s).strip()

    tokens = s.split(" ")
    invalid_size_token = find_invalid_leading_zero_size_token(tokens)

    size = find_embedded_size(raw)
    material = find_embedded_material(raw)
    special_use = normalize_mlcc_series_class(raw)
    cap_pf = None
    tol = ""
    volt = ""

    size_candidates = {"008004", "01005", "0102", "015008", "0201", "0401", "0402", "0603", "0805", "1206", "1210", "1808", "1812", "1825", "2220"}
    material_candidates = {"X5R", "X7R", "X7S", "X7T", "Y5V", "COG", "NPO", "COG(NPO)", "C0G", "NP0", "X6S"}
    tol_letter_map = {"F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"}

    compact_raw = raw.upper().replace(" ", "")
    if tol == "":
        pf_tol_match = re.search(r"(\+/-\d+(?:\.\d+)?PF)", compact_raw)
        if pf_tol_match:
            tol = clean_tol_for_match(pf_tol_match.group(1))
    if tol == "":
        percent_tol_match = re.search(r"(\+/-\d+(?:\.\d+)?%)", compact_raw)
        if percent_tol_match:
            tol = clean_tol_for_match(percent_tol_match.group(1))
    if tol == "":
        asym_tol_match = re.search(r"(\+\d+(?:\.\d+)?%?/-\d+(?:\.\d+)?%?)", compact_raw)
        if asym_tol_match:
            tol = clean_tol_for_match(asym_tol_match.group(1))

    for token in tokens:
        t = token.strip().upper()
        if t == "":
            continue

        # size
        if size == "" and t in size_candidates:
            size = t
            continue
        if size == "":
            embedded_size = find_embedded_size(t)
            if embedded_size != "":
                size = embedded_size

        if t in size_candidates:
            continue

        # material
        if material == "" and t in material_candidates:
            material = clean_material(t)
            continue
        if material == "":
            embedded_material = find_embedded_material(t)
            if embedded_material != "":
                material = embedded_material

        # capacitance: handle explicit values before tolerance so `12PF`
        # is not mistaken for a +/-12pF tolerance in slash-separated specs.
        pf = parse_cap_token_to_pf(t)
        if cap_pf is None and pf is not None:
            cap_pf = pf
            continue

        # tolerance
        if tol == "":
            parsed_tol = parse_tolerance_token(t)
            if parsed_tol != "":
                tol = parsed_tol
                continue
            if t in tol_letter_map:
                tol = clean_tol_for_match(tol_letter_map[t])
                continue

        # voltage
        if volt == "" and re.fullmatch(r"\d+(?:\.\d+)?V", t):
            volt = clean_voltage(t)
            continue
        if volt == "" and re.fullmatch(r"\d+R\d+", t):
            volt = clean_voltage(t.replace("R", "."))
            continue
        if volt == "" and re.fullmatch(r"\d+(?:\.\d+)?", t) and "." in t:
            num = float(t)
            if 0 < num <= 1000:
                volt = clean_voltage(t)
                continue
        # common bare voltages when clearly voltage-like
        if volt == "" and t in {"4", "6.3", "10", "16", "25", "35", "50", "100", "200", "250", "500", "630", "1000"}:
            volt = clean_voltage(t)
            continue

    if cap_pf is None:
        explicit_cap_match = re.search(r"(?<!\d)(\d+(?:\.\d+)?)(PF|NF|UF)(?![A-Z])", compact_raw)
        if explicit_cap_match:
            cap_pf = cap_to_pf(explicit_cap_match.group(1), explicit_cap_match.group(2))
    if cap_pf is None:
        compact_code_match = re.search(r"(?<!\d)(\d{3,4})P(?![A-Z0-9])", compact_raw)
        if compact_code_match:
            cap_pf = eia_code_to_pf(compact_code_match.group(1))

    param_count = sum([
        1 if size else 0,
        1 if material else 0,
        1 if cap_pf is not None else 0,
        1 if tol else 0,
        1 if volt else 0,
        1 if special_use else 0,
    ])

    if param_count == 0:
        return None

    result = {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": size,
        "材质（介质）": material,
        "容值_pf": cap_pf,
        "容值误差": tol,
        "耐压（V）": clean_voltage(volt),
        "特殊用途": special_use,
        "_mlcc_series_class": special_use,
        "_param_count": param_count
    }
    if invalid_size_token != "":
        result["_invalid_size_token"] = invalid_size_token
        result["_unsupported_component"] = True
        result["_unsupported_reason"] = (
            f"尺寸输入错误：{invalid_size_token} 不是当前规格库支持的封装尺寸；"
            "请确认尺寸输入是否正确，例如 0201、0402、0603、0805、1206 等。"
        )
    return result

def format_resistance_display(ohm_value):
    try:
        ohm = float(ohm_value)
    except:
        return ""
    if 0 < ohm < 1:
        value = ohm * 1000
        text = f"{value:.3f}".rstrip("0").rstrip(".")
        return f"{text}mΩ"
    if ohm >= 1000000:
        value = ohm / 1000000
        text = f"{value:.3f}".rstrip("0").rstrip(".")
        return f"{text}MΩ"
    if ohm >= 1000:
        value = ohm / 1000
        text = f"{value:.3f}".rstrip("0").rstrip(".")
        return f"{text}KΩ"
    text = f"{ohm:.3f}".rstrip("0").rstrip(".")
    return f"{text}Ω"

def parse_explicit_resistance_measurement_to_ohm(value_text, unit_text):
    try:
        numeric = float(clean_text(value_text))
    except Exception:
        return None
    unit = clean_text(unit_text).replace("Ω", "Ω").replace("ω", "Ω")
    if unit == "":
        return None
    unit_upper = unit.upper()
    if unit == "mΩ" or unit in {"mR", "mr", "mohm", "mohms"} or unit == "毫欧":
        return numeric / 1000.0
    if unit == "MΩ" or unit in {"MR", "Mr"} or unit_upper in {"MOHM", "MOHMS"}:
        return numeric * 1_000_000.0
    if unit_upper in {"KΩ", "KOHM", "KOHMS"}:
        return numeric * 1000.0
    if unit_upper in {"OHM", "OHMS", "Ω"}:
        return numeric
    return None


def find_explicit_resistance_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return None
    raw = raw.replace("Ω", "Ω").replace("ω", "Ω")
    raw = re.sub(r"\bohms?\b", "OHM", raw, flags=re.I)
    for match in EXPLICIT_RESISTANCE_MEASUREMENT_PATTERN.finditer(raw):
        ohm = parse_explicit_resistance_measurement_to_ohm(match.group(1), match.group(2))
        if ohm is not None:
            return ohm
    return None


def parse_resistance_token_to_ohm(token):
    raw = clean_text(token).replace(" ", "")
    raw = raw.replace("毫欧", "mΩ")
    raw = raw.replace("OHMS", "Ω").replace("OHM", "Ω").replace("ohms", "Ω").replace("ohm", "Ω")
    explicit_ohm = find_explicit_resistance_in_text(raw)
    if explicit_ohm is not None:
        return explicit_ohm
    t = raw.upper()
    if t.endswith("Ω"):
        bare = t[:-1]
        if re.fullmatch(r"\d+(?:\.\d+)?(?:[RKM])", bare) or re.fullmatch(r"\d+[RKM]\d+", bare):
            t = bare
        elif re.fullmatch(r"\d+(?:\.\d+)?", bare):
            t = bare + "R"
        else:
            t = bare
    if t == "":
        return None
    leading_r_match = re.fullmatch(r"R(\d+(?:\.\d+)?)", t)
    if leading_r_match:
        digits = leading_r_match.group(1)
        if "." in digits:
            return float(f"0{digits}")
        return float(digits) / (10 ** len(digits))
    direct_match = re.fullmatch(r"(\d+(?:\.\d+)?)([RKM])", t)
    if direct_match:
        value = float(direct_match.group(1))
        unit = direct_match.group(2)
        multiplier = {"R": 1, "K": 1000, "M": 1000000}[unit]
        return value * multiplier
    compact_match = re.fullmatch(r"(\d+)([RKM])(\d+)", t)
    if compact_match:
        whole, unit, frac = compact_match.groups()
        value = float(f"{whole}.{frac}")
        multiplier = {"R": 1, "K": 1000, "M": 1000000}[unit]
        return value * multiplier
    plain_match = re.fullmatch(r"\d+(?:\.\d+)?", t)
    if plain_match:
        return float(t)
    return None

def normalize_common_tolerance_symbol_typos(text):
    value = clean_text(text).replace("％", "%").replace("﹪", "%")
    return re.sub(r"(?<![\u4e00-\u9fff])[士土]\s*(?=\d+(?:\.\d+)?\s*%)", "±", value)


def find_resistance_in_text(text):
    raw = normalize_common_tolerance_symbol_typos(text).replace("±", "+/-").replace("卤", "+/-")
    explicit_ohm = find_explicit_resistance_in_text(raw)
    if explicit_ohm is not None:
        return explicit_ohm
    upper = raw.upper().replace("OHMS", "Ω").replace("OHM", "Ω")
    ohm_match = RESISTOR_OHM_PATTERN.search(upper)
    if ohm_match:
        return parse_resistance_token_to_ohm(ohm_match.group(1))
    resistor_context = detect_component_type_hint(upper) in (RESISTOR_COMPONENT_TYPES | {"热敏电阻"}) or looks_like_resistor_context(upper)
    if resistor_context:
        compact_match = RESISTOR_COMPACT_CONTEXT_PATTERN.search(upper)
        if compact_match:
            return parse_resistance_token_to_ohm(compact_match.group(1))
    match = RESISTOR_VALUE_PATTERN.search(upper)
    if match:
        return parse_resistance_token_to_ohm(match.group(1))
    return None


def find_leading_unlabeled_resistance_in_resistor_text(text):
    """Parse BOM rows whose first resistor field omits R/ohm, e.g. ``150,50mW``."""
    raw = clean_text(text)
    if raw == "":
        return None
    upper = raw.upper()
    if not any(token in upper for token in ("RESISTOR", "电阻", "電阻")):
        return None
    match = re.match(
        r"^\s*(\d+(?:\.\d+)?)\s*[,，;；|]\s*(?=\d+(?:\.\d+)?\s*(?:MW|W)(?![A-Z0-9]))",
        upper,
        flags=re.I,
    )
    if not match:
        return None
    try:
        value = float(match.group(1))
    except (TypeError, ValueError):
        return None
    return value if value >= 0 else None


_RESISTOR_SERIES_PRICING_CACHE = {"mtime": None, "rules": None}


def normalize_resistor_pricing_type_dimension(value):
    raw = clean_text(value).replace("\u3000", " ")
    raw = re.sub(r"\s+", " ", raw).strip()
    if raw == "":
        return ""
    parts = raw.split(" ")
    size = clean_size(parts[0]) if parts else ""
    power = format_power_display(parts[-1]) if len(parts) >= 2 else ""
    if size == "" or power == "":
        return raw.upper()
    return f"{size} {power}"


def load_resistor_series_pricing_rules():
    path = RESISTOR_SERIES_PRICING_PATH
    try:
        mtime = os.path.getmtime(path)
    except Exception:
        _RESISTOR_SERIES_PRICING_CACHE["mtime"] = None
        _RESISTOR_SERIES_PRICING_CACHE["rules"] = []
        return []
    if (
        _RESISTOR_SERIES_PRICING_CACHE.get("mtime") == mtime
        and _RESISTOR_SERIES_PRICING_CACHE.get("rules") is not None
    ):
        return _RESISTOR_SERIES_PRICING_CACHE["rules"]
    try:
        raw_df = pd.read_csv(path, dtype=str).fillna("")
    except Exception:
        rules = []
    else:
        rules = []
        for record in raw_df.to_dict("records"):
            rule = {
                "series": clean_text(record.get("Series", "")).upper(),
                "type_dimension": clean_text(record.get("TypeDimension", "")),
                "type_dimension_norm": normalize_resistor_pricing_type_dimension(record.get("TypeDimension", "")),
                "range": clean_text(record.get("ResistanceRange", "")),
                "price_5": clean_text(record.get("Price5Percent", "")),
                "price_1": clean_text(record.get("Price1Percent", "")),
                "package": clean_text(record.get("Package", "")),
            }
            if rule["series"] != "" and rule["type_dimension_norm"] != "" and rule["range"] != "":
                rules.append(rule)
    _RESISTOR_SERIES_PRICING_CACHE["mtime"] = mtime
    _RESISTOR_SERIES_PRICING_CACHE["rules"] = rules
    return rules


def normalize_resistor_pricing_series(row):
    brand_text = clean_text(row.get("品牌", "")).upper()
    if "FOJAN" not in brand_text and "富捷" not in brand_text:
        return ""
    series_text = clean_text(row.get("系列", "")).upper()
    model_text = clean_model(row.get("型号", "")).upper()
    for prefix in ("FRC", "FRL"):
        if series_text == prefix or series_text.startswith(prefix):
            return prefix
        if model_text.startswith(prefix):
            return prefix
    return ""


def resistance_range_group_matches(range_group, resistance_ohm):
    text = clean_text(range_group).upper()
    if text == "" or resistance_ohm is None:
        return False
    text = text.replace("，", ",").replace("－", "-").replace("–", "-").replace("—", "-").replace("~", "-").replace("～", "-")
    alternatives = [clean_text(part) for part in text.split(",") if clean_text(part) != ""]
    for part in alternatives:
        if "-" in part:
            left, right = [clean_text(piece) for piece in part.split("-", 1)]
            low = parse_resistance_token_to_ohm(left)
            high = parse_resistance_token_to_ohm(right)
            if low is None or high is None:
                continue
            if low > high:
                low, high = high, low
            epsilon = max(1e-9, abs(resistance_ohm) * 1e-9)
            if resistance_ohm + epsilon >= low and resistance_ohm - epsilon <= high:
                return True
        else:
            target = parse_resistance_token_to_ohm(part)
            if target is None:
                continue
            epsilon = max(1e-9, abs(target) * 1e-9)
            if abs(resistance_ohm - target) <= epsilon:
                return True
    return False


def select_resistor_segment_price(range_text, price_text, resistance_ohm):
    price_text = clean_text(price_text)
    if price_text == "":
        return ""
    range_groups = [clean_text(part) for part in clean_text(range_text).split("/") if clean_text(part) != ""]
    if not range_groups:
        range_groups = [clean_text(range_text)]
    price_groups = [clean_text(part) for part in price_text.split("/") if clean_text(part) != ""]
    for idx, range_group in enumerate(range_groups):
        if not resistance_range_group_matches(range_group, resistance_ohm):
            continue
        if len(price_groups) == len(range_groups):
            return price_groups[idx]
        return price_text
    return ""


def get_row_resistance_for_pricing(row):
    for col in ("_res_ohm", "_resistance_ohm"):
        try:
            value = row.get(col, None)
            if value is not None and not pd.isna(value):
                return float(value)
        except Exception:
            pass
    explicit = find_resistance_in_text(
        " ".join(
            clean_text(part)
            for part in [
                row.get("阻值@25C", ""),
                row.get("规格摘要", ""),
                row.get("匹配参数明细", ""),
                f"{clean_text(row.get('容值', ''))}{clean_text(row.get('容值单位', ''))}",
                f"{clean_text(row.get('参数值', ''))}{clean_text(row.get('参数单位', ''))}",
            ]
            if clean_text(part) != ""
        )
    )
    return explicit


def lookup_resistor_series_pricing(row):
    component_type = normalize_component_type(row.get("器件类型", ""))
    if component_type not in RESISTOR_COMPONENT_TYPES:
        return {"成本": "", "更新时间": "", "MOQ": ""}
    series = normalize_resistor_pricing_series(row)
    if series == "":
        return {"成本": "", "更新时间": "", "MOQ": ""}
    size = clean_size(row.get("尺寸（inch）", ""))
    if size == "":
        size = infer_resistor_size_from_model(row.get("型号", ""))
    power_text = infer_resistor_power_text_from_record(row)
    if clean_text(power_text) == "":
        power_text = row.get("功率", "") or row.get("_power", "")
    power = format_power_display(power_text)
    if size == "" or power == "":
        return {"成本": "", "更新时间": "", "MOQ": ""}
    resistance_ohm = get_row_resistance_for_pricing(row)
    if resistance_ohm is None:
        return {"成本": "", "更新时间": "", "MOQ": ""}
    tol = clean_tol_for_match(row.get("容值误差", "") or row.get("_tol", ""))
    price_key = "price_1" if tol == "1" else "price_5" if tol == "5" else ""
    if price_key == "":
        return {"成本": "", "更新时间": "", "MOQ": ""}
    type_dimension = f"{size} {power}"
    if series == "FRC" and price_key == "price_1" and abs(float(resistance_ohm)) <= 1e-12:
        for rule in load_resistor_series_pricing_rules():
            if rule.get("series") != series or rule.get("type_dimension_norm") != type_dimension:
                continue
            price = select_resistor_segment_price(rule.get("range", ""), rule.get("price_1", ""), 10.0)
            if price != "":
                return {
                    "成本": price,
                    "更新时间": RESISTOR_SERIES_PRICING_UPDATED_AT,
                    "MOQ": rule.get("package", ""),
                }
        return {"成本": "", "更新时间": "", "MOQ": ""}
    for rule in load_resistor_series_pricing_rules():
        if rule.get("series") != series:
            continue
        if rule.get("type_dimension_norm") != type_dimension:
            continue
        price = select_resistor_segment_price(rule.get("range", ""), rule.get(price_key, ""), resistance_ohm)
        if price != "":
            return {"成本": price, "更新时间": RESISTOR_SERIES_PRICING_UPDATED_AT, "MOQ": rule.get("package", "")}
    return {"成本": "", "更新时间": "", "MOQ": ""}


def enrich_resistor_pricing_columns(df):
    if df is None:
        return df
    out = df.copy()
    if out.empty:
        out["成本"] = ""
        out["更新时间"] = ""
        out["MOQ"] = ""
        return out
    pricing_rows = out.apply(lookup_resistor_series_pricing, axis=1)
    out["成本"] = [item.get("成本", "") for item in pricing_rows]
    out["更新时间"] = [item.get("更新时间", "") for item in pricing_rows]
    out["MOQ"] = [item.get("MOQ", "") for item in pricing_rows]
    return out


def find_inductance_in_text(text):
    upper = clean_text(text).upper().replace("μ", "U").replace("µ", "U").replace("Μ", "U")
    match = INDUCTANCE_PATTERN.search(upper)
    if not match:
        return ""
    return f"{match.group(1)}{match.group(2).upper()}"


def text_contains_inductance_range(text):
    upper = clean_text(text).upper().replace("μ", "U").replace("µ", "U").replace("Μ", "U")
    if upper == "":
        return False
    if "INDUCTANCE RANGE" in upper:
        return True
    return bool(
        re.search(
            r"\d+(?:\.\d+)?\s*(?:-|~|–|TO)\s*\d+(?:\.\d+)?\s*(NH|UH|MH|H)\b",
            upper,
            flags=re.I,
        )
    )

def find_current_in_text(text):
    upper = clean_text(text).upper()
    matches = CURRENT_PATTERN.findall(upper)
    if not matches:
        return ""
    for value, unit in matches:
        if unit.upper() == "A" or float(value) >= 1:
            return f"{value}{unit.upper()}"
    value, unit = matches[0]
    return f"{value}{unit.upper()}"


def text_contains_current_range(text):
    upper = clean_text(text).upper()
    if upper == "":
        return False
    if "CURRENT RANGE" in upper:
        return True
    return bool(
        re.search(
            r"\d+(?:\.\d+)?\s*(?:-|~|–|TO)\s*\d+(?:\.\d+)?\s*(UA|MA|A)\b",
            upper,
            flags=re.I,
        )
    )


def find_labeled_current_in_text(text, labels):
    upper = clean_text(text).upper().replace("DC MAX.", "DC").replace("DC MAX", "DC")
    if upper == "":
        return ""
    if isinstance(labels, str):
        labels = [labels]
    for label in labels or []:
        label_text = clean_text(label).upper()
        if label_text == "":
            continue
        pattern = re.compile(rf"{re.escape(label_text)}[^0-9]{{0,40}}(\d+(?:\.\d+)?)\s*(UA|MA|A)\b", flags=re.I)
        match = pattern.search(upper)
        if match:
            return f"{match.group(1)}{match.group(2).upper()}"
    return ""


def find_frequency_in_text(text):
    upper = clean_text(text).upper()
    match = FREQUENCY_PATTERN.search(upper)
    if not match:
        return ""
    return f"{match.group(1)}{match.group(2).upper()}"


def find_frequency_tolerance_in_text(text):
    upper = clean_text(text).upper().replace("±", "+/-")
    if upper == "":
        return ""
    match = re.search(r"(\+/-)\s*(\d+(?:\.\d+)?)\s*(PPM|%)", upper, flags=re.I)
    if match:
        return f"{match.group(1)}{match.group(2)}{match.group(3).upper()}"
    match = re.search(r"(\d+(?:\.\d+)?)\s*(PPM)\b", upper, flags=re.I)
    if match:
        return f"{match.group(1)}{match.group(2).upper()}"
    return ""


def clean_frequency_tolerance_for_match(value):
    text = clean_text(value).upper().replace("±", "+/-").replace("PPM", "")
    return clean_tol_for_match(text)


def clean_frequency_tolerance_for_display(value):
    normalized = clean_frequency_tolerance_for_match(value)
    if normalized == "":
        return ""
    return f"±{normalized}ppm" if re.fullmatch(r"\d+(?:\.\d+)?", normalized) else normalized


TIMING_TEMPERATURE_CHARACTERISTIC_LABEL = (
    r"(?:频率温度特性|温度特性|温度范围频差|温度稳定度|"
    r"FREQUENCY\s*(?:TOLERANCE|STABILITY)[^,;，；]{0,18}(?:TEMP|TEMPERATURE)|"
    r"TEMP(?:ERATURE)?\s*(?:RANGE\s*)?(?:TOLERANCE|STABILITY))"
)
TIMING_AGING_LABEL = r"(?:25\s*(?:℃|°C|C)?\s*老化|老化|AGING)"


def find_labeled_timing_ppm_in_text(text, label_pattern):
    raw = clean_text(text).replace("±", "+/-")
    if raw == "":
        return ""
    pattern = (
        rf"{label_pattern}[^0-9+\-]{{0,24}}"
        rf"(?:\+/-\s*)?([+\-]?\d+(?:\.\d+)?)\s*PPM\b"
    )
    match = re.search(pattern, raw, flags=re.I)
    if not match:
        return ""
    normalized = clean_frequency_tolerance_for_match(match.group(1))
    return clean_frequency_tolerance_for_display(normalized)


def find_primary_timing_tolerance_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    masked = raw.replace("±", "+/-")
    detail_patterns = [
        rf"{TIMING_TEMPERATURE_CHARACTERISTIC_LABEL}[^,;，；]{{0,36}}?(?:PPM)\b",
        rf"{TIMING_AGING_LABEL}[^,;，；]{{0,28}}?(?:PPM)\b",
    ]
    for pattern in detail_patterns:
        masked = re.sub(pattern, " ", masked, flags=re.I)
    return find_frequency_tolerance_in_text(masked)


def find_turnover_temperature_in_text(text):
    raw = clean_text(text).replace("±", "+/-")
    if raw == "":
        return ""
    match = re.search(
        r"(?:拐点温度|TURNOVER\s*TEMPERATURE)[^0-9+\-]{0,24}"
        r"([+\-]?\d+(?:\.\d+)?)\s*(?:℃|°C|C)?\s*"
        r"(?:\+/-)\s*(\d+(?:\.\d+)?)\s*(?:℃|°C|C)?",
        raw,
        flags=re.I,
    )
    if not match:
        return ""
    center = _format_compact_number(float(match.group(1)))
    tolerance = _format_compact_number(float(match.group(2)))
    if not center.startswith("-"):
        center = f"+{center}"
    return f"{center}℃ ±{tolerance}℃"


def find_parabolic_coefficient_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    match = re.search(
        r"(?:抛物线系数|PARABOLIC\s*COEFFICIENT)[^0-9+\-]{0,24}"
        r"([+\-]?\d+(?:\.\d+)?)",
        raw,
        flags=re.I,
    )
    if not match:
        return ""
    return f"{_format_compact_number(float(match.group(1)))}ppm/℃²"


def normalize_timing_overtone_order(value):
    text = clean_text(value).upper()
    if text == "":
        return ""
    compact = re.sub(r"[^A-Z0-9\u4e00-\u9fff]+", "", text)
    if "FUNDAMENTAL" in compact or "基频" in compact or "基波" in compact:
        return "FUNDAMENTAL"
    if (
        "3RDOVERTONE" in compact
        or "THIRDOVERTONE" in compact
        or "三次泛音" in compact
        or "3次泛音" in compact
    ):
        return "3RD OVERTONE"
    if "OVERTONE" in compact or "泛音" in compact:
        return compact
    return text


def find_timing_overtone_order_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    normalized = normalize_timing_overtone_order(raw)
    if normalized in {"FUNDAMENTAL", "3RD OVERTONE"}:
        return normalized
    return ""


def _find_labeled_resistive_measurement(text, labels):
    raw = clean_text(text).replace("OHMS", "OHM").replace("ohms", "ohm")
    if raw == "":
        return ""
    if isinstance(labels, str):
        labels = [labels]
    for label in labels or []:
        label_text = clean_text(label)
        if label_text == "":
            continue
        pattern = re.compile(rf"{re.escape(label_text)}[^0-9]{{0,48}}(\d+(?:\.\d+)?)\s*(mΩ|MΩ|KΩ|MOHM|KOHM|OHM|Ω)", flags=re.I)
        match = pattern.search(raw)
        if match:
            return combine_value_and_unit(match.group(1), normalize_library_value_unit(match.group(2)), separator="")
    return ""


def find_dcr_in_text(text):
    return _find_labeled_resistive_measurement(text, ["DCR", "DC RESISTANCE"])


def find_unlabeled_dcr_in_inductor_text(text):
    raw = clean_text(text).replace("OHMS", "OHM").replace("ohms", "ohm")
    if raw == "":
        return ""
    upper = raw.upper()
    for match in re.finditer(r"(?<![A-Z0-9])(\d+(?:\.\d+)?)\s*(mΩ|MΩ|KΩ|MOHM|KOHM|OHM|Ω)(?![A-Z0-9])", raw, flags=re.I):
        prefix = upper[max(0, match.start() - 24):match.start()]
        if re.search(r"(ESR|IMPEDANCE|阻抗|Z)\s*$", prefix, flags=re.I):
            continue
        unit = normalize_library_value_unit(match.group(2))
        return combine_value_and_unit(match.group(1), unit, separator="")
    return ""


def find_esr_in_text(text):
    return _find_labeled_resistive_measurement(text, ["ESR"])


def text_contains_impedance_range(text):
    upper = clean_text(text).upper()
    if upper == "":
        return False
    if "IMPEDANCE RANGE" in upper:
        return True
    return bool(
        re.search(
            r"\d+(?:,\d{3})*(?:\.\d+)?\s*(OHM|Ω)\s*(?:-|~|–|TO)\s*\d+(?:,\d{3})*(?:\.\d+)?\s*(OHM|Ω)?",
            upper,
            flags=re.I,
        )
    )


def find_impedance_at_100mhz_in_text(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    match = re.search(r"100\s*MHZ[^0-9]{0,24}(\d+(?:\.\d+)?)\s*(OHM|Ω)", upper, flags=re.I)
    if match:
        return combine_value_and_unit(match.group(1), normalize_library_value_unit(match.group(2)), separator="")
    match = re.search(r"IMPEDANCE[^0-9]{0,24}(\d+(?:\.\d+)?)\s*(OHM|Ω)", upper, flags=re.I)
    if match:
        return combine_value_and_unit(match.group(1), normalize_library_value_unit(match.group(2)), separator="")
    return ""


def find_impedance_in_text(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    labeled = find_impedance_at_100mhz_in_text(text)
    if labeled != "":
        return labeled
    match = re.search(
        r"(?<![A-Z0-9.])(\d+(?:\.\d+)?)\s*(MΩ|KΩ|Ω|MOHM|KOHM|OHM)(?![A-Z0-9])",
        upper,
        flags=re.I,
    )
    if not match:
        return ""
    return combine_value_and_unit(
        match.group(1),
        normalize_library_value_unit(match.group(2)),
        separator="",
    )


def find_b_value_in_text(text):
    upper = clean_text(text).upper().replace("β", "B")
    if upper == "":
        return ""
    match = re.search(r"(?:B(?:ETA)?(?:25/50|25/85)?|B值)[^0-9]{0,12}(\d{3,5}(?:\.\d+)?)\s*K?", upper, flags=re.I)
    if not match:
        return ""
    return normalize_b_value_text(match.group(1))


def normalize_b_value_condition(value):
    upper = clean_text(value).upper().replace("β", "B")
    if upper == "":
        return ""
    match = re.search(r"(25|50)\s*(?:℃|°C)?\s*/\s*(50|85|100)\s*(?:℃|°C)?", upper, flags=re.I)
    if match is None:
        return clean_text(value)
    return f"{match.group(1)}/{match.group(2)}℃"


def find_b_value_condition_in_text(text):
    upper = clean_text(text).upper().replace("β", "B")
    if upper == "":
        return ""
    match = re.search(
        r"((?:25|50)\s*(?:℃|°C)?\s*/\s*(?:50|85|100)\s*(?:℃|°C)?)",
        upper,
        flags=re.I,
    )
    if not match:
        return ""
    return normalize_b_value_condition(match.group(1))


def find_circuit_count_in_text(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    match = re.search(r"(\d+)\s*(?:LINES?|CIRCUITS?|回路)", upper, flags=re.I)
    if not match:
        return ""
    return clean_text(match.group(1))


def find_shielding_type_in_text(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    if "UNSHIELDED" in upper or "NON-SHIELDED" in upper or "非屏蔽" in upper:
        return "非屏蔽"
    if "SHIELDED" in upper or "屏蔽" in upper:
        return "屏蔽"
    return ""


def find_varistor_voltage_in_text(text):
    coded = infer_varistor_nominal_voltage_from_model(text)
    if coded != "":
        return coded
    explicit = parse_voltage_from_text(text)
    if explicit != "":
        return explicit
    upper = clean_text(text).upper().replace(" ", "")
    match = VARISTOR_CODE_PATTERN.search(upper)
    if not match:
        return ""
    code = match.group(1)
    try:
        base = int(code[:2])
        multiplier = int(code[2])
        voltage = base * (10 ** multiplier)
        return clean_voltage(str(voltage))
    except Exception:
        return ""

def find_disc_size_code(text):
    upper = clean_text(text).upper().replace(" ", "")
    match = DISC_SIZE_CODE_PATTERN.search(upper)
    if not match:
        return ""
    return f"{match.group(1)}D"

def find_tolerance_in_text(text):
    upper = normalize_common_tolerance_symbol_typos(text).upper()
    upper = upper.replace("±", "+/-").replace("卤", "+/-")
    if upper == "":
        return ""
    patterns = [
        r"(\+/-\s*\d+(?:\.\d+)?\s*%)",
        r"(?<![\d.])(\d+(?:\.\d+)?\s*%)",
        r"(\+\s*\d+(?:\.\d+)?\s*%?\s*/-\s*\d+(?:\.\d+)?\s*%?)",
    ]
    for pattern in patterns:
        match = re.search(pattern, upper)
        if match:
            return clean_tol_for_match(match.group(1))
    compact = upper.replace(" ", "")
    for pattern in [r"(\+/-\d+(?:\.\d+)?%)", r"(?<![A-Z0-9.])(\d+(?:\.\d+)?%)", r"(\+\d+(?:\.\d+)?%?/-\d+(?:\.\d+)?%?)"]:
        match = re.search(pattern, compact)
        if match:
            return clean_tol_for_match(match.group(1))
    return ""

def find_power_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    normalized = raw.replace("毫瓦", "mW").replace("瓦", "W")
    broken_fraction_match = re.search(
        r"(?<![A-Z0-9.])1\s*[/;；]\s*(2|4|8|10|16|20|32)\s*W(?![A-Z0-9])",
        normalized,
        flags=re.I,
    )
    if broken_fraction_match:
        return format_power_display(f"1/{broken_fraction_match.group(1)}W")
    for pattern in [
        r"(?<![A-Z0-9.])(\d+\s*/\s*\d+\s*W)(?![A-Z0-9])",
        r"(?<![A-Z0-9.])(\d+(?:\.\d+)?\s*mW)(?![A-Z0-9])",
        r"(?<![A-Z0-9.])(\d+(?:\.\d+)?\s*W)(?![A-Z0-9])",
    ]:
        match = re.search(pattern, normalized, flags=re.I)
        if match:
            return format_power_display(match.group(1))
    return ""

def parse_voltage_from_text(text):
    upper = clean_text(text).upper()
    upper = upper.replace("±", "+/-").replace("卤", "+/-")
    compact = upper.replace(" ", "")
    # Support tightly packed values like 100UF25V or 0.1UF275V.
    compact_match = re.search(r"(?:PF|NF|UF)(\d+(?:\.\d+)?)V", compact)
    if compact_match:
        return clean_voltage(compact_match.group(1))
    voltage_match = re.search(r"(\d+(?:\.\d+)?)\s*V", upper)
    if voltage_match:
        return clean_voltage(voltage_match.group(1))
    return ""


def merge_query_text_hints_into_spec(spec, query_text):
    if spec is None:
        return spec
    spec = apply_query_brand_hint_to_spec(spec, query_text)
    explicit_voltage = parse_voltage_from_text(query_text)
    explicit_special_use = extract_special_use_from_text(query_text)
    current_voltage = clean_voltage(spec.get("耐压（V）", ""))
    current_special_use = normalize_special_use(spec.get("特殊用途", ""))
    if (explicit_voltage == "" or current_voltage != "") and explicit_special_use == "":
        return spec
    merged = dict(spec)
    if explicit_voltage != "" and current_voltage == "":
        merged["耐压（V）"] = explicit_voltage
    if explicit_special_use != "":
        special_tokens = special_use_tokens(current_special_use) + special_use_tokens(explicit_special_use)
        merged["特殊用途"] = "/".join(dict.fromkeys(special_tokens))
    try:
        merged["_param_count"] = max(int(merged.get("_param_count", 0) or 0), count_query_params(merged))
    except Exception:
        pass
    return merged

def normalize_component_keyword_compact(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    compact = upper.replace(" ", "")
    return re.sub(r"[^A-Z0-9\u4E00-\u9FFFΩ]+", "", compact)


def alias_token_matches(upper_text, compact_text, token):
    token_upper = clean_text(token).upper()
    if token_upper == "":
        return False
    token_compact = re.sub(r"[^A-Z0-9\u4E00-\u9FFFΩ]+", "", token_upper.replace(" ", ""))
    if token_compact == "":
        return False
    if re.fullmatch(r"[A-Z0-9]+", token_compact) and len(token_compact) <= 4:
        boundary_patterns = [
            rf"(?<![A-Z0-9]){re.escape(token_compact)}(?![A-Z0-9])",
            rf"(?<![A-Z0-9]){re.escape(token_compact)}(?=\d)",
            rf"^{re.escape(token_compact)}(?=\d)",
        ]
        return any(re.search(pattern, upper_text) is not None for pattern in boundary_patterns)
    if re.search(r"[^A-Z0-9Ω]", token_upper) or " " in token_upper:
        return token_upper in upper_text
    return token_compact in compact_text


