def matches_component_alias(text, component_type):
    upper = clean_text(text).upper()
    compact = normalize_component_keyword_compact(text)
    if upper == "":
        return False
    token_group = COMPONENT_ALIAS_TOKENS.get(component_type, {})
    compact_tokens = token_group.get("compact", [])
    upper_tokens = token_group.get("upper", [])
    if any(alias_token_matches(upper, compact, token) for token in compact_tokens):
        return True
    return any(alias_token_matches(upper, compact, token) for token in upper_tokens)


def detect_unsupported_semiconductor_type(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    upper = raw.upper()
    compact = normalize_component_keyword_compact(raw)
    model = clean_model(raw)

    mos_keyword_patterns = [
        r"\bMOSFET\b",
        r"\bN[-\s]?MOS\b",
        r"\bP[-\s]?MOS\b",
        r"\bNMOS\b",
        r"\bPMOS\b",
        r"场效应",
        r"MOS管",
        r"RDS\s*\(?ON\)?",
        r"RDS\(ON\)",
    ]
    if any(re.search(pattern, upper, flags=re.I) for pattern in mos_keyword_patterns):
        return "MOSFET"

    if re.search(r"(二极管|DIODE|肖特基|SCHOTTKY|整流|快恢复)", upper, flags=re.I):
        if "TVS" in upper or "ESD" in upper:
            return "TVS二极管"
        return "二极管"
    if re.search(r"(三极管|TRANSISTOR|晶体管|NPN|PNP|BJT)", upper, flags=re.I):
        return "三极管"
    if re.search(r"(TVS\s*二极管|TVS\s*DIODE|ESD\s*DIODE)", upper, flags=re.I):
        return "TVS二极管"

    # Compact model blockers. These prevent common semiconductor part numbers
    # from being reinterpreted as capacitor or resistor value codes.
    if re.fullmatch(r"(?:AO|AOD|AON|BSS|SI|FDN|FDS)\d+[A-Z0-9-]*", model):
        return "MOSFET"
    if re.fullmatch(r"(?:IRF|IRL|IRFS|IRLR|IRFR)[A-Z]*\d+[A-Z0-9-]*", model):
        return "MOSFET"
    if re.fullmatch(r"(?:STP|STW|STF|STL|STD|DMN|DMP|RQ|SSM|PMV|PSMN)[A-Z0-9-]*\d+[A-Z0-9-]*", model):
        return "MOSFET"
    if re.fullmatch(r"2N700[02][A-Z0-9-]*", model):
        return "MOSFET"
    if re.fullmatch(r"(?:1N|BAV|BAT|SS|SK|RB|CUS|DSA|MBR|FR|UF|HER)\d+[A-Z0-9-]*", model):
        return "二极管"
    if re.fullmatch(r"(?:SMBJ|SMAJ|SMCJ|PESD|ESD)\d?[A-Z0-9.]+", model):
        return "TVS二极管"
    if re.fullmatch(r"(?:CDSOD|ESDA)[A-Z0-9.-]+", model):
        return "TVS二极管"
    if re.fullmatch(r"(?:2N|2SC|2SA|2STR|MMBT|UMT|S)\d{3,5}[A-Z0-9-]*", model):
        return "三极管"
    if "MOS" in compact and re.search(r"(?:沟道|CHANNEL|RDS|场效应)", upper, flags=re.I):
        return "MOSFET"
    return ""


def build_unsupported_semiconductor_spec(line, component_type):
    component_type = clean_text(component_type) or "半导体功率器件"
    return {
        "品牌": "",
        "型号": clean_text(line),
        "器件类型": component_type,
        "规格摘要": f"{component_type}暂未接入匹配库",
        "_unsupported_component": True,
        "_unsupported_reason": f"暂不支持{component_type}匹配，避免误推荐被动器件",
        "_core_param_count": 0,
        "_param_count": 0,
    }


SEMICONDUCTOR_PACKAGE_PATTERN = re.compile(
    r"\b(TO-?220(?:AB)?|TO-?252|DPAK|D2PAK|SOT-?23(?:-?\d*)?|SOT-?223|SOT-?323|SOT-?363|SOD-?123|SOD-?323|SOD-?523|DO-?214(?:AA|AB|AC)|DO-?35|DO-?41|SMA|SMB|SMC|SOP-?8|SO-?8|DFN\d*x\d*)\b",
    flags=re.I,
)


def extract_semiconductor_package(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    match = SEMICONDUCTOR_PACKAGE_PATTERN.search(upper)
    if not match:
        return ""
    return match.group(1).upper().replace("TO220", "TO-220").replace("SOT23", "SOT-23").replace("SOD123", "SOD-123")


def extract_semiconductor_polarity(text, component_type=""):
    upper = clean_text(text).upper()
    component_type = normalize_component_type(component_type)
    if upper == "":
        return ""
    if component_type == "MOSFET":
        if re.search(r"\bP[-\s]?CHANNEL\b|\bP[-\s]?MOS\b|\bPMOS\b|P沟道|P型", upper, flags=re.I):
            return "P沟道"
        if re.search(r"\bN[-\s]?CHANNEL\b|\bN[-\s]?MOS\b|\bNMOS\b|N沟道|N型", upper, flags=re.I):
            return "N沟道"
    if component_type == "三极管":
        if re.search(r"\bPNP\b|PNP型", upper, flags=re.I):
            return "PNP"
        if re.search(r"\bNPN\b|NPN型", upper, flags=re.I):
            return "NPN"
    if component_type == "TVS二极管":
        if re.search(r"\bBI[-\s]?DIRECTIONAL\b|双向|BIDIRECTIONAL", upper, flags=re.I):
            return "双向"
        if re.search(r"\bUNI[-\s]?DIRECTIONAL\b|单向|UNIDIRECTIONAL", upper, flags=re.I):
            return "单向"
    return ""


def find_rds_on_in_text(text):
    raw = clean_text(text).replace("OHMS", "OHM").replace("ohms", "ohm")
    if raw == "":
        return ""
    pattern = re.compile(
        r"(?:RDS\s*\(?ON\)?|RDS\(ON\)|导通电阻)[^0-9]{0,40}(\d+(?:\.\d+)?)\s*(mΩ|MΩ|KΩ|MOHM|KOHM|OHM|Ω)",
        flags=re.I,
    )
    match = pattern.search(raw)
    if match:
        return combine_value_and_unit(match.group(1), normalize_library_value_unit(match.group(2)), separator="")
    return ""


def parse_semiconductor_resistance_to_ohms(value):
    return parse_resistive_measurement_to_ohms(value, default_unit="Ω")


def get_semiconductor_voltage_num(record):
    value = clean_voltage(record.get("耐压（V）", ""))
    return safe_numeric_value(value)


def get_semiconductor_current_amps(record):
    return parse_current_to_amps(record.get("额定电流", ""))


def get_semiconductor_rds_ohms(record):
    text = clean_text(record.get("_rds_on", ""))
    if text == "":
        text = find_rds_on_in_text(
            " ".join(
                clean_text(record.get(key, ""))
                for key in ["规格摘要", "备注1", "备注2", "备注3", "DCR"]
            )
        )
    return parse_semiconductor_resistance_to_ohms(text), text


def normalize_semiconductor_package(value):
    text = clean_text(value).upper().replace(" ", "")
    if text == "":
        return ""
    if "DO-214AB" in text and "SMC" in text:
        return "SMC"
    if "DO-214AA" in text and "SMB" in text:
        return "SMB"
    if "DO-214AC" in text and "SMA" in text:
        return "SMA"
    replacements = {
        "TO220": "TO-220",
        "TO220AB": "TO-220AB",
        "DO214AB": "SMC",
        "DO214AA": "SMB",
        "DO214AC": "SMA",
        "DO-214AB": "SMC",
        "DO-214AA": "SMB",
        "DO-214AC": "SMA",
        "SOT23": "SOT-23",
        "SOT223": "SOT-223",
        "SOT323": "SOT-323",
        "SOD123": "SOD-123",
        "SOD323": "SOD-323",
        "DO35": "DO-35",
        "DO41": "DO-41",
        "SO8": "SO-8",
        "SOP8": "SOP-8",
    }
    return replacements.get(text, text)


def enrich_semiconductor_spec_fields(spec, source_text=""):
    if not isinstance(spec, dict):
        return spec
    out = dict(spec)
    component_type = infer_spec_component_type(out)
    if component_type not in SEMICONDUCTOR_COMPONENT_TYPES:
        return out
    merged_text = " ".join(
        clean_text(part)
        for part in [
            source_text,
            out.get("器件类型", ""),
            out.get("型号", ""),
            out.get("特殊用途", ""),
            out.get("规格摘要", ""),
            out.get("备注1", ""),
            out.get("备注2", ""),
            out.get("备注3", ""),
            out.get("极性", ""),
            out.get("封装代码", ""),
        ]
        if clean_text(part) != ""
    )
    if clean_text(out.get("封装代码", "")) == "":
        out["封装代码"] = extract_semiconductor_package(merged_text)
    if clean_text(out.get("极性", "")) == "":
        out["极性"] = extract_semiconductor_polarity(merged_text, component_type)
    if component_type == "MOSFET" and clean_text(out.get("_rds_on", "")) == "":
        out["_rds_on"] = find_rds_on_in_text(merged_text)
    if clean_text(out.get("规格摘要", "")) == "":
        out["规格摘要"] = build_other_component_summary([
            clean_text(out.get("极性", "")) or clean_text(out.get("特殊用途", "")),
            voltage_display(out.get("耐压（V）", "")),
            format_current_display(out.get("额定电流", "")),
            clean_text(out.get("_rds_on", "")),
            clean_text(out.get("封装代码", "")),
        ])
    core_count = sum([
        1 if clean_text(out.get("器件类型", "")) != "" else 0,
        1 if clean_voltage(out.get("耐压（V）", "")) != "" else 0,
        1 if clean_text(out.get("额定电流", "")) != "" else 0,
        1 if clean_text(out.get("封装代码", "")) != "" else 0,
        1 if clean_text(out.get("极性", "")) != "" else 0,
        1 if clean_text(out.get("_rds_on", "")) != "" else 0,
    ])
    out["_core_param_count"] = max(int(out.get("_core_param_count", 0) or 0), core_count)
    out["_param_count"] = max(int(out.get("_param_count", 0) or 0), core_count)
    return out


def parse_semiconductor_spec_query(line, component_type=""):
    raw = clean_text(line)
    if raw == "":
        return None
    component_type = normalize_component_type(component_type) or detect_unsupported_semiconductor_type(raw)
    if component_type not in SEMICONDUCTOR_COMPONENT_TYPES:
        return None
    upper = raw.upper()
    package = extract_semiconductor_package(raw)
    polarity = extract_semiconductor_polarity(raw, component_type)
    current = find_current_in_text(upper)
    rds_on = find_rds_on_in_text(raw) if component_type == "MOSFET" else ""
    voltage = ""
    voltage_match = re.search(r"(?<![A-Z0-9])(\d+(?:\.\d+)?)\s*V(?![A-Z])", upper)
    if voltage_match:
        voltage = clean_voltage(voltage_match.group(1))
    special_use = ""
    if component_type == "二极管":
        special_use = "肖特基二极管" if re.search(r"SCHOTTKY|肖特基", upper, flags=re.I) else "开关/整流二极管"
    elif component_type == "TVS二极管":
        special_use = "TVS二极管"
    elif component_type == "MOSFET":
        special_use = build_other_component_summary([polarity, "MOSFET"])
    elif component_type == "三极管":
        special_use = build_other_component_summary([polarity, "BJT"])

    param_count = sum([
        1 if component_type else 0,
        1 if voltage else 0,
        1 if current else 0,
        1 if package else 0,
        1 if polarity else 0,
        1 if rds_on else 0,
    ])
    if param_count <= 1:
        return None
    spec = {
        "品牌": "",
        "型号": raw,
        "器件类型": component_type,
        "特殊用途": special_use,
        "耐压（V）": voltage,
        "额定电流": current,
        "封装代码": package,
        "极性": polarity,
        "_rds_on": rds_on,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }
    return enrich_semiconductor_spec_fields(spec, source_text=raw)


def resistor_context_should_block_mlcc(text):
    raw = clean_text(text)
    if raw == "":
        return False
    upper = raw.upper()
    compact = normalize_component_keyword_compact(raw)
    if any(token in upper for token in ["电阻", "電阻", "RESISTOR"]):
        return True
    has_ohm_token = "Ω" in upper or re.search(r"(?<![A-Z0-9])OHMS?(?![A-Z0-9])", upper) is not None
    if has_ohm_token and not any(token in upper or token in compact for token in ["电容", "電容", "CAP", "MLCC", "PF", "NF", "UF"]):
        return True
    return False


def looks_like_mlcc_context(text):
    upper = clean_text(text).upper()
    compact = normalize_component_keyword_compact(text)
    if upper == "":
        return False
    if resistor_context_should_block_mlcc(text):
        return False
    if matches_component_alias(text, "MLCC"):
        return True
    if any(token in compact for token, _ in SPEC_EMBEDDED_MATERIALS) and (
        any(unit in compact for unit in ["PF", "NF", "UF"]) or find_embedded_size(upper) != ""
    ):
        return True
    return False

def looks_like_film_capacitor_context(text):
    upper = clean_text(text).upper()
    if upper == "":
        return False
    if matches_component_alias(text, "薄膜电容"):
        return True
    if re.search(r"(?<![A-Z0-9])(X1|X2|Y1|Y2)(?![A-Z0-9])", upper):
        return True
    return False

def looks_like_tantalum_context(text):
    return matches_component_alias(text, "钽电容")

def looks_like_leaded_ceramic_context(text):
    upper = clean_text(text).upper()
    compact = normalize_component_keyword_compact(text)
    if upper == "":
        return False
    if "Y5P" not in compact and "Y5P" not in upper:
        return False
    if re.search(r"D\d+\s*\*\s*L\d+", upper) is None and re.search(r"(LEADED|DISC|RADIAL|圆片|圆瓷|引线|瓷片|陶瓷圆片)", upper) is None:
        return False
    return True

def looks_like_varistor_context(text):
    return (
        matches_component_alias(text, "压敏电阻")
        or matches_component_alias(text, "引线型压敏电阻")
        or matches_component_alias(text, "贴片压敏电阻")
    )

def looks_like_smd_varistor_context(text):
    if not looks_like_varistor_context(text):
        return False
    upper = clean_text(text).upper()
    if upper == "":
        return False
    if matches_component_alias(text, "贴片压敏电阻"):
        return True
    if any(token in upper for token in ["SMD", "SMT", "CHIP", "贴片", "貼片", "MLV"]):
        return True
    return SMD_SIZE_CODE_PATTERN.search(upper) is not None

def looks_like_leaded_varistor_context(text):
    if not looks_like_varistor_context(text):
        return False
    if looks_like_smd_varistor_context(text):
        return False
    upper = clean_text(text).upper()
    compact = normalize_component_keyword_compact(text)
    if upper == "":
        return False
    if matches_component_alias(text, "引线型压敏电阻"):
        return True
    if find_disc_size_code(text) != "":
        return True
    if extract_pitch_from_text(text) != "":
        return True
    if re.search(r"(LEADED|RADIAL|引线|插件|直插|脚距)", upper):
        return True
    return MM_DIMENSION_PATTERN.search(upper) is not None and "SMD" not in compact

def detect_resistor_subtype_hint(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    if looks_like_varistor_context(text):
        if looks_like_smd_varistor_context(text):
            return "贴片压敏电阻"
        if looks_like_leaded_varistor_context(text):
            return "引线型压敏电阻"
        return "压敏电阻"
    if matches_component_alias(text, "热敏电阻"):
        return "热敏电阻"
    if matches_component_alias(text, "合金电阻"):
        return "合金电阻"
    if matches_component_alias(text, "碳膜电阻"):
        return "碳膜电阻"
    if matches_component_alias(text, "薄膜电阻"):
        return "薄膜电阻"
    if matches_component_alias(text, "厚膜电阻"):
        return "厚膜电阻"
    compact = normalize_component_keyword_compact(text)
    if matches_component_alias(text, "贴片电阻") or upper.startswith("RES"):
        return "贴片电阻"
    return ""

def detect_inductor_subtype_hint(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    model_tokens = [clean_model(token) for token in extract_model_like_tokens(text)]
    if any(token.startswith("CMBH") for token in model_tokens):
        return "磁珠"
    if any(token.startswith("CMLH") for token in model_tokens):
        return "功率电感"
    if matches_component_alias(text, "射频电感"):
        return "射频电感"
    if matches_component_alias(text, "共模电感"):
        return "共模电感"
    if matches_component_alias(text, "磁珠"):
        return "磁珠"
    if matches_component_alias(text, "功率电感"):
        return "功率电感"
    return ""

def detect_timing_subtype_hint(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    compact_model = clean_model(text)
    if (
        matches_component_alias(text, "实时时钟模块")
        or re.fullmatch(r"(?:RX|RA|RTC)-?\d{4}[A-Z]{1,3}(?:-?(?:UA|UB|UC|AA|AC|B))?", compact_model)
    ):
        return "实时时钟模块"
    if matches_component_alias(text, "振荡器"):
        return "振荡器"
    if matches_component_alias(text, "晶振"):
        return "晶振"
    return ""

def find_film_material(text):
    upper = clean_text(text).upper().replace(" ", "")
    material_tokens = [
        ("MKP", "MKP"),
        ("MKT", "MKT"),
        ("CBB", "CBB"),
        ("PPS", "PPS"),
        ("PEN", "PEN"),
        ("PP", "PP"),
        ("PET", "PET"),
    ]
    for token, label in material_tokens:
        if token in upper:
            return label
    return ""

def find_safety_class(text):
    upper = clean_text(text).upper()
    match = re.search(r"(?<![A-Z0-9])(X1|X2|Y1|Y2)(?![A-Z0-9])", upper)
    if match:
        return match.group(1)
    return ""

def detect_component_type_hint(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    semiconductor_hint = detect_unsupported_semiconductor_type(text)
    if semiconductor_hint != "":
        return semiconductor_hint
    timing_hint = detect_timing_subtype_hint(text)
    if timing_hint != "":
        return timing_hint
    inductor_hint = detect_inductor_subtype_hint(text)
    if inductor_hint != "":
        return inductor_hint
    resistor_hint = detect_resistor_subtype_hint(text)
    if resistor_hint in (VARISTOR_COMPONENT_TYPES | {"热敏电阻"}):
        return resistor_hint
    if looks_like_film_capacitor_context(text):
        return "薄膜电容"
    if looks_like_tantalum_context(text):
        return "钽电容"
    if looks_like_leaded_ceramic_context(text):
        return "引线型陶瓷电容"
    if looks_like_mlcc_context(text):
        return "MLCC"
    if looks_like_electrolytic_context(text):
        return "铝电解电容"
    if resistor_hint != "":
        return resistor_hint
    return ""

def normalize_component_type(value):
    text = clean_text(value)
    if text == "":
        return ""
    if text in UNSUPPORTED_SEMICONDUCTOR_TYPES:
        return text
    if text in ALL_PASSIVE_COMPONENT_TYPES:
        return text
    hint = detect_component_type_hint(text)
    if hint != "":
        return hint
    return text


def resolve_component_category_type(value):
    if isinstance(value, pd.Series):
        value = value.to_dict()
    if isinstance(value, dict):
        direct_type = normalize_component_type(value.get("器件类型", ""))
        if direct_type != "":
            return direct_type
        inferred_row_type = infer_db_component_type(value)
        if inferred_row_type != "":
            return inferred_row_type
        inferred_spec_type = infer_spec_component_type(value)
        return inferred_spec_type if inferred_spec_type in ALL_PASSIVE_COMPONENT_TYPES else ""
    return normalize_component_type(value)


def format_component_category_display(value):
    component_type = resolve_component_category_type(value)
    if component_type == "":
        return ""
    return COMPONENT_CATEGORY_DISPLAY_LABELS.get(component_type, component_type)


def format_component_size_display_value(value):
    text = clean_text(value)
    if text == "":
        return ""
    normalized = text.lower()
    if "mm" in normalized or "×" in text or "*" in text or re.search(r"\d\s*[xX]\s*\d", text):
        return text
    return clean_size(text)


def resistor_source_evidence_present(value):
    note = clean_text(value).lower()
    if note == "":
        return False
    return any(token in note for token in RESISTOR_SOURCE_EVIDENCE_TOKENS)


def infer_strong_component_type_override(row, direct="", text=""):
    direct_type = normalize_component_type(direct)
    if direct_type in ALL_RESISTOR_TYPES or direct_type in INDUCTOR_COMPONENT_TYPES or direct_type in TIMING_COMPONENT_TYPES:
        return ""
    summary = clean_text(row.get("规格摘要", ""))
    notes = clean_text(row.get("校验备注", ""))
    if summary == "" and notes == "":
        return ""
    explicit_resistor_summary = (
        detect_resistor_subtype_hint(summary) != ""
        or (
            looks_like_resistor_context(summary)
            and not looks_like_varistor_context(summary)
            and not looks_like_thermistor_context(summary)
        )
    )
    if not resistor_source_evidence_present(notes) and not explicit_resistor_summary:
        return ""
    evidence_text = " ".join(
        part for part in [
            clean_text(text),
            summary,
            notes,
            clean_text(row.get("品牌", "")),
            clean_text(row.get("型号", "")),
            clean_text(row.get("系列", "")),
            clean_text(row.get("备注1", "")),
            clean_text(row.get("备注2", "")),
            clean_text(row.get("备注3", "")),
        ]
        if clean_text(part) != ""
    )
    resistor_hint = detect_resistor_subtype_hint(evidence_text)
    if resistor_hint != "":
        return resistor_hint
    if looks_like_resistor_context(evidence_text):
        return "贴片电阻"
    return ""

def infer_db_component_type(row):
    direct = normalize_component_type(row.get("器件类型", ""))
    raw_unit = clean_text(row.get("容值单位", "")).upper()
    text = " ".join([
        clean_text(row.get("器件类型", "")),
        clean_text(row.get("品牌", "")),
        clean_text(row.get("型号", "")),
        clean_text(row.get("系列", "")),
        clean_text(row.get("安装方式", "")),
        clean_text(row.get("封装代码", "")),
        clean_text(row.get("尺寸（mm）", "")),
        clean_text(row.get("材质（介质）", "")),
        clean_text(row.get("规格摘要", "")),
        clean_text(row.get("特殊用途", "")),
        clean_text(row.get("备注1", "")),
        clean_text(row.get("备注2", "")),
        clean_text(row.get("备注3", "")),
    ])
    if direct in VARISTOR_COMPONENT_TYPES or looks_like_varistor_context(text):
        if direct == "贴片压敏电阻" or looks_like_smd_varistor_context(text):
            return "贴片压敏电阻"
        if direct == "引线型压敏电阻" or looks_like_leaded_varistor_context(text):
            return "引线型压敏电阻"
        if direct in VARISTOR_COMPONENT_TYPES:
            return direct
        return "压敏电阻"
    if direct in SEMICONDUCTOR_COMPONENT_TYPES:
        return direct
    if looks_like_thermistor_context(text):
        return "热敏电阻"
    if direct == "MLCC" and looks_like_leaded_ceramic_context(text):
        return "引线型陶瓷电容"
    strong_override = infer_strong_component_type_override(row, direct=direct, text=text)
    if strong_override != "":
        return strong_override
    if direct in INDUCTOR_COMPONENT_TYPES or raw_unit in {"NH", "UH", "MH"}:
        return direct if direct in INDUCTOR_COMPONENT_TYPES else (detect_inductor_subtype_hint(text) or "功率电感")
    if direct in TIMING_COMPONENT_TYPES or raw_unit in {"HZ", "KHZ", "MHZ"}:
        return direct if direct in TIMING_COMPONENT_TYPES else (detect_timing_subtype_hint(text) or "晶振")
    if direct != "":
        return direct
    hint = detect_component_type_hint(text)
    if hint != "":
        return hint
    if looks_like_film_capacitor_context(text):
        return "薄膜电容"
    # Some vendor tables only expose electrolytic / resistor / thermistor clues
    # in package text, pitch, or ohm-related fields, so give these a second pass
    # before falling back to MLCC.
    if looks_like_leaded_ceramic_context(text):
        return "引线型陶瓷电容"
    if looks_like_electrolytic_context(text):
        return "铝电解电容"
    if looks_like_thermistor_context(text):
        return "热敏电阻"
    if looks_like_resistor_context(text):
        return "贴片电阻"
    if clean_material(row.get("材质（介质）", "")) != "" or pd.notna(row.get("容值_pf", None)):
        return "MLCC"
    if clean_text(row.get("容值单位", "")).upper() in {"PF", "NF", "UF"}:
        return "MLCC"
    return ""

def infer_spec_component_type(spec):
    if spec is None:
        return ""
    direct = normalize_component_type(spec.get("器件类型", ""))
    raw_unit = clean_text(spec.get("容值单位", "")).upper()
    spec_text = " ".join([
        clean_text(spec.get("器件类型", "")),
        clean_text(spec.get("型号", "")),
        clean_text(spec.get("规格摘要", "")),
        clean_text(spec.get("安装方式", "")),
        clean_text(spec.get("封装代码", "")),
        clean_text(spec.get("尺寸（mm）", "")),
        clean_text(spec.get("材质（介质）", "")),
        clean_text(spec.get("_body_size", "")),
        clean_text(spec.get("_pitch", "")),
        clean_text(spec.get("_safety_class", "")),
    ])
    if direct in VARISTOR_COMPONENT_TYPES or looks_like_varistor_context(spec_text):
        if direct == "贴片压敏电阻" or looks_like_smd_varistor_context(spec_text):
            return "贴片压敏电阻"
        if direct == "引线型压敏电阻" or looks_like_leaded_varistor_context(spec_text):
            return "引线型压敏电阻"
        if direct in VARISTOR_COMPONENT_TYPES:
            return direct
        return "压敏电阻"
    if direct in SEMICONDUCTOR_COMPONENT_TYPES:
        return direct
    if direct == "MLCC" and looks_like_leaded_ceramic_context(spec_text):
        return "引线型陶瓷电容"
    strong_override = infer_strong_component_type_override(spec, direct=direct, text=spec_text)
    if strong_override != "":
        return strong_override
    if direct in INDUCTOR_COMPONENT_TYPES or raw_unit in {"NH", "UH", "MH"}:
        return direct if direct in INDUCTOR_COMPONENT_TYPES else (detect_inductor_subtype_hint(spec_text) or "功率电感")
    if direct in TIMING_COMPONENT_TYPES or raw_unit in {"HZ", "KHZ", "MHZ"}:
        return direct if direct in TIMING_COMPONENT_TYPES else (detect_timing_subtype_hint(spec_text) or "晶振")
    if direct != "":
        return direct
    hint = detect_component_type_hint(spec_text)
    if hint != "":
        return hint
    if looks_like_film_capacitor_context(spec_text):
        return "薄膜电容"
    if looks_like_leaded_ceramic_context(spec_text):
        return "引线型陶瓷电容"
    if looks_like_electrolytic_context(spec_text):
        return "铝电解电容"
    if looks_like_thermistor_context(spec_text):
        return "热敏电阻"
    if looks_like_resistor_context(spec_text):
        return "贴片电阻"
    if spec.get("容值_pf", None) is not None or clean_material(spec.get("材质（介质）", "")) != "":
        return "MLCC"
    return ""

def looks_like_thermistor_context(text):
    raw = clean_text(text)
    if raw == "":
        return False
    upper = raw.upper()
    compact = normalize_component_keyword_compact(raw)
    if matches_component_alias(raw, "热敏电阻"):
        return True
    if upper.startswith("NTC") or compact.startswith("NTC"):
        return True
    if any(token in raw for token in ["过流保护", "正极电阻", "自恢复保险丝", "可恢复保险丝", "保险丝热敏"]):
        return True
    if any(token in upper for token in ["PTC THERMISTOR", "OVERCURRENT PROTECTION", "RESETTABLE FUSE", "RESETTABLE", "POLYFUSE", "PPTC", "POSISTOR"]):
        return True
    if "MURATA" in upper and re.search(r"\bPRG\d", upper):
        return True
    if "MURATA" in upper and re.search(r"PRG\d", compact):
        return True
    if re.search(r"(?:FTN|NCP|NCU|NCG)\d{2}[A-Z]{2}\d{3}[BCDEFGJKMZ]", compact):
        return True
    return False


def reverse_lookup_row_priority(row):
    model_text = clean_model(row.get("_model_clean", row.get("型号", "")))
    row_type = normalize_component_type(row.get("_component_type", "")) or infer_db_component_type(row) or normalize_component_type(row.get("器件类型", ""))
    data_source = clean_text(row.get("数据来源", ""))
    data_status = clean_text(row.get("数据状态", ""))
    series = clean_text(row.get("系列", ""))
    summary = clean_text(row.get("规格摘要", ""))
    model_granularity = clean_text(row.get("型号粒度", ""))
    score = 0

    if "官方PDF" in data_status:
        score += 1000
    elif "官方" in data_status:
        score += 400

    if "Part Number List" in data_source or "官方" in data_source:
        score += 200
    if data_source.startswith("型号编码解析"):
        score -= 100

    if model_granularity == "官方逐料号":
        score += 800
    elif model_granularity == "官方型号+频率+规格编号":
        score += 700
    elif model_granularity == "官方料号模板":
        score += 300
    elif model_granularity in {"官方系列范围", "官方可配置系列"}:
        score += 200

    if looks_like_thermistor_context(model_text):
        if row_type == "热敏电阻":
            score += 300
        elif row_type in RESISTOR_COMPONENT_TYPES:
            score -= 300

    if looks_like_varistor_context(model_text):
        if row_type in VARISTOR_COMPONENT_TYPES:
            score += 300
        elif row_type == "贴片电阻":
            score -= 300

    yageo_mlcc_model = parse_yageo_common(model_text)
    if yageo_mlcc_model is not None:
        if row_type == "MLCC":
            score += 600
        elif row_type in RESISTOR_COMPONENT_TYPES:
            score -= 600

    pulse_bbgk_model = parse_pulse_bbgk_ferrite_bead(model_text)
    if pulse_bbgk_model is not None:
        if row_type == "磁珠":
            score += 600
        elif row_type in (RESISTOR_COMPONENT_TYPES | {"MLCC"}):
            score -= 600

    if series != "":
        score += 10
    if summary != "":
        score += 5
    if clean_text(row.get("容值", "")) != "" or clean_text(row.get("阻值@25C", "")) != "":
        score += 5
    return score


def prioritize_component_rows_for_lookup(df):
    if df is None or df.empty:
        return df
    if "品牌" not in df.columns or "型号" not in df.columns:
        return df

    work = df.copy()
    work["_lookup_order"] = range(len(work))
    work["_lookup_brand_key"] = work["品牌"].astype(str).apply(
        lambda value: canonical_cost_price_brand_label(value).upper()
    )
    work["_lookup_model_key"] = work["型号"].astype(str).apply(clean_model)
    if "_component_type" in work.columns:
        work["_lookup_component_key"] = work["_component_type"].astype(str).apply(normalize_component_type)
    else:
        work["_lookup_component_key"] = work.apply(lambda row: infer_db_component_type(row) or normalize_component_type(row.get("器件类型", "")), axis=1)
    try:
        work["_lookup_priority"] = work.apply(reverse_lookup_row_priority, axis=1)
    except Exception:
        work["_lookup_priority"] = 0

    work = work.sort_values(
        by=["_lookup_brand_key", "_lookup_model_key", "_lookup_component_key", "_lookup_priority", "_lookup_order"],
        ascending=[True, True, True, False, True],
        kind="mergesort",
    )
    return work.drop(
        columns=[
            "_lookup_priority",
            "_lookup_order",
            "_lookup_brand_key",
            "_lookup_model_key",
            "_lookup_component_key",
        ],
        errors="ignore",
    )


def has_explicit_capacitance_value_token(text):
    raw = clean_text(text)
    if raw == "":
        return False
    upper = (
        raw.upper()
        .replace("μF", "UF")
        .replace("µF", "UF")
        .replace("ΜF", "UF")
    )
    if re.search(r"(?<![A-Z0-9])\d+(?:\.\d+)?\s*(?:PF|NF|UF)(?![A-Z0-9])", upper):
        return True
    if re.search(r"(?<![A-Z0-9])(?:\d+[PNU]\d+|\d+(?:\.\d+)?[PNU])(?![A-Z0-9])", upper):
        return True
    if re.search(r"(?<![A-Z0-9])\d{3,4}P(?![A-Z0-9])", upper):
        return True
    return False


def looks_like_resistor_context(text):
    hint = detect_component_type_hint(text)
    if hint in (VARISTOR_COMPONENT_TYPES | UNSUPPORTED_SEMICONDUCTOR_TYPES | {"热敏电阻", "铝电解电容", "薄膜电容", "钽电容", "功率电感", "共模电感", "磁珠", "晶振", "振荡器", "MLCC"}):
        return False
    if hint in RESISTOR_COMPONENT_TYPES:
        return True
    normalized_text = normalize_common_tolerance_symbol_typos(text)
    upper = normalized_text.upper().replace("±", "+/-").replace("卤", "+/-")
    compact = normalize_component_keyword_compact(normalized_text).replace("±", "+/-").replace("卤", "+/-")
    if any(token in upper for token in ["电阻", "RESISTOR", "OHM", "Ω"]) or upper.startswith("RES"):
        return True
    if has_explicit_capacitance_value_token(text):
        return False
    has_compact_resistance = RESISTOR_VALUE_PATTERN.search(upper) is not None or RESISTOR_COMPACT_CONTEXT_PATTERN.search(upper) is not None
    if has_compact_resistance and "%" in upper:
        return True

    # Common purchasing shorthand omits "ohm"/"resistor", e.g. "0201 1/20W 0R".
    # Keep the gate narrow so MLCC/order-code strings are not promoted to resistors.
    if has_compact_resistance and find_power_in_text(upper) != "":
        return True
    zero_ohm_token = re.search(r"(?<![A-Z0-9])(?:0+(?:\.0+)?R|R0+|0+(?:\.0+)?\s*(?:Ω|OHM))(?![A-Z0-9])", upper, flags=re.I)
    if zero_ohm_token and find_embedded_size(upper) != "":
        return True
    return False

def build_other_component_summary(parts):
    return " ".join([clean_text(part) for part in parts if clean_text(part) != ""])


def parse_inductor_spec_query(line):
    raw = clean_text(line)
    if raw == "":
        return None

    upper = raw.upper().replace("μ", "U").replace("µ", "U").replace("Μ", "U")
    component_type = detect_inductor_subtype_hint(raw)
    inductance = find_inductance_in_text(upper)
    impedance = find_impedance_in_text(upper) if component_type in {"共模电感", "磁珠"} else ""
    if component_type == "" and inductance == "":
        return None
    if component_type == "" and any(
        checker(raw)
        for checker in (
            looks_like_mlcc_context,
            looks_like_film_capacitor_context,
            looks_like_electrolytic_context,
            looks_like_resistor_context,
            looks_like_varistor_context,
            looks_like_thermistor_context,
        )
    ):
        return None
    if component_type == "":
        component_type = "功率电感"

    size = find_embedded_size(raw)
    tol = find_tolerance_in_text(raw)
    tokens = [token.strip().upper() for token in re.split(r"[\s,;/|()（）]+", upper) if token.strip()]
    if tol == "":
        for token in tokens:
            if token in INDUCTOR_TOLERANCE_CODE_MAP:
                tol = clean_tol_for_match(INDUCTOR_TOLERANCE_CODE_MAP[token])
                break
    current = find_current_in_text(upper)
    dcr = find_dcr_in_text(raw) or find_unlabeled_dcr_in_inductor_text(raw)
    body_size = extract_body_size_from_text(raw)

    inductance_value = ""
    inductance_unit = ""
    inductance_match = re.fullmatch(r"(\d+(?:\.\d+)?)(NH|UH|MH)", inductance, flags=re.I)
    if inductance_match:
        inductance_value = clean_text(inductance_match.group(1))
        inductance_unit = clean_text(inductance_match.group(2)).upper()
    impedance_value, impedance_unit = parse_impedance_value_unit(impedance)
    if component_type in {"共模电感", "磁珠"} and impedance_value != "":
        value = impedance_value
        unit = impedance_unit
    else:
        value = inductance_value
        unit = inductance_unit

    param_count = sum([
        1 if size else 0,
        1 if inductance_value and inductance_unit else 0,
        1 if impedance_value and impedance_unit else 0,
        1 if tol else 0,
        1 if current else 0,
        1 if dcr else 0,
        1 if body_size else 0,
    ])
    if param_count == 0:
        return None

    summary = build_other_component_summary([
        f"{value}{unit}" if value and unit else "",
        clean_tol_for_display(tol) if tol else "",
        current,
        dcr,
        body_size,
        size,
    ])
    return {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": size,
        "材质（介质）": "",
        "容值": value,
        "容值单位": unit,
        "容值_pf": None,
        "容值误差": tol,
        "耐压（V）": "",
        "尺寸（mm）": body_size,
        "器件类型": component_type,
        "规格摘要": summary,
        "_current": current,
        "额定电流": current,
        "DCR": dcr,
        "共模阻抗": impedance_value if component_type == "共模电感" else "",
        "阻抗@100MHz": impedance_value if component_type == "磁珠" else "",
        "阻抗单位": impedance_unit,
        "电感值": inductance_value,
        "电感单位": inductance_unit,
        "_body_size": body_size,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }


def parse_resistor_spec_query(line):
    raw = clean_text(line)
    if raw == "" or not looks_like_resistor_context(raw):
        return None
    if detect_unsupported_semiconductor_type(raw) != "":
        return None

    normalized = raw.upper()
    normalized = normalized.replace("μF", "UF").replace("µF", "UF")
    normalized = normalized.replace("％", "%").replace("﹪", "%")
    normalized = normalized.replace("＋", "+").replace("﹢", "+")
    normalized = normalized.replace("／", "/").replace("\\", "/")
    normalized = normalized.replace("±", "+/-").replace("卤", "+/-")
    normalized = normalized.replace("+/-", " PLUSMINUS ")
    for old in ["，", ",", "/", "|", ";", "；", "(", ")", "（", "）", "：", ":"]:
        normalized = normalized.replace(old, " ")
    normalized = normalized.replace("PLUSMINUS", "+/-")
    tokens = [token.strip().upper() for token in normalized.split(" ") if token.strip()]

    component_type_hint = detect_resistor_subtype_hint(raw)
    component_type = component_type_hint or "贴片电阻"
    if component_type in SPECIAL_RESISTOR_COMPONENT_TYPES:
        return None
    invalid_size_token = find_invalid_leading_zero_size_token(tokens, component_type)
    size = find_embedded_size(raw)
    if size == "":
        array_size_match = re.search(
            r"(?<![A-Z0-9])(022R|024R|042R|044R|062R|064R)(?![A-Z0-9])",
            normalized,
        )
        if array_size_match is not None:
            size = array_size_match.group(1)
    tol = find_tolerance_in_text(raw)
    resistance_source = raw
    if size in {"022R", "024R", "042R", "044R", "062R", "064R"}:
        resistance_source = re.sub(
            rf"(?<![A-Z0-9]){re.escape(size)}(?![A-Z0-9])",
            " ",
            raw,
            flags=re.I,
        )
    resistance_ohm = find_resistance_in_text(resistance_source)
    if resistance_ohm is None:
        resistance_ohm = find_leading_unlabeled_resistance_in_resistor_text(resistance_source)
    power = find_power_in_text(raw)
    if component_type_hint == "" and resistance_ohm is not None:
        compact_raw = clean_model(raw)
        low_ohm_notation = MILLIOHM_NOTATION_PATTERN.search(raw.replace("Ω", "Ω").replace("ω", "Ω")) is not None
        if "HOLRS" in compact_raw or "LRS" in compact_raw or (resistance_ohm < 0.01 and low_ohm_notation):
            component_type = "合金电阻"
    if size == "":
        for token in tokens:
            embedded_size = find_embedded_size(token)
            if embedded_size != "":
                size = embedded_size
                break
    if tol == "":
        for token in tokens:
            if token in RESISTOR_TOLERANCE_CODE_MAP:
                tol = clean_tol_for_match(RESISTOR_TOLERANCE_CODE_MAP[token])
                break

    param_count = sum([
        1 if size else 0,
        1 if resistance_ohm is not None else 0,
        1 if tol else 0,
        1 if power else 0,
    ])
    if param_count == 0:
        return None

    summary = build_other_component_summary([
        format_resistance_display(resistance_ohm) if resistance_ohm is not None else "",
        clean_tol_for_display(tol) if tol else "",
        power,
        size,
    ])
    result = {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": size,
        "材质（介质）": "",
        "容值_pf": None,
        "容值误差": tol,
        "耐压（V）": "",
        "器件类型": component_type,
        "规格摘要": summary,
        "_resistance_ohm": resistance_ohm,
        "_power": power,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }
    if invalid_size_token != "":
        result["_invalid_size_token"] = invalid_size_token
        result["_unsupported_component"] = True
        result["_unsupported_reason"] = (
            f"尺寸输入错误：{invalid_size_token} 不是当前贴片电阻库支持的封装尺寸；"
            "请确认是否应为 0201、0402、0603、0805、1206、1210、2010、2512 等。"
        )
    return apply_query_brand_hint_to_spec(result, raw)

def looks_like_electrolytic_context(text):
    if looks_like_film_capacitor_context(text):
        return False
    upper = clean_text(text).upper()
    if upper == "":
        return False
    compact = normalize_component_keyword_compact(text)
    if matches_component_alias(text, "铝电解电容"):
        return True
    if "铝电容" in upper or "鋁電容" in upper:
        return True
    electrolytic_tokens = [
        "电解",
        "電解",
        "ELECTROLYTIC",
        "ALUMINUM ELECTROLYTIC",
        "ALUMINIUM ELECTROLYTIC",
        "E CAP",
        "E-CAP",
        "ECAP",
        "PE E CAP",
        "PE E-CAP",
        "PEECAP",
    ]
    capacitor_tokens = ["电容", "電容", "CAP", "CAPACITOR"]
    explicit_electrolytic = (
        any(token in upper for token in electrolytic_tokens)
        or any(token.replace(" ", "") in compact for token in electrolytic_tokens)
        or "电解" in upper
        or "電解" in upper
    )
    if looks_like_mlcc_context(text) and not explicit_electrolytic:
        return False
    if any(token in upper for token in electrolytic_tokens) or any(token.replace(" ", "") in compact for token in electrolytic_tokens):
        if any(token in upper for token in capacitor_tokens) or any(token in compact for token in capacitor_tokens):
            return True
    if ("电容" in upper or "電容" in upper or "CAP" in compact or "CAPACITOR" in compact) and (
        "电解" in upper or "電解" in upper or "ELECTROLYTIC" in upper or "ELECTROLYTIC" in compact
    ):
        return True
    return "UF" in compact and (extract_body_size_from_text(upper) != "" or extract_pitch_from_text(upper) != "")


def parse_varistor_spec_query(line):
    raw = clean_text(line)
    if raw == "" or not looks_like_varistor_context(raw):
        return None

    component_type = detect_resistor_subtype_hint(raw) or "压敏电阻"
    tol = find_tolerance_in_text(raw)
    varistor_voltage = clean_voltage(find_varistor_voltage_in_text(raw))
    disc_size = clean_text(find_disc_size_code(raw))
    pitch = extract_pitch_from_text(raw)
    power = find_power_in_text(raw)

    param_count = sum([
        1 if varistor_voltage else 0,
        1 if tol else 0,
        1 if disc_size else 0,
        1 if pitch else 0,
        1 if power else 0,
    ])
    if param_count == 0:
        return None

    summary = build_other_component_summary([
        voltage_display(varistor_voltage) if varistor_voltage else "",
        clean_tol_for_display(tol) if tol else "",
        disc_size,
        pitch,
        power,
    ])
    return {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": "",
        "材质（介质）": "",
        "容值_pf": None,
        "容值误差": tol,
        "耐压（V）": varistor_voltage,
        "器件类型": component_type,
        "规格摘要": summary,
        "_varistor_voltage": varistor_voltage,
        "_disc_size": disc_size,
        "_pitch": pitch,
        "_power": power,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }

def parse_thermistor_spec_query(line):
    raw = clean_text(line)
    if raw == "" or not looks_like_thermistor_context(raw):
        return None

    size = find_embedded_size(raw)
    tol = find_tolerance_in_text(raw)
    resistance_ohm = find_resistance_in_text(raw)
    resistance_value, resistance_unit = ohm_to_library_value_unit(resistance_ohm)
    b_value = find_b_value_in_text(raw)
    b_condition = find_b_value_condition_in_text(raw)
    b_tolerance = thermistor_b_tolerance_from_record({"规格摘要": raw})
    power = find_power_in_text(raw)

    param_count = sum([
        1 if size else 0,
        1 if resistance_ohm is not None else 0,
        1 if tol else 0,
        1 if b_value else 0,
        1 if b_tolerance else 0,
        1 if power else 0,
    ])
    if param_count == 0:
        return None

    summary = build_other_component_summary([
        format_resistance_display(resistance_ohm) if resistance_ohm is not None else "",
        clean_tol_for_display(tol) if tol else "",
        f"B{b_condition}={b_value}" if b_value and b_condition else (f"B={b_value}" if b_value else ""),
        clean_tol_for_display(b_tolerance) if b_tolerance else "",
        format_power_display(power),
        size,
    ])
    return {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": size,
        "材质（介质）": "",
        "容值_pf": None,
        "容值误差": tol,
        "阻值@25C": resistance_value,
        "阻值单位": resistance_unit,
        "阻值误差": tol,
        "B值": b_value,
        "B值误差": b_tolerance,
        "B值条件": b_condition,
        "功率": format_power_display(power),
        "耐压（V）": "",
        "器件类型": "热敏电阻",
        "规格摘要": summary,
        "_resistance_ohm": resistance_ohm,
        "_power": power,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }

def parse_film_capacitor_spec_query(line):
    raw = clean_text(line)
    if raw == "" or not looks_like_film_capacitor_context(raw):
        return None

    base_spec = parse_spec_query(raw) or {}
    cap_pf = base_spec.get("容值_pf", None)
    tol = clean_tol_for_match(base_spec.get("容值误差", ""))
    volt = clean_voltage(base_spec.get("耐压（V）", ""))
    body_size = extract_body_size_from_text(raw)
    pitch = extract_pitch_from_text(raw)
    material = find_film_material(raw)
    safety_class = find_safety_class(raw)

    param_count = sum([
        1 if cap_pf is not None else 0,
        1 if tol else 0,
        1 if volt else 0,
        1 if body_size else 0,
        1 if pitch else 0,
        1 if material else 0,
        1 if safety_class else 0,
    ])
    if param_count == 0:
        return None

    value, unit = pf_to_value_unit(cap_pf)
    summary = build_other_component_summary([
        material,
        f"{value}{unit}" if value != "" and unit != "" else "",
        clean_tol_for_display(tol) if tol else "",
        voltage_display(volt) if volt else "",
        safety_class,
        body_size,
        pitch,
    ])
    return {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": "",
        "材质（介质）": material,
        "容值_pf": cap_pf,
        "容值误差": tol,
        "耐压（V）": volt,
        "器件类型": "薄膜电容",
        "规格摘要": summary,
        "_body_size": body_size,
        "_pitch": pitch,
        "_safety_class": safety_class,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }

def parse_electrolytic_spec_query(line):
    raw = clean_text(line)
    if raw == "" or not looks_like_electrolytic_context(raw):
        return None

    compact = raw.upper().replace("±", "+/-").replace("卤", "+/-")
    compact = compact.replace("μF", "UF").replace("µF", "UF")

    base_spec = parse_spec_query(raw) or {}
    cap_pf = base_spec.get("容值_pf", None)
    tol = clean_tol_for_match(base_spec.get("容值误差", ""))
    volt = clean_voltage(base_spec.get("耐压（V）", ""))
    body_size = extract_body_size_from_text(compact)
    pitch = extract_pitch_from_text(compact)
    work_temp = normalize_working_temperature_text(base_spec.get("工作温度", "")) or extract_working_temperature_from_text(compact)
    life_hours = normalize_life_hours_value(base_spec.get("寿命（h）", "")) or parse_life_hours_from_text(compact)
    mounting_style = normalize_mounting_style(base_spec.get("安装方式", "") or extract_mounting_style_from_text(compact))
    special_use = normalize_special_use(base_spec.get("特殊用途", "") or extract_special_use_from_text(compact))
    if tol == "":
        tol = find_tolerance_in_text(compact)
    if volt == "":
        volt = parse_voltage_from_text(compact)
    if volt == "":
        compact_match = re.search(r"(?:PF|NF|UF)(\d+(?:\.\d+)?)V", compact.replace(" ", ""))
        if compact_match:
            volt = clean_voltage(compact_match.group(1))

    param_count = sum([
        1 if cap_pf is not None else 0,
        1 if tol else 0,
        1 if volt else 0,
        1 if body_size else 0,
        1 if pitch else 0,
        1 if work_temp else 0,
        1 if life_hours else 0,
        1 if mounting_style else 0,
        1 if special_use else 0,
    ])
    if param_count == 0:
        return None

    value, unit = pf_to_value_unit(cap_pf)
    summary = build_other_component_summary([
        f"{value}{unit}" if value != "" and unit != "" else "",
        clean_tol_for_display(tol) if tol else "",
        voltage_display(volt) if volt else "",
        work_temp,
        format_life_hours_display(life_hours),
        body_size,
        mounting_style,
        special_use,
        pitch,
    ])
    return {
        "品牌": "",
        "型号": raw,
        "尺寸（inch）": "",
        "材质（介质）": "",
        "容值_pf": cap_pf,
        "容值误差": tol,
        "耐压（V）": volt,
        "工作温度": work_temp,
        "寿命（h）": life_hours,
        "安装方式": mounting_style,
        "特殊用途": special_use,
        "器件类型": "铝电解电容",
        "规格摘要": summary,
        "_body_size": body_size,
        "_pitch": pitch,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }

def parse_other_passive_query(line):
    timing = parse_timing_spec_query(line)
    if timing is not None:
        return timing
    for parser in [
        parse_inductor_spec_query,
        parse_film_capacitor_spec_query,
        parse_electrolytic_spec_query,
        parse_varistor_spec_query,
        parse_thermistor_spec_query,
        parse_resistor_spec_query,
    ]:
        parsed = parser(line)
        if parsed is not None:
            return parsed
    return None


def build_component_detail_lines(
    component_type,
    size="",
    material="",
    value="",
    unit="",
    tol="",
    volt="",
    resistance_ohm=None,
    power="",
    body_size="",
    pitch="",
    safety_class="",
    varistor_voltage="",
    disc_size="",
    work_temp="",
    life_hours="",
    mounting_style="",
    special_use="",
    production_status="",
    package_code="",
    diameter_mm="",
    height_mm="",
    polarity="",
    esr="",
    ripple_current="",
    resistance_25c="",
    resistance_unit="",
    resistance_tol="",
    b_value="",
    b_value_condition="",
    common_mode_impedance="",
    impedance_unit="",
    rated_current="",
    dcr="",
    circuit_count="",
    inductance_value="",
    inductance_unit="",
    inductance_tol="",
    saturation_current="",
    shielding="",
    impedance_100mhz="",
    load_capacitance="",
    drive_level="",
    output_type="",
    duty_cycle="",
):
    lines = []
    component_type = normalize_component_type(component_type)
    size = clean_size(size)
    material = clean_material(material)
    value = clean_text(value)
    unit = clean_text(unit).upper()
    tol = clean_tol_for_display(tol) if clean_text(tol) != "" else ""
    volt = voltage_display(volt) if clean_text(volt) != "" else ""
    power = format_power_display(power)
    body_size = clean_text(body_size)
    pitch = clean_text(pitch)
    safety_class = clean_text(safety_class)
    varistor_voltage = voltage_display(varistor_voltage) if clean_text(varistor_voltage) != "" else ""
    disc_size = clean_text(disc_size)
    work_temp = normalize_working_temperature_text(work_temp)
    life_hours = normalize_life_hours_value(life_hours)
    mounting_style = normalize_mounting_style(mounting_style)
    special_use = normalize_special_use(special_use)
    production_status = clean_text(production_status)
    package_code = clean_text(package_code)
    diameter_mm = normalize_dimension_mm_value(diameter_mm)
    height_mm = normalize_dimension_mm_value(height_mm)
    polarity = clean_text(polarity)
    esr = clean_text(esr)
    ripple_current = format_current_display(ripple_current)
    resistance_25c = clean_text(resistance_25c)
    resistance_unit = normalize_library_value_unit(resistance_unit)
    resistance_tol = clean_tol_for_display(resistance_tol) if clean_text(resistance_tol) != "" else ""
    b_value = normalize_b_value_text(b_value)
    b_value_condition = clean_text(b_value_condition)
    common_mode_impedance = format_impedance_display(common_mode_impedance, impedance_unit)
    rated_current = format_current_display(rated_current)
    dcr = clean_text(dcr)
    circuit_count = clean_text(circuit_count)
    inductance_value = clean_text(inductance_value)
    inductance_unit = clean_text(inductance_unit)
    inductance_tol = clean_tol_for_display(inductance_tol) if clean_text(inductance_tol) != "" else ""
    saturation_current = format_current_display(saturation_current)
    shielding = clean_text(shielding)
    impedance_100mhz = format_impedance_display(impedance_100mhz, impedance_unit)
    load_capacitance = clean_text(load_capacitance)
    drive_level = clean_text(drive_level)
    output_type = clean_text(output_type)
    duty_cycle = clean_text(duty_cycle)
    pitch = format_pitch_display(pitch)

    if component_type == "MLCC":
        if size != "":
            lines.append(f"尺寸: {size}")
        if material != "":
            lines.append(f"介质: {material}")
        if value != "" and unit != "":
            lines.append(f"容值: {value} {unit}")
        if tol != "":
            lines.append(f"误差: {tol}")
        if volt != "":
            lines.append(f"耐压: {volt}")
        if work_temp != "":
            lines.append(f"温度: {work_temp}")
        if package_code != "":
            lines.append(f"封装: {package_code}")
        return lines

    if component_type in RESISTOR_COMPONENT_TYPES:
        if size != "":
            lines.append(f"尺寸: {size}")
        if resistance_ohm is not None:
            lines.append(f"阻值: {format_resistance_display(resistance_ohm)}")
        if tol != "":
            lines.append(f"误差: {tol}")
        if power != "":
            lines.append(f"功率: {power}")
        if volt != "":
            lines.append(f"耐压: {volt}")
        if work_temp != "":
            lines.append(f"温度: {work_temp}")
        if package_code != "":
            lines.append(f"封装: {package_code}")
        return lines

    if component_type == "热敏电阻":
        if size != "":
            lines.append(f"尺寸: {size}")
        if resistance_25c != "":
            lines.append(f"R25: {combine_value_and_unit(resistance_25c, resistance_unit)}")
        elif resistance_ohm is not None:
            lines.append(f"阻值: {format_resistance_display(resistance_ohm)}")
        if resistance_tol != "":
            lines.append(f"误差: {resistance_tol}")
