def build_component_section_title(spec, suffix):
    component_label = format_component_category_display(spec)
    if component_label == "":
        component_label = resolve_component_display_type(spec)
    return f"{component_label}{suffix}" if component_label != "" else suffix


def build_component_summary_from_spec(spec):
    if spec is None:
        return ""
    component_type = infer_spec_component_type(spec)
    value, unit = spec_display_value_unit(spec)
    if component_type == "MLCC":
        return build_other_component_summary([
            clean_size(spec.get("尺寸（inch）", "")),
            clean_material(spec.get("材质（介质）", "")),
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            voltage_display(spec.get("耐压（V）", "")),
        ])
    if component_type in RESISTOR_COMPONENT_TYPES:
        return build_other_component_summary([
            format_resistance_display(spec.get("_resistance_ohm")) if spec.get("_resistance_ohm") is not None else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            clean_text(spec.get("_power", "")),
            clean_size(spec.get("尺寸（inch）", "")),
        ])
    if component_type == "热敏电阻":
        return build_other_component_summary([
            format_resistance_display(spec.get("_resistance_ohm")) if spec.get("_resistance_ohm") is not None else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            clean_size(spec.get("尺寸（inch）", "")),
        ])
    if component_type in VARISTOR_COMPONENT_TYPES:
        return build_other_component_summary([
            voltage_display(spec.get("_varistor_voltage", spec.get("耐压（V）", ""))),
            clean_tol_for_display(spec.get("容值误差", "")),
            clean_text(spec.get("_disc_size", "")),
            clean_text(spec.get("_pitch", "")),
            clean_text(spec.get("_power", "")),
        ])
    if component_type == "铝电解电容":
        return build_other_component_summary([
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            voltage_display(spec.get("耐压（V）", "")),
            normalize_working_temperature_text(spec.get("工作温度", "")),
            format_life_hours_display(spec.get("寿命（h）", "")),
            clean_text(spec.get("_body_size", "")),
            normalize_mounting_style(spec.get("安装方式", "")),
            normalize_special_use(spec.get("特殊用途", "")),
            clean_text(spec.get("_pitch", "")),
        ])
    if component_type == "钽电容":
        return build_other_component_summary([
            clean_size(spec.get("尺寸（inch）", "")),
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            voltage_display(spec.get("耐压（V）", "")),
        ])
    if component_type == "薄膜电容":
        return build_other_component_summary([
            clean_material(spec.get("材质（介质）", "")),
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            voltage_display(spec.get("耐压（V）", "")),
            clean_text(spec.get("_safety_class", "")),
            clean_text(spec.get("_body_size", "")),
            clean_text(spec.get("_pitch", "")),
        ])
    if component_type == "引线型陶瓷电容":
        return build_other_component_summary([
            clean_material(spec.get("材质（介质）", "")),
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            voltage_display(spec.get("耐压（V）", "")),
            clean_text(spec.get("_body_size", "")),
            clean_text(spec.get("_pitch", "")),
        ])
    if component_type in INDUCTOR_COMPONENT_TYPES:
        summary = build_other_component_summary([
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            format_current_display(spec.get("额定电流", "")),
            clean_text(spec.get("DCR", "")),
            clean_text(spec.get("尺寸（mm）", "")) or clean_size(spec.get("尺寸（inch）", "")),
        ])
        return summary or clean_text(spec.get("规格摘要", ""))
    if component_type in SEMICONDUCTOR_COMPONENT_TYPES:
        rds_text = clean_text(spec.get("_rds_on", "")) or find_rds_on_in_text(
            " ".join(clean_text(spec.get(key, "")) for key in ["DCR", "规格摘要", "备注1", "备注2", "备注3"])
        )
        return build_other_component_summary([
            clean_text(spec.get("特殊用途", "")) or clean_text(spec.get("极性", "")),
            voltage_display(spec.get("耐压（V）", "")),
            format_current_display(spec.get("额定电流", "")),
            rds_text,
            clean_text(spec.get("封装代码", "")),
        ]) or clean_text(spec.get("规格摘要", ""))
    if component_type in TIMING_COMPONENT_TYPES:
        return build_other_component_summary([
            f"{value}{unit}" if value != "" and unit != "" else "",
            clean_tol_for_display(spec.get("容值误差", "")),
            voltage_display(spec.get("耐压（V）", "")),
            clean_size(spec.get("尺寸（inch）", "")),
        ])
    return clean_text(spec.get("规格摘要", ""))


def extract_body_size_from_text(text):
    upper = clean_text(text).upper()
    match3 = THREE_DIM_SIZE_PATTERN.search(upper)
    if match3:
        return f"{match3.group(1)}*{match3.group(2)}*{match3.group(3)}mm"
    match = ELECTROLYTIC_SIZE_PATTERN.search(upper)
    if not match:
        return ""
    return f"{match.group(1)}*{match.group(2)}mm"


def format_dimension_mm_text(*values):
    parts = [normalize_dimension_mm_value(value) for value in values]
    parts = [part for part in parts if part != ""]
    if not parts:
        return ""
    return f"{'*'.join(parts)}mm"


def normalize_capacitor_body_size_text(value):
    text = clean_text(value)
    if text == "":
        return ""
    extracted = extract_body_size_from_text(text)
    if extracted != "":
        return extracted
    normalized = text.replace("×", "*").replace("X", "*").replace("x", "*")
    normalized = re.sub(r"\s+", "", normalized)
    if normalized.lower().endswith("mm"):
        body = normalized[:-2]
    else:
        body = normalized
    if re.fullmatch(r"\d+(?:\.\d+)?(?:\*\d+(?:\.\d+)?){1,2}", body):
        return f"{body}mm"
    return ""


def capacitor_body_size_parts(value):
    body_size = normalize_capacitor_body_size_text(value)
    if body_size == "":
        return []
    body = body_size[:-2] if body_size.lower().endswith("mm") else body_size
    parts = [normalize_dimension_mm_value(part) for part in body.split("*")]
    return [part for part in parts if part != ""]


def is_scalar_dimension_value(value):
    text = normalize_dimension_mm_value(value)
    if text == "":
        return False
    if re.search(r"[*Xx×\s]", text):
        return False
    match = re.fullmatch(r"(\d+(?:\.\d+)?)(?:±\d+(?:\.\d+)?|\+\d+(?:\.\d+)?/-\d+(?:\.\d+)?)?", text)
    if match is None:
        return False
    try:
        return 0 < float(match.group(1)) <= 500
    except Exception:
        return False


def non_mlcc_capacitor_dimension_fields_from_record(record):
    component_type = normalize_component_type(record.get("_component_type", "")) or normalize_component_type(record.get("器件类型", ""))
    if component_type not in CAPACITOR_COMPONENT_TYPES or component_type == "MLCC":
        return {}, "", ""

    cylindrical_body_hint = any(
        re.search(r"[ØΦ]", clean_text(record.get(col, "")))
        for col in ["_body_size", "尺寸（mm）", "尺寸(mm)", "规格摘要", "备注1"]
    )
    source_value = ""
    source_raw = ""
    parts = []
    for col in ["_body_size", "尺寸（mm）", "尺寸(mm)", "规格摘要", "备注1", "型号"]:
        raw_value = record.get(col, "")
        candidate_parts = capacitor_body_size_parts(raw_value)
        if len(candidate_parts) in {2, 3}:
            parts = candidate_parts
            source_raw = clean_text(raw_value)
            source_value = normalize_capacitor_body_size_text(raw_value)
            break
    if not parts:
        return {}, "", ""

    fields = {}
    if len(parts) == 3:
        fields.update(build_dimension_field_map(parts[0], parts[1], parts[2]))
    elif component_type == "铝电解电容":
        fields["直径（mm）"] = parts[0]
        fields["高度（mm）"] = parts[1]
    elif cylindrical_body_hint or re.search(r"[ØΦ]", source_raw):
        fields.update(build_dimension_field_map(parts[1], parts[0], parts[0]))
        fields["直径（mm）"] = parts[0]
    else:
        fields.update(build_dimension_field_map(parts[0], parts[1], ""))

    source_label = "已有尺寸字段拆分"
    data_source = clean_text(record.get("数据来源", ""))
    official_url = clean_text(record.get("官网链接", ""))
    if official_url != "" or re.search(r"official|官网|规格书|catalog|pdf", data_source, flags=re.I):
        source_label = "官方目录尺寸字段拆分"
    return fields, source_value, source_label


def extract_pitch_mm_value_from_text(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    match = re.search(r"\bP\s*=?\s*(\d+(?:\.\d+)?)\s*MM\b", upper)
    if match is None:
        match = re.search(r"\bP\s*=?\s*(\d+(?:\.\d+)?)\b", upper)
    if match is None:
        return ""
    value = normalize_dimension_mm_value(match.group(1))
    # Earlier clean_size() removed ".0" inside arbitrary package text, so 5.08mm
    # could be cached as 58mm. Lead pitch above 25mm is not credible here.
    if value == "58":
        value = "5.08"
    if value == "254":
        value = "2.54"
    if value == "":
        return ""
    return f"{value}mm"


def looks_like_throughhole_capacitor_package(value):
    upper = clean_text(value).upper()
    if upper == "":
        return False
    return any(token in upper for token in ["THROUGHHOLE", "RADIAL", "AXIAL", "LEADED"]) or re.search(r"\bP\s*=", upper) is not None


MURATA_LEADED_CERAMIC_SERIES_CODES = {"RCE", "RDE", "RHE", "RHS", "RPE", "RPER", "RHEL"}
KYOCERA_AVX_LEADED_CERAMIC_SERIES_CODES = {"SR", "SA", "CK", "MR"}


def looks_like_known_leaded_ceramic_record(record):
    brand = clean_brand(record.get("品牌", ""))
    brand_upper = brand.upper()
    series = clean_text(record.get("系列", "")).upper()
    model = clean_model(record.get("型号", ""))
    package_text = " ".join(
        clean_text(record.get(col, ""))
        for col in ["尺寸（inch）", "_size", "封装代码", "规格摘要", "备注1"]
    )
    if looks_like_throughhole_capacitor_package(package_text):
        return True
    if ("MURATA" in brand_upper or "村田" in brand) and (
        series in MURATA_LEADED_CERAMIC_SERIES_CODES
        or any(model.startswith(code) for code in MURATA_LEADED_CERAMIC_SERIES_CODES)
    ):
        return True
    if ("KYOCERA" in brand_upper or "AVX" in brand_upper or "晶瓷" in brand) and (
        series in KYOCERA_AVX_LEADED_CERAMIC_SERIES_CODES
        or any(model.startswith(code) for code in KYOCERA_AVX_LEADED_CERAMIC_SERIES_CODES)
    ):
        return True
    return False


def capacitor_dimension_mm_text_from_record(record):
    current = clean_text(record.get("尺寸（mm）", "")) or clean_text(record.get("尺寸(mm)", ""))
    if current != "":
        return current
    component_type = normalize_component_type(record.get("_component_type", "")) or normalize_component_type(record.get("器件类型", ""))
    if component_type == "MLCC":
        for col in ["_body_size", "尺寸（inch）", "_size", "封装代码", "规格摘要", "备注1"]:
            body_size = normalize_capacitor_body_size_text(record.get(col, ""))
            if body_size != "":
                return body_size
        dimension_text = format_dimension_mm_text(
            record.get("长度（mm）", ""),
            record.get("宽度（mm）", ""),
            record.get("高度（mm）", ""),
        )
        if dimension_text != "":
            return dimension_text
        nominal_fields = infer_mlcc_nominal_dimension_fields_from_size(
            clean_size(record.get("_size", "")) or clean_size(record.get("尺寸（inch）", ""))
        )
        return format_dimension_mm_text(
            nominal_fields.get("长度（mm）", ""),
            nominal_fields.get("宽度（mm）", ""),
            nominal_fields.get("高度（mm）", ""),
        )
    if component_type in CAPACITOR_COMPONENT_TYPES:
        body_size = normalize_capacitor_body_size_text(record.get("_body_size", ""))
        if body_size != "":
            return body_size
        body_size = format_dimension_mm_text(record.get("直径（mm）", ""), record.get("高度（mm）", ""))
        if body_size != "":
            return body_size
        return format_dimension_mm_text(
            record.get("长度（mm）", ""),
            record.get("宽度（mm）", ""),
            record.get("高度（mm）", ""),
        )
    return ""


def capacitor_body_size_text_from_record(record):
    component_type = normalize_component_type(record.get("_component_type", "")) or normalize_component_type(record.get("器件类型", ""))
    if component_type not in (CAPACITOR_COMPONENT_TYPES - {"MLCC"}):
        return clean_text(record.get("_body_size", ""))
    for value in [
        record.get("_body_size", ""),
        record.get("尺寸（mm）", ""),
        record.get("尺寸(mm)", ""),
    ]:
        body_size = normalize_capacitor_body_size_text(value)
        if body_size != "":
            return body_size
    body_size = format_dimension_mm_text(record.get("直径（mm）", ""), record.get("高度（mm）", ""))
    if body_size != "":
        return body_size
    return format_dimension_mm_text(
        record.get("长度（mm）", ""),
        record.get("宽度（mm）", ""),
        record.get("高度（mm）", ""),
    )


def normalize_capacitor_dimension_fields_in_dataframe(df):
    if df is None or df.empty:
        return df
    if "_component_type" not in df.columns and "器件类型" not in df.columns:
        return df
    work = df.copy()
    for col in ["尺寸（mm）", "_body_size", "长度（mm）", "宽度（mm）", "高度（mm）", "直径（mm）"]:
        if col not in work.columns:
            work[col] = ""
    component_types = (
        work["_component_type"].astype("string").fillna("").apply(normalize_component_type)
        if "_component_type" in work.columns
        else work["器件类型"].astype("string").fillna("").apply(normalize_component_type)
    )
    capacitor_mask = component_types.isin(CAPACITOR_COMPONENT_TYPES)
    if not capacitor_mask.any():
        return work
    cap_rows = work.loc[capacitor_mask]

    size_mm = work.loc[capacitor_mask, "尺寸（mm）"].astype("string").fillna("").apply(clean_text)
    blank_size_mm = size_mm.eq("")
    if blank_size_mm.any():
        fill_values = cap_rows.loc[blank_size_mm].apply(capacitor_dimension_mm_text_from_record, axis=1).astype(str).apply(clean_text)
        fill_values = fill_values[fill_values.ne("")]
        if len(fill_values) > 0:
            work.loc[fill_values.index, "尺寸（mm）"] = fill_values

    non_mlcc_mask = capacitor_mask & component_types.ne("MLCC")
    if non_mlcc_mask.any():
        body_size = work.loc[non_mlcc_mask, "_body_size"].astype("string").fillna("").apply(clean_text)
        blank_body = body_size.eq("")
        if blank_body.any():
            body_rows = work.loc[non_mlcc_mask].loc[blank_body]
            fill_body = body_rows.apply(capacitor_body_size_text_from_record, axis=1).astype(str).apply(clean_text)
            fill_body = fill_body[fill_body.ne("")]
            if len(fill_body) > 0:
                work.loc[fill_body.index, "_body_size"] = fill_body
        for idx in work.loc[non_mlcc_mask].index.tolist():
            row = work.loc[idx].to_dict()
            fields, normalized_body, source_label = non_mlcc_capacitor_dimension_fields_from_record(row)
            if not fields:
                continue
            if normalized_body != "":
                if clean_text(work.at[idx, "尺寸（mm）"]) == "" or clean_text(work.at[idx, "尺寸（mm）"]) != normalized_body:
                    work.at[idx, "尺寸（mm）"] = normalized_body
                if clean_text(work.at[idx, "_body_size"]) == "":
                    work.at[idx, "_body_size"] = normalized_body
            for col in ["长度（mm）", "宽度（mm）", "高度（mm）", "直径（mm）"]:
                value = normalize_dimension_mm_value(fields.get(col, ""))
                current_value = clean_text(work.at[idx, col])
                should_replace = current_value == "" or not is_scalar_dimension_value(current_value)
                if value != "" and should_replace:
                    work.at[idx, col] = value
                elif value == "" and col == "直径（mm）" and current_value != "" and not is_scalar_dimension_value(current_value):
                    work.at[idx, col] = ""
            if "尺寸来源" not in work.columns:
                work["尺寸来源"] = ""
            if source_label != "" and clean_text(work.at[idx, "尺寸来源"]) == "":
                work.at[idx, "尺寸来源"] = source_label
    return work


def normalize_leaded_ceramic_rows_in_dataframe(df):
    if df is None or df.empty:
        return df
    if "_component_type" not in df.columns and "器件类型" not in df.columns:
        return df
    work = df.copy()
    for col in [
        "器件类型", "_component_type", "安装方式", "封装代码", "尺寸（inch）", "_size",
        "尺寸（mm）", "_body_size", "脚距（mm）", "系列说明",
    ]:
        if col not in work.columns:
            work[col] = ""
        elif isinstance(work[col].dtype, pd.CategoricalDtype):
            work[col] = work[col].astype("object")

    component_types = work["_component_type"].astype("string").fillna("").apply(normalize_component_type)
    if "器件类型" in work.columns:
        fallback_types = work["器件类型"].astype("string").fillna("").apply(normalize_component_type)
        component_types = component_types.where(component_types.ne(""), fallback_types)
    mlcc_idx = work[component_types.eq("MLCC")].index
    if len(mlcc_idx) == 0:
        return work

    target_idx = [
        idx for idx in mlcc_idx
        if looks_like_known_leaded_ceramic_record(work.loc[idx].to_dict())
    ]
    if not target_idx:
        return work

    for idx in target_idx:
        row = work.loc[idx].to_dict()
        package_text = clean_text(row.get("尺寸（inch）", "")) or clean_text(row.get("_size", "")) or clean_text(row.get("封装代码", ""))
        body_size = ""
        for col in ["_body_size", "尺寸（mm）", "尺寸（inch）", "_size", "封装代码", "规格摘要", "备注1"]:
            body_size = normalize_capacitor_body_size_text(row.get(col, ""))
            if body_size != "":
                break
        pitch = ""
        for col in ["脚距（mm）", "尺寸（inch）", "_size", "封装代码", "规格摘要", "备注1"]:
            pitch = extract_pitch_mm_value_from_text(row.get(col, ""))
            if pitch != "":
                break

        work.at[idx, "器件类型"] = "引线型陶瓷电容"
        work.at[idx, "_component_type"] = "引线型陶瓷电容"
        if clean_text(work.at[idx, "安装方式"]) == "":
            work.at[idx, "安装方式"] = "插件"
        if clean_text(work.at[idx, "封装代码"]) == "":
            work.at[idx, "封装代码"] = "THROUGHHOLE" if looks_like_throughhole_capacitor_package(package_text) else "RADIAL"
        if body_size != "":
            work.at[idx, "尺寸（mm）"] = body_size
            work.at[idx, "_body_size"] = body_size
        if pitch != "":
            work.at[idx, "脚距（mm）"] = pitch

        if not is_mlcc_size_code(work.at[idx, "尺寸（inch）"]):
            work.at[idx, "尺寸（inch）"] = ""
        if not is_mlcc_size_code(work.at[idx, "_size"]):
            work.at[idx, "_size"] = ""
        if clean_text(work.at[idx, "系列说明"]) == "" or "MLCC" in clean_text(work.at[idx, "系列说明"]).upper():
            work.at[idx, "系列说明"] = "引线型陶瓷电容 / Radial leaded ceramic capacitor"
    return work


def infer_mlcc_size_from_model_record(record):
    model = clean_model(record.get("型号", ""))
    if model == "":
        return ""
    brand_text = clean_brand(record.get("品牌", ""))
    brand_upper = brand_text.upper()
    if "TAIYO" in brand_upper or "太诱" in brand_text or "太阳诱电" in brand_text or taiyo_mlcc_series_code_from_model(model) != "":
        size = infer_taiyo_mlcc_size_from_model(model)
        if size != "":
            return size
    parsed = parse_model_rule(
        model,
        brand=brand_text,
        component_type=normalize_component_type(record.get("器件类型", "")) or "MLCC",
    )
    if parsed is None:
        return ""
    return clean_size(parsed.get("尺寸（inch）", ""))


def apply_taiyo_leaded_ceramic_overrides_in_dataframe(df):
    if df is None or df.empty or "型号" not in df.columns:
        return df
    work = df.copy()
    brand_series = work["品牌"].astype("string").fillna("").apply(clean_brand) if "品牌" in work.columns else pd.Series([""] * len(work), index=work.index, dtype="string")
    model_series = work["型号"].astype("string").fillna("").apply(clean_model)
    brand_mask = brand_series.str.contains("TAIYO|太诱|太阳诱电", case=False, na=False)
    model_mask = model_series.str.match(r"^[LETGU][PT](?:025|050|075)", na=False)
    target_idx = work[brand_mask & model_mask].index.tolist()
    if not target_idx:
        return work
    for col in [
        "器件类型", "系列", "系列说明", "安装方式", "封装代码", "尺寸（inch）", "尺寸（mm）",
        "_body_size", "容值", "容值单位", "容值误差", "耐压（V）", "容值_pf",
        "_component_type", "_model_rule_authority",
    ]:
        if col not in work.columns:
            work[col] = ""
        elif isinstance(work[col].dtype, pd.CategoricalDtype):
            work[col] = work[col].astype("object")
    for idx in target_idx:
        parsed = parse_taiyo_leaded_ceramic_model(work.at[idx, "型号"])
        if parsed is None:
            continue
        for col, value in parsed.items():
            if col == "容值_pf":
                if value is not None:
                    work.at[idx, col] = value
                    cap_value, cap_unit = pf_to_value_unit(value)
                    if cap_value != "":
                        work.at[idx, "容值"] = cap_value
                    if cap_unit != "":
                        work.at[idx, "容值单位"] = cap_unit
                continue
            if clean_text(value) != "":
                work.at[idx, col] = value
        work.at[idx, "_component_type"] = "引线型陶瓷电容"
    return work


def fill_missing_mlcc_size_fields_in_dataframe(df):
    if df is None or df.empty:
        return df
    if "_component_type" not in df.columns and "器件类型" not in df.columns:
        return df
    work = df.copy()
    if "_size" not in work.columns:
        work["_size"] = ""
    if "尺寸（inch）" not in work.columns:
        work["尺寸（inch）"] = ""
    work["_size"] = work["_size"].astype("string").fillna("").apply(clean_size)
    work["尺寸（inch）"] = work["尺寸（inch）"].astype("string").fillna("").apply(clean_size)
    component_types = (
        work["_component_type"].astype("string").fillna("").apply(normalize_component_type)
        if "_component_type" in work.columns
        else work["器件类型"].astype("string").fillna("").apply(normalize_component_type)
    )
    mlcc_mask = component_types.eq("MLCC")
    if not mlcc_mask.any():
        return work
    mlcc_indices = mlcc_mask[mlcc_mask].index
    work.loc[mlcc_indices, "_size"] = work.loc[mlcc_indices, "_size"].astype("string").fillna("").apply(clean_mlcc_size_code)
    size_from_inch = work.loc[mlcc_mask, "尺寸（inch）"].astype("string").fillna("").apply(clean_mlcc_size_code)
    blank_size = work.loc[mlcc_mask, "_size"].astype("string").fillna("").apply(clean_size).eq("")
    if blank_size.any():
        fill_from_inch = size_from_inch[blank_size & size_from_inch.ne("")]
        if len(fill_from_inch) > 0:
            work.loc[fill_from_inch.index, "_size"] = fill_from_inch
    blank_size = work.loc[mlcc_mask, "_size"].astype("string").fillna("").apply(clean_size).eq("")
    if blank_size.any():
        target_idx = blank_size[blank_size].index
        inferred = work.loc[target_idx].apply(infer_mlcc_size_from_model_record, axis=1).astype(str).apply(clean_size)
        inferred = inferred[inferred.ne("")]
        if len(inferred) > 0:
            work.loc[inferred.index, "_size"] = inferred
            blank_inch = work.loc[inferred.index, "尺寸（inch）"].astype("string").fillna("").apply(clean_size).eq("")
            if blank_inch.any():
                work.loc[blank_inch[blank_inch].index, "尺寸（inch）"] = inferred.loc[blank_inch[blank_inch].index]
    return work


def extract_pitch_from_text(text):
    upper = clean_text(text).upper()
    match = PITCH_PATTERN.search(upper)
    if match:
        return f"脚距{match.group(1)}mm"
    if looks_like_varistor_context(text):
        match = VARISTOR_PITCH_PATTERN.search(upper)
        if match:
            return f"脚距{match.group(1)}mm"
    return ""


def _format_compact_number(value):
    try:
        num = float(value)
    except Exception:
        return clean_text(value)
    if abs(num - round(num)) < 1e-9:
        return str(int(round(num)))
    return f"{num:.6f}".rstrip("0").rstrip(".")


def normalize_numeric_range_text(value):
    text = clean_text(value)
    if text == "":
        return ""
    normalized = text.replace("−", "-").replace("–", "-").replace("—", "-")
    normalized = normalized.replace("～", "~").replace("至", "~")
    compact = re.sub(r"\s+", "", normalized)
    compact = re.sub(r"(?i)(?<=\d)TO(?=[+\-]?\d)", "~", compact)
    range_match = re.fullmatch(r"([+\-]?\d+(?:\.\d+)?)(?:~|-)([+\-]?\d+(?:\.\d+)?)", compact)
    if range_match:
        return f"{_format_compact_number(range_match.group(1))}~{_format_compact_number(range_match.group(2))}"
    if re.fullmatch(r"[+\-]?\d+(?:\.\d+)?", compact):
        return _format_compact_number(compact)
    return text


def working_temperature_bounds(value):
    text = clean_text(value)
    if text == "":
        return None, None
    upper = text.upper()
    upper = upper.replace("−", "-").replace("–", "-").replace("—", "-")
    upper = upper.replace("～", "~").replace("至", "~").replace("TO", "~")
    upper = upper.replace("℃", "C").replace("°C", "C")
    compact = re.sub(r"\s+", "", upper)

    range_match = re.search(
        r"([+\-]?\d+(?:\.\d+)?)\s*C?\s*(?:~|-)\s*([+\-]?\d+(?:\.\d+)?)(?:C)?",
        compact,
    )
    if range_match:
        try:
            return float(range_match.group(1)), float(range_match.group(2))
        except Exception:
            return None, None

    single_match = re.search(r"([+\-]?\d+(?:\.\d+)?)(?:C)$", compact)
    if single_match:
        try:
            single = float(single_match.group(1))
            return None, single
        except Exception:
            return None, None

    if re.fullmatch(r"[+\-]?\d+(?:\.\d+)?", compact):
        try:
            single = float(compact)
            return None, single
        except Exception:
            return None, None
    return None, None


def normalize_working_temperature_text(value):
    low, high = working_temperature_bounds(value)
    if low is None and high is None:
        return ""
    if low is None:
        return f"{_format_compact_number(high)}℃"
    return f"{_format_compact_number(low)}~{_format_compact_number(high)}℃"


def extract_working_temperature_from_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    upper = raw.upper().replace("−", "-").replace("–", "-").replace("—", "-")
    upper = upper.replace("～", "~").replace("至", "~").replace("TO", "~").replace("℃", "C").replace("°C", "C")
    patterns = [
        r"(?:WORK(?:ING)?|CATEGORY|OPERATING)\s*TEMPERATURE(?:\s*RANGE)?[^0-9+\-]{0,24}([+\-]?\d+(?:\.\d+)?\s*(?:~|-)\s*[+\-]?\d+(?:\.\d+)?)",
        r"(?:工作温度|温度范围)[^0-9+\-]{0,8}([+\-]?\d+(?:\.\d+)?\s*(?:~|-)\s*[+\-]?\d+(?:\.\d+)?)",
        r"([+\-]?\d+(?:\.\d+)?\s*(?:~|-)\s*[+\-]?\d+(?:\.\d+)?)\s*C(?=$|[^0-9A-Z])",
        r"([+\-]?\d+(?:\.\d+)?)\s*C(?=$|[^0-9A-Z])",
    ]
    for pattern in patterns:
        match = re.search(pattern, upper, flags=re.I)
        if not match:
            continue
        normalized = normalize_working_temperature_text(match.group(1))
        if normalized != "":
            return normalized
    bare_negative_range = re.search(r"(-\d+(?:\.\d+)?)\s*(?:~|-)\s*(\+?\d+(?:\.\d+)?)(?=$|[^0-9A-Z])", upper, flags=re.I)
    if bare_negative_range:
        normalized = normalize_working_temperature_text(f"{bare_negative_range.group(1)}~{bare_negative_range.group(2)}℃")
        if normalized != "":
            return normalized
    return ""


def life_hours_to_number(value):
    text = clean_text(value).upper().replace(",", "")
    if text == "":
        return None
    if re.fullmatch(r"\d+(?:\.\d+)?", text):
        try:
            return float(text)
        except Exception:
            return None
    if not re.search(r"(?:H|HR|HRS|HOUR)", text):
        return None
    match = re.search(r"(\d{3,6}(?:\.\d+)?)", text)
    if not match:
        return None
    try:
        return float(match.group(1))
    except Exception:
        return None


def normalize_life_hours_value(value):
    number = life_hours_to_number(value)
    if number is None:
        return ""
    return _format_compact_number(number)


def parse_life_hours_from_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    upper = raw.upper().replace(",", "").replace("小时", "H").replace("小時", "H")
    match = re.search(r"(\d{3,6}(?:\.\d+)?)\s*(?:H|HR|HRS|HOUR|HOURS)(?=$|[^0-9A-Z])", upper)
    if not match:
        return ""
    return normalize_life_hours_value(match.group(1))


def format_life_hours_display(value):
    normalized = normalize_life_hours_value(value)
    return f"{normalized}h" if normalized != "" else ""


def normalize_b_value_text(value):
    text = clean_text(value).upper().replace(" ", "")
    if text == "":
        return ""
    if text.endswith("KK"):
        text = text[:-1]
    match = re.fullmatch(r"(\d+(?:\.\d+)?)(K)?", text)
    if match:
        return f"{match.group(1)}K"
    return clean_text(value)


def combine_value_and_unit(value, unit="", separator=" "):
    value_text = clean_text(value)
    unit_text = clean_text(unit)
    if value_text == "":
        return ""
    if unit_text == "":
        return value_text
    if value_text.upper().endswith(unit_text.upper()):
        return value_text
    joiner = "" if unit_text in {"Ω", "KΩ", "MΩ", "mΩ", "A", "mA", "uA", "nH", "uH", "mH", "H", "Hz", "kHz", "MHz", "GHz"} else separator
    return f"{value_text}{joiner}{unit_text}"


def format_current_display(value):
    text = clean_text(value).replace(" ", "")
    if text == "":
        return ""
    match = re.fullmatch(r"(\d+(?:\.\d+)?)(UA|MA|A)", text, flags=re.I)
    if match:
        return f"{match.group(1)}{match.group(2).upper()}"
    return clean_text(value)


def format_pitch_display(value):
    text = clean_text(value)
    if text == "":
        return ""
    if "脚距" in text or "PITCH" in text.upper():
        return text
    normalized = normalize_dimension_mm_value(text)
    if normalized == "":
        return text
    return f"脚距{normalized}mm"


def format_impedance_display(value, unit=""):
    value_text = clean_text(value)
    unit_text = normalize_library_value_unit(unit)
    if value_text == "":
        return ""
    upper = value_text.upper()
    if any(token in upper for token in ["Ω", "OHM"]):
        return value_text.replace("OHMS", "Ω").replace("OHM", "Ω")
    if unit_text == "":
        unit_text = "Ω"
    return combine_value_and_unit(value_text, unit_text, separator=" ")


def parse_inductance_value_unit(text):
    normalized = clean_text(text).upper().replace("Μ", "U").replace("ΜH", "UH").replace("μ", "U").replace("µ", "U").replace(" ", "")
    if normalized == "":
        return "", ""
    match = re.fullmatch(r"(\d+(?:\.\d+)?)(NH|UH|MH|H)", normalized, flags=re.I)
    if not match:
        return "", ""
    return clean_text(match.group(1)), clean_text(match.group(2)).upper()


def parse_frequency_value_unit(text):
    normalized = clean_text(text).upper().replace(" ", "")
    if normalized == "":
        return "", ""
    match = re.fullmatch(r"(\d+(?:\.\d+)?)(HZ|KHZ|MHZ|GHZ)", normalized, flags=re.I)
    if not match:
        return "", ""
    return clean_text(match.group(1)), clean_text(match.group(2)).upper()


def normalize_timing_output_type(value):
    text = clean_text(value).upper().replace(" ", "").replace("_", "-")
    if text == "":
        return ""
    compact = text.replace("-", "")
    if "LVCMOS" in compact or compact == "CMOS" or "CMOS" in compact:
        return "CMOS"
    if "LVDS" in compact:
        return "LVDS"
    if "LVPECL" in compact or "PECL" in compact:
        return "LVPECL"
    if "HCSL" in compact:
        return "HCSL"
    if "CLIPPEDSINE" in compact or "SINE" in compact:
        return "CLIPPED SINE"
    return text


def timing_voltage_bounds(value):
    normalized = clean_voltage(value)
    if normalized == "":
        return None, None
    range_match = re.fullmatch(r"([+\-]?\d+(?:\.\d+)?)~([+\-]?\d+(?:\.\d+)?)", normalized)
    if range_match:
        low = float(range_match.group(1))
        high = float(range_match.group(2))
        return (min(low, high), max(low, high))
    try:
        scalar = float(normalized)
    except Exception:
        return None, None
    return scalar, scalar


def timing_voltage_allows(candidate, required):
    required_low, required_high = timing_voltage_bounds(required)
    candidate_low, candidate_high = timing_voltage_bounds(candidate)
    if required_low is None or required_high is None:
        return True
    if candidate_low is None or candidate_high is None:
        return False
    return candidate_low <= required_low + 1e-9 and candidate_high >= required_high - 1e-9


def timing_option_numbers(value):
    text = clean_text(value)
    if text == "":
        return []
    numbers = []
    for match in re.finditer(r"[+\-]?\d+(?:\.\d+)?", text):
        try:
            number = float(match.group(0))
        except Exception:
            continue
        if not any(abs(number - existing) < 1e-9 for existing in numbers):
            numbers.append(number)
    return numbers


def timing_option_contains(value, required):
    try:
        target = float(clean_text(required))
    except Exception:
        return False
    return any(abs(option - target) < 1e-9 for option in timing_option_numbers(value))


def timing_frequency_candidate_allows(row, required):
    required_text = clean_text(required)
    if required_text == "":
        return True
    try:
        target = float(required_text)
    except Exception:
        return False

    exact_text = clean_text(row.get("容值", ""))
    if exact_text != "":
        try:
            if abs(float(exact_text) - target) < 1e-9:
                return True
        except Exception:
            pass

    try:
        minimum = float(clean_text(row.get("频率下限", "")))
        maximum = float(clean_text(row.get("频率上限", "")))
    except Exception:
        minimum = maximum = None
    if minimum is not None and maximum is not None:
        if min(minimum, maximum) - 1e-9 <= target <= max(minimum, maximum) + 1e-9:
            return True
    return timing_option_contains(row.get("频率选项", ""), target)


def timing_tolerance_candidate_allows(row, required):
    required_text = clean_frequency_tolerance_for_match(required)
    if required_text == "":
        return True
    candidate_text = clean_frequency_tolerance_for_match(
        row.get("容值误差", "") or row.get("频差（ppm）", "")
    )
    if candidate_text == required_text:
        return True
    return timing_option_contains(row.get("频差选项", ""), required_text)


def timing_voltage_candidate_allows(row, required):
    required_text = clean_voltage(required)
    if required_text == "":
        return True
    if timing_voltage_allows(
        row.get("耐压（V）", "") or row.get("电源电压", ""),
        required_text,
    ):
        return True
    return timing_option_contains(row.get("电压选项", ""), required_text)


def timing_load_cap_candidate_allows(row, required):
    required_text = clean_text(required)
    if required_text == "":
        return True
    candidate_text = clean_text(row.get("负载电容（pF）", ""))
    try:
        if candidate_text != "" and abs(float(candidate_text) - float(required_text)) < 1e-9:
            return True
    except Exception:
        pass
    return timing_option_contains(row.get("负载电容选项", ""), required_text)


def timing_spec_number(value):
    text = clean_text(value).replace("−", "-").replace("＋", "+")
    if text == "" or "包含在总频差内" in text or text.upper() == "TBD":
        return None
    numbers = []
    for match in re.finditer(r"[+\-]?\+?\d+(?:\.\d+)?", text):
        try:
            numbers.append(float(match.group(0).replace("++", "+")))
        except Exception:
            continue
    if not numbers:
        return None
    return max(abs(number) for number in numbers)


def timing_ppm_candidate_allows(candidate, required):
    required_number = timing_spec_number(required)
    if required_number is None:
        return clean_text(candidate).upper() == clean_text(required).upper()
    candidate_number = timing_spec_number(candidate)
    if candidate_number is None:
        return False
    return candidate_number <= required_number + 1e-9


def timing_signed_scalar_equal(candidate, required):
    def first_number(value):
        match = re.search(r"[+\-]?\d+(?:\.\d+)?", clean_text(value).replace("−", "-"))
        return float(match.group(0)) if match else None

    candidate_number = first_number(candidate)
    required_number = first_number(required)
    if required_number is None:
        return True
    if candidate_number is None:
        return False
    return abs(candidate_number - required_number) < 1e-9


def timing_turnover_candidate_allows(candidate, required):
    def numbers(value):
        parsed = []
        for match in re.finditer(r"[+\-]?\d+(?:\.\d+)?", clean_text(value).replace("−", "-")):
            try:
                parsed.append(float(match.group(0)))
            except Exception:
                continue
        return parsed

    required_values = numbers(required)
    if not required_values:
        return True
    candidate_values = numbers(candidate)
    if len(candidate_values) < len(required_values):
        return False
    return all(
        abs(candidate_values[index] - required_values[index]) < 1e-9
        for index in range(len(required_values))
    )


def timing_detail_candidate_state(row, spec):
    checks = [
        (
            "工作温度",
            lambda candidate, required: working_temperature_covers(candidate, required),
        ),
        (
            "频率温度特性（ppm）",
            timing_ppm_candidate_allows,
        ),
        (
            "25℃老化（ppm）",
            timing_ppm_candidate_allows,
        ),
        (
            "拐点温度",
            timing_turnover_candidate_allows,
        ),
        (
            "抛物线系数（ppm/℃²）",
            timing_signed_scalar_equal,
        ),
        (
            "泛音阶次",
            lambda candidate, required: (
                normalize_timing_overtone_order(candidate)
                == normalize_timing_overtone_order(required)
            ),
        ),
    ]
    complete = True
    for field, allows in checks:
        required = clean_text(spec.get(field, ""))
        if required == "":
            continue
        candidate = clean_text(row.get(field, ""))
        if field == "25℃老化（ppm）" and candidate == "":
            candidate = clean_text(row.get("长期稳定度", ""))
        if candidate == "":
            complete = False
            continue
        if not allows(candidate, required):
            return False, False
    return True, complete


def timing_query_has_complete_details(spec, component_type):
    if component_type == "实时时钟模块":
        return all(
            clean_text(value) != ""
            for value in [
                spec.get("封装代码", "") or spec.get("尺寸（mm）", ""),
                spec.get("接口类型", ""),
                spec.get("耐压（V）", "") or spec.get("电源电压", ""),
                spec.get("计时电压（V）", ""),
                spec.get("备用电流（µA）", ""),
                spec.get("工作温度", ""),
                spec.get("频率温度特性（ppm）", "") or spec.get("容值误差", ""),
            ]
        )
    work_temp = clean_text(spec.get("工作温度", ""))
    aging = clean_text(spec.get("25℃老化（ppm）", ""))
    if work_temp == "" or aging == "":
        return False
    if component_type == "振荡器":
        return True
    unit = clean_text(spec.get("容值单位", "")).upper()
    try:
        frequency = float(clean_text(spec.get("容值", "")))
    except Exception:
        frequency = None
    is_khz_crystal = unit == "KHZ" and frequency is not None and frequency <= 100
    if is_khz_crystal:
        return (
            clean_text(spec.get("拐点温度", "")) != ""
            and clean_text(spec.get("抛物线系数（ppm/℃²）", "")) != ""
        )
    return (
        clean_text(spec.get("频率温度特性（ppm）", "")) != ""
        and clean_text(spec.get("泛音阶次", "")) != ""
    )


def timing_model_requires_configuration(row):
    granularity = clean_text(row.get("型号粒度", "")).upper()
    if any(token in granularity for token in ["系列", "模板", "可配置"]):
        return True
    model = clean_text(row.get("型号", ""))
    return "*" in model or "?" in model


def find_timing_output_type_in_text(text):
    upper = clean_text(text).upper()
    if upper == "":
        return ""
    for token in ["LVCMOS", "CMOS", "LVDS", "LV-PECL", "LVPECL", "HCSL", "CLIPPED SINE"]:
        if token in upper:
            return "LV-PECL" if token in {"LVPECL", "LV-PECL"} else token
    return ""


def find_load_capacitance_pf_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    patterns = [
        r"(?:CL|LOAD\s*CAP(?:ACITANCE)?|负载电容)[^0-9]{0,20}(\d+(?:\.\d+)?)\s*PF\b",
        r"(\d+(?:\.\d+)?)\s*PF\b",
    ]
    for pattern in patterns:
        match = re.search(pattern, raw, flags=re.I)
        if match:
            return clean_text(match.group(1))
    return ""


TIMING_PACKAGE_CODES = {
    "1008", "1210", "1610", "1612", "2012", "2016", "2520",
    "3215", "3225", "5032", "7015", "7050", "8038",
}


def find_timing_package_code_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    for match in re.finditer(r"(?<!\d)(\d{4})(?!\d)", raw):
        code = match.group(1)
        if code in TIMING_PACKAGE_CODES:
            return code
    dimension_match = re.search(
        r"(?<!\d)(\d+(?:\.\d+)?)\s*[xX×*]\s*(\d+(?:\.\d+)?)\s*(?:MM)?",
        raw,
        flags=re.I,
    )
    if not dimension_match:
        return ""
    try:
        length_code = int(round(float(dimension_match.group(1)) * 10))
        width_code = int(round(float(dimension_match.group(2)) * 10))
    except Exception:
        return ""
    code = f"{length_code:02d}{width_code:02d}"
    return code if code in TIMING_PACKAGE_CODES else ""


def parse_timing_spec_query(line):
    raw = clean_text(line)
    if raw == "":
        return None
    component_type = detect_timing_subtype_hint(raw)
    if component_type not in TIMING_COMPONENT_TYPES:
        return None

    frequency = find_frequency_in_text(raw)
    value, unit = parse_frequency_value_unit(frequency)
    size = find_timing_package_code_in_text(raw) or find_embedded_size(raw)
    body_size = extract_body_size_from_text(raw)
    freq_tol = clean_frequency_tolerance_for_match(find_primary_timing_tolerance_in_text(raw))
    output_type = find_timing_output_type_in_text(raw) if component_type == "振荡器" else ""
    load_cap = find_load_capacitance_pf_in_text(raw) if component_type == "晶振" else ""
    work_temp = extract_working_temperature_from_text(raw)
    temp_characteristic = find_labeled_timing_ppm_in_text(
        raw,
        TIMING_TEMPERATURE_CHARACTERISTIC_LABEL,
    )
    aging = find_labeled_timing_ppm_in_text(raw, TIMING_AGING_LABEL)
    turnover_temp = find_turnover_temperature_in_text(raw) if component_type == "晶振" else ""
    parabolic_coef = find_parabolic_coefficient_in_text(raw) if component_type == "晶振" else ""
    overtone_order = find_timing_overtone_order_in_text(raw) if component_type == "晶振" else ""
    voltage = ""
    if component_type == "振荡器":
        voltage_match = re.search(r"(?<![A-Z0-9])(\d+(?:\.\d+)?)\s*V(?![A-Z])", raw.upper())
        if voltage_match:
            voltage = clean_voltage(voltage_match.group(1))

    param_count = sum([
        1 if component_type != "" else 0,
        1 if value != "" and unit != "" else 0,
        1 if size != "" or body_size != "" else 0,
        1 if freq_tol != "" else 0,
        1 if voltage != "" else 0,
        1 if output_type != "" else 0,
        1 if load_cap != "" else 0,
        1 if work_temp != "" else 0,
        1 if temp_characteristic != "" else 0,
        1 if aging != "" else 0,
        1 if turnover_temp != "" else 0,
        1 if parabolic_coef != "" else 0,
        1 if overtone_order != "" else 0,
    ])
    if value == "" and unit == "":
        return None

    spec = {
        "品牌": "",
        "型号": raw,
        "器件类型": component_type,
        "特殊用途": special_use,
        "尺寸（inch）": size,
        "材质（介质）": "",
        "容值": value,
        "容值单位": unit,
        "容值_pf": None,
        "容值误差": freq_tol,
        "耐压（V）": voltage,
        "频率": value if component_type == "晶振" else "",
        "输出频率": value if component_type == "振荡器" else "",
        "频率单位": unit,
        "电源电压": voltage,
        "输出类型": output_type,
        "负载电容（pF）": load_cap,
        "工作温度": work_temp,
        "频率温度特性（ppm）": temp_characteristic,
        "25℃老化（ppm）": aging,
        "拐点温度": turnover_temp,
        "抛物线系数（ppm/℃²）": parabolic_coef,
        "泛音阶次": overtone_order,
        "_body_size": body_size,
        "_core_param_count": param_count,
        "_param_count": param_count,
    }
    return spec


def parse_impedance_value_unit(text):
    normalized = clean_text(text).replace(" ", "")
    if normalized == "":
        return "", ""
    match = re.fullmatch(r"(\d+(?:\.\d+)?)(MΩ|KΩ|Ω|mΩ|MOHM|KOHM|OHM)", normalized, flags=re.I)
    if not match:
        return "", ""
    return clean_text(match.group(1)), normalize_library_value_unit(match.group(2))


def extract_electrolytic_dimensions_from_text(text):
    upper = clean_text(text).upper().replace("Φ", "").replace("Ø", "")
    if upper == "":
        return "", "", ""
    match = ELECTROLYTIC_SIZE_PATTERN.search(upper)
    if not match:
        return "", "", ""
    diameter = normalize_dimension_mm_value(match.group(1))
    height = normalize_dimension_mm_value(match.group(2))
    body_text = " x ".join(part for part in [diameter, height] if part != "")
    return diameter, height, body_text


def build_series_description_fallback(component_type, brand="", series="", special_use=""):
    component_type = normalize_component_type(component_type)
    series_text = clean_text(series)
    if series_text == "":
        return ""
    special_text = normalize_special_use(special_use)
    brand_text = clean_brand(brand)
    prefix = f"{brand_text} " if brand_text != "" else ""
    if component_type == "铝电解电容":
        return f"{prefix}{series_text} 铝电解电容系列".strip()
    if component_type == "薄膜电容":
        return f"{prefix}{series_text} 薄膜电容系列".strip()
    if component_type == "钽电容":
        return f"{prefix}{series_text} 钽电容系列".strip()
    if component_type == "引线型陶瓷电容":
        return f"{prefix}{series_text} 引线型陶瓷电容系列".strip()
    if component_type in RESISTOR_COMPONENT_TYPES:
        if special_text != "":
            return f"{special_text} {component_type}系列".strip()
        return f"{component_type}系列".strip()
    if component_type == "热敏电阻":
        if special_text != "":
            return f"{prefix}{series_text} {special_text} 热敏电阻系列".strip()
        return f"{prefix}{series_text} 热敏电阻系列".strip()
    if component_type in VARISTOR_COMPONENT_TYPES:
        if special_text != "":
            return f"{prefix}{series_text} {special_text} 压敏电阻系列".strip()
        return f"{prefix}{series_text} 压敏电阻系列".strip()
    if component_type in INDUCTOR_COMPONENT_TYPES:
        suffix = "磁珠系列" if component_type == "磁珠" else f"{component_type}系列"
        return f"{prefix}{series_text} {suffix}".strip()
    if component_type in TIMING_COMPONENT_TYPES:
        return f"{prefix}{series_text} {component_type}系列".strip()
    if special_text != "":
        return f"{series_text} / {special_text}"
    return f"{prefix}{series_text} 系列".strip()


