def joyin_ntc_suffix_from_model(model):
    match = JOYIN_NTC_MODEL_PATTERN.match(clean_model(model))
    return match.group(1).upper() if match else ""


def joyin_ntc_series_profile_from_model(model):
    suffix = joyin_ntc_suffix_from_model(model)
    profile = JOYIN_NTC_SERIES_PROFILES.get(suffix, {})
    if not profile:
        return {}
    return {
        "系列": profile["series"],
        "系列说明": profile["description"],
        "特殊用途": profile["special_use"],
        "工作温度": profile["temperature"],
        "_joyin_ntc_class": profile["class"],
    }


def parse_joyin_ntc_common(model, brand=""):
    compact = clean_model(model)
    match = JOYIN_NTC_MODEL_DETAIL_PATTERN.fullmatch(compact)
    if match is None:
        return None
    profile = joyin_ntc_series_profile_from_model(compact)
    size_inch, body_size, length_mm, width_mm, height_mm = JOYIN_NTC_SIZE_PROFILES.get(
        match.group("size").upper(),
        ("", "", "", "", ""),
    )
    resistance_ohm = parse_resistor_value_code(match.group("resistance"))
    if resistance_ohm is None:
        return None
    resistance_value, resistance_unit = ohm_to_library_value_unit(resistance_ohm)
    tolerance = JOYIN_NTC_RESISTANCE_TOLERANCE_CODES.get(
        match.group("resistance_tol").upper(),
        "",
    )
    b_value = JOYIN_NTC_UNAMBIGUOUS_B_VALUES.get(match.group("b_code"), "")
    b_tolerance = JOYIN_NTC_B_TOLERANCE_CODES.get(match.group("b_tol").upper(), "")
    b_condition = JOYIN_NTC_B_CONDITIONS.get(match.group("b_condition").upper(), "")
    return {
        "品牌": clean_brand(brand) or "JOYIN(久尹)",
        "型号": compact,
        "器件类型": "热敏电阻",
        "系列": clean_text(profile.get("系列", "")) or "JSN",
        "系列说明": clean_text(profile.get("系列说明", "")) or "久尹 JSN 贴片 NTC 热敏电阻系列",
        "特殊用途": clean_text(profile.get("特殊用途", "")) or "测温 | 贴片 | NTC",
        "工作温度": clean_text(profile.get("工作温度", "")),
        "安装方式": "贴片",
        "封装代码": size_inch,
        "尺寸（inch）": size_inch,
        "尺寸（mm）": "×".join(part for part in (length_mm, width_mm, height_mm) if part != ""),
        "长度（mm）": length_mm,
        "宽度（mm）": width_mm,
        "高度（mm）": height_mm,
        "阻值@25C": resistance_value,
        "阻值单位": resistance_unit,
        "阻值误差": tolerance,
        "容值": resistance_value,
        "容值单位": resistance_unit,
        "容值误差": tolerance,
        "B值": b_value,
        "B值误差": b_tolerance,
        "B值条件": b_condition,
        "规格摘要": " ".join(
            part
            for part in [
                combine_value_and_unit(resistance_value, resistance_unit, separator=""),
                clean_tol_for_display(tolerance),
                (
                    f"B{b_condition}={b_value}K {clean_tol_for_display(b_tolerance)}"
                    if b_value and b_condition
                    else ""
                ),
                body_size,
                f"({size_inch})" if size_inch else "",
            ]
            if clean_text(part) != ""
        ),
        "_resistance_ohm": resistance_ohm,
        "_model_rule_authority": "joyin_jsn_ntc_model",
        "_param_count": sum(
            [
                1 if size_inch else 0,
                1 if resistance_ohm is not None else 0,
                1 if tolerance else 0,
                1 if b_value else 0,
                1 if b_tolerance else 0,
            ]
        ),
    }


def thermistor_b_tolerance_from_record(record):
    if not hasattr(record, "get"):
        return ""
    explicit = clean_tol_for_match(record.get("B值误差", ""))
    if explicit != "":
        return explicit

    model = clean_model(record.get("型号", ""))
    joyin_match = JOYIN_NTC_MODEL_DETAIL_PATTERN.fullmatch(model)
    if joyin_match is not None:
        return JOYIN_NTC_B_TOLERANCE_CODES.get(joyin_match.group("b_tol").upper(), "")

    context = " ".join(
        clean_text(record.get(col, ""))
        for col in ("规格摘要", "备注1", "备注2", "备注3")
    )
    context_match = re.search(
        r"B\s*(?:25\s*/\s*(?:50|85|100))?\s*=\s*\d+(?:\.\d+)?\s*K?\s*[±+/-]*\s*(\d+(?:\.\d+)?)\s*%",
        context,
        flags=re.I,
    )
    if context_match is not None:
        return clean_tol_for_match(context_match.group(1))

    for prefix, tolerance in MURATA_NTC_B_TOLERANCE_BY_PREFIX.items():
        if model.startswith(prefix):
            return tolerance
    return ""


def find_thermistor_max_power_in_text(text):
    raw = clean_text(text)
    if raw == "":
        return ""
    normalized = raw.replace("毫瓦", "mW").replace("瓦", "W")
    match = re.search(
        r"(?:MAX(?:IMUM)?\s*(?:RATED\s*)?POWER|POWER\s*MAX|最大(?:耗散)?功率|额定功率)"
        r"\s*[:=：]?\s*(\d+(?:\.\d+)?)\s*(mW|W)\b",
        normalized,
        flags=re.I,
    )
    if match is None:
        return ""
    return format_power_display(f"{match.group(1)}{match.group(2)}")


JOYIN_NTC_MAX_POWER_BY_SIZE = {
    "0201": "100mW",
    "0402": "170mW",
    "0603": "210mW",
}


def joyin_ntc_max_power_from_model(model):
    match = JOYIN_NTC_MODEL_DETAIL_PATTERN.fullmatch(clean_model(model))
    if match is None:
        return ""
    size_inch = JOYIN_NTC_SIZE_PROFILES.get(match.group("size").upper(), ("", "", "", "", ""))[0]
    return JOYIN_NTC_MAX_POWER_BY_SIZE.get(size_inch, "")


def thermistor_max_power_text_from_record(record):
    if not hasattr(record, "get"):
        return ""
    for key in ("最大功率", "额定功率"):
        power_text = format_power_display(record.get(key, ""))
        if parse_power_to_watts(power_text) is not None:
            return power_text
    context = " ".join(
        clean_text(record.get(col, ""))
        for col in ("规格摘要", "备注1", "备注2", "备注3")
    )
    context_power = find_thermistor_max_power_in_text(context)
    if context_power != "":
        return context_power
    if clean_text(record.get("_power_source", "")) == "thermistor_max_power":
        power_text = format_power_display(record.get("功率", "") or record.get("_power", ""))
        if parse_power_to_watts(power_text) is not None:
            return power_text
    return joyin_ntc_max_power_from_model(record.get("型号", ""))


def joyin_ntc_target_class_from_spec(spec):
    if not isinstance(spec, dict):
        return ""
    model = clean_model(spec.get("型号", ""))
    series = clean_text(spec.get("系列", "")).upper()
    combined = " ".join(
        clean_text(spec.get(key, ""))
        for key in ("系列说明", "特殊用途", "规格摘要", "备注1", "备注2", "备注3")
    ).upper()
    if model.startswith("NCP") or series.startswith("NCP"):
        return "standard"
    if "AUTOMOTIVE" in combined or "AEC" in combined or "车规" in combined:
        return "automotive"
    return ""


def joyin_ntc_series_rank(row, spec):
    profile = joyin_ntc_series_profile_from_model(row.get("型号", "") if hasattr(row, "get") else "")
    if not profile:
        return 0
    cls = clean_text(profile.get("_joyin_ntc_class", ""))
    target_class = joyin_ntc_target_class_from_spec(spec)
    if target_class == "standard":
        return {"standard": 0, "standard_high_temp": 1, "automotive": 4, "automotive_high_temp": 5}.get(cls, 9)
    if target_class == "automotive":
        return {"automotive": 0, "automotive_high_temp": 1, "standard_high_temp": 4, "standard": 5}.get(cls, 9)
    return {"standard": 0, "standard_high_temp": 1, "automotive": 2, "automotive_high_temp": 3}.get(cls, 9)


def joyin_ntc_series_matches_target(row, spec):
    target_class = joyin_ntc_target_class_from_spec(spec)
    if target_class == "":
        return True
    profile = joyin_ntc_series_profile_from_model(row.get("型号", "") if hasattr(row, "get") else "")
    if not profile:
        return True
    cls = clean_text(profile.get("_joyin_ntc_class", ""))
    if target_class == "standard":
        return cls == "standard"
    if target_class == "automotive":
        return cls == "automotive"
    return True

