def brand_alias_matches(brand, aliases):
    brand_text = clean_brand(brand).upper()
    if brand_text == "":
        return False
    for alias in aliases:
        alias_text = clean_text(alias).upper()
        if alias_text != "" and alias_text in brand_text:
            return True
    return False


def empty_bom_preferred_brand_slots(limit=BOM_PREFERRED_BRAND_SLOTS):
    slots = {}
    for idx in range(1, limit + 1):
        slots[f"品牌{idx}"] = ""
        slots[f"型号{idx}"] = ""
    return slots


def bom_slot_name(base, idx):
    base = clean_text(base)
    return base if int(idx or 1) <= 1 else f"{base}{int(idx)}"


def bom_own_brand_internal_column(prefix, idx):
    return bom_slot_name(prefix, idx)


def empty_bom_own_brand_export_slots(limit=BOM_OWN_BRAND_EXPORT_MAX_SLOTS):
    slots = {}
    for idx in range(1, int(limit or 0) + 1):
        for prefix in BOM_OWN_BRAND_EXPORT_INTERNAL_PREFIXES:
            slots[bom_own_brand_internal_column(prefix, idx)] = ""
    return slots


def bom_own_brand_groups_for_component(component_type):
    ctype = normalize_component_type(component_type)
    if ctype in RESISTOR_COMPONENT_TYPES:
        return BOM_OWN_BRAND_RESISTOR_ALIAS_GROUPS
    if ctype in CAPACITOR_COMPONENT_TYPES or ctype == "MLCC":
        return BOM_OWN_BRAND_CAPACITOR_ALIAS_GROUPS
    return ()


def normalize_bom_export_settings(export_settings=None):
    settings = export_settings if isinstance(export_settings, dict) else {}
    mode = clean_text(settings.get("mode", BOM_EXPORT_MODE_AUTO))
    if mode not in {BOM_EXPORT_MODE_AUTO, BOM_EXPORT_MODE_CUSTOM}:
        mode = BOM_EXPORT_MODE_AUTO
    brands = []
    seen = set()
    for value in settings.get("brands", []) or []:
        brand = clean_brand(value)
        key = brand.upper()
        if brand == "" or key in seen:
            continue
        seen.add(key)
        brands.append(brand)
        if len(brands) >= BOM_EXPORT_BRAND_MAX_SELECTIONS:
            break
    return {"mode": mode, "brands": brands}


def bom_output_selection_ready(export_mode, selected_brands=None):
    mode = clean_text(export_mode)
    if mode == BOM_EXPORT_MODE_AUTO:
        return True
    if mode == BOM_EXPORT_MODE_CUSTOM:
        return bool(normalize_bom_export_settings({"mode": mode, "brands": selected_brands}).get("brands"))
    return False


def should_start_bom_matching(
    stored_signature,
    current_signature,
    export_mode,
    start_clicked=False,
    custom_start_clicked=None,
):
    current_signature = clean_text(current_signature)
    if current_signature == "":
        return False
    if clean_text(export_mode) not in {BOM_EXPORT_MODE_AUTO, BOM_EXPORT_MODE_CUSTOM}:
        return False
    if custom_start_clicked is not None:
        start_clicked = custom_start_clicked
    return bool(start_clicked)


def bom_export_brand_groups(component_type, export_settings=None):
    settings = normalize_bom_export_settings(export_settings)
    if settings["mode"] != BOM_EXPORT_MODE_CUSTOM:
        groups = tuple(bom_own_brand_groups_for_component(component_type))
        return groups or (("系统推荐", ()),)
    groups = []
    for brand in settings["brands"]:
        groups.append((brand, tuple(brand_query_aliases_for_label(brand))))
    return tuple(groups)


def bom_export_brand_options():
    options = []
    seen = set()
    preferred = [
        "信昌PDC",
        "华新科Walsin",
        "芯声微HRE",
        "厚声UNI-ROYAL",
        "FOJAN(富捷)",
    ]
    for canonical in preferred + [item[0] for item in BRAND_QUERY_ALIAS_GROUPS]:
        brand = clean_brand(canonical)
        key = brand.upper()
        if brand == "" or key in seen:
            continue
        seen.add(key)
        options.append(brand)
    return options


def infer_bom_own_brand_component_type(spec=None, frame=None):
    if spec is not None:
        ctype = infer_spec_component_type(spec)
        if clean_text(ctype) != "":
            return ctype
        ctype = clean_text(spec.get("器件类型", "")) if isinstance(spec, dict) else ""
        if ctype != "":
            return ctype
    if isinstance(frame, pd.DataFrame) and not frame.empty and "器件类型" in frame.columns:
        for value in frame["器件类型"].astype(str).tolist():
            ctype = normalize_component_type(value)
            if ctype != "":
                return ctype
    return ""


def prepare_bom_own_brand_candidate_frame(frame, component_type, brand_groups=None):
    if frame is None or frame.empty:
        return pd.DataFrame()
    work = frame.copy()
    groups = list(brand_groups or [])
    if groups and "品牌" in work.columns and not any(not aliases for _, aliases in groups):
        brand_mask = work["品牌"].astype(str).map(
            lambda brand: any(brand_alias_matches(brand, aliases) for _, aliases in groups)
        )
        work = work[brand_mask].copy()
        if work.empty:
            return work
    ctype = normalize_component_type(component_type)
    if ctype in RESISTOR_COMPONENT_TYPES:
        work = normalize_fojan_resistor_series_display_fields(work)
        work = enrich_resistor_pricing_columns(work)
    work = enrich_component_cost_columns(work)
    return work


def bom_spec_has_special_requirement(spec):
    if not isinstance(spec, dict):
        return False
    values = [
        spec.get("特殊用途", ""),
        spec.get("系列说明", ""),
        spec.get("规格摘要", ""),
    ]
    for value in values:
        text = clean_text(value)
        if text == "":
            continue
        upper = text.upper()
        if any(keyword.upper() in upper for keyword in BOM_RESISTOR_SPECIAL_SERIES_KEYWORDS):
            return True
    return False


def bom_resistor_general_series_priority(row):
    series = clean_text(row.get("系列", "")).upper()
    desc = clean_text(row.get("系列说明", ""))
    special = clean_text(row.get("特殊用途", ""))
    model = clean_text(row.get("型号", "")).upper()
    combined = " ".join([series, desc, special, model]).upper()
    if series in {clean_text(code).upper() for code in BOM_RESISTOR_GENERAL_SERIES_CODES}:
        return 0
    if any(keyword.upper() in combined for keyword in BOM_RESISTOR_GENERAL_SERIES_KEYWORDS):
        return 0
    if special == "" and not any(keyword.upper() in combined for keyword in BOM_RESISTOR_SPECIAL_SERIES_KEYWORDS):
        return 1
    return 2


def sort_bom_own_brand_candidates(candidates, component_type, spec=None):
    if not candidates:
        return []
    ctype = normalize_component_type(component_type)
    if ctype not in RESISTOR_COMPONENT_TYPES or bom_spec_has_special_requirement(spec):
        return sorted(candidates, key=lambda item: item.get("_order", 0))
    return sorted(
        candidates,
        key=lambda item: (
            bom_resistor_general_series_priority(item.get("_row", {})),
            item.get("_order", 0),
        ),
    )


def match_bom_preferred_brand_label(brand):
    for label, aliases in BOM_PREFERRED_BRAND_ALIAS_GROUPS:
        if brand_alias_matches(brand, aliases):
            return label
    return ""


def normalize_brand_model_pair_set(pairs):
    normalized = set()
    for item in pairs or []:
        if not isinstance(item, (list, tuple)) or len(item) < 2:
            continue
        brand = clean_brand(item[0])
        model = clean_text(item[1])
        if brand != "" and model != "":
            normalized.add((brand, model))
        label = match_bom_preferred_brand_label(brand)
        if label != "" and model != "":
            normalized.add((label, model))
    return normalized


def build_bom_preferred_brand_slots(frame, limit=BOM_PREFERRED_BRAND_SLOTS, exclude_pairs=None):
    slots = empty_bom_preferred_brand_slots(limit=limit)
    if frame is None or frame.empty:
        return slots
    if "品牌" not in frame.columns or "型号" not in frame.columns:
        return slots
    excluded = normalize_brand_model_pair_set(exclude_pairs)
    items = []
    seen = set()
    for brand_value, model_value in zip(frame["品牌"].astype(str).tolist(), frame["型号"].astype(str).tolist()):
        label = match_bom_preferred_brand_label(brand_value)
        model = clean_text(model_value)
        if label == "" or model == "":
            continue
        key = (label, model)
        if key in excluded or key in seen:
            continue
        seen.add(key)
        items.append(key)
        if len(items) >= limit:
            break
    for idx, (brand, model) in enumerate(items, start=1):
        slots[f"品牌{idx}"] = brand
        slots[f"型号{idx}"] = model
    return slots


def build_bom_own_brand_export_slots(frame, spec=None, limit=BOM_OWN_BRAND_EXPORT_MAX_SLOTS, export_settings=None):
    slots = empty_bom_own_brand_export_slots(limit=limit)
    if frame is None or frame.empty:
        return slots
    if "品牌" not in frame.columns or "型号" not in frame.columns:
        return slots

    component_type = infer_bom_own_brand_component_type(spec=spec, frame=frame)
    brand_groups = bom_export_brand_groups(component_type, export_settings=export_settings)
    if not brand_groups:
        return slots

    work = prepare_bom_own_brand_candidate_frame(frame, component_type, brand_groups=brand_groups)
    if work.empty:
        return slots

    selected = []
    seen = set()
    for label, aliases in brand_groups:
        brand_candidates = []
        for order, (_, row) in enumerate(work.iterrows()):
            if aliases and not brand_alias_matches(row.get("品牌", ""), aliases):
                continue
            model = clean_text(row.get("型号", ""))
            if model == "":
                continue
            output_brand = label if aliases else clean_brand(row.get("品牌", ""))
            key = (output_brand, model)
            if key in seen:
                continue
            brand_candidates.append(
                {
                    "_order": order,
                    "_row": row,
                    "key": key,
                    "品牌": output_brand,
                    "型号": model,
                    "成本": clean_text(row.get("成本", "")),
                    "更新时间": clean_text(row.get("更新时间", "")),
                    "MOQ": clean_text(row.get("MOQ", "")),
                    "L&T": clean_text(row.get("L&T", "")),
                }
            )
        ordered_candidates = sort_bom_own_brand_candidates(brand_candidates, component_type, spec=spec)
        match_level_rank = {"完全匹配": 0, "高代低": 1, "可直接替代": 1, "部分参数匹配": 2}
        for selection_order, item in enumerate(ordered_candidates):
            item["_selection_order"] = selection_order
        ordered_candidates = sorted(
            ordered_candidates,
            key=lambda item: (
                match_level_rank.get(clean_text(item.get("_row", {}).get("推荐等级", "")), 9),
                0 if clean_text(item.get("成本", "")) != "" else 1,
                int(item.get("_selection_order", 0) or 0),
            ),
        )
        for item in ordered_candidates:
            if item["key"] in seen:
                continue
            seen.add(item["key"])
            selected.append(item)
            break
        if len(selected) >= int(limit or 0):
            break

    for idx, item in enumerate(selected[: int(limit or 0)], start=1):
        candidate_row = item.get("_row")
        candidate_reason = first_clean_row_value(
            candidate_row,
            ["匹配说明", "推荐理由", "差异说明", "解析说明"],
        )
        confirmation_detail = ""
        if candidate_row is not None and spec is not None:
            try:
                _, classified_reason = classify_recommendation_status(candidate_row, spec)
                candidate_reason = clean_text(classified_reason) or candidate_reason
            except Exception:
                pass
            try:
                confirmation_detail = build_match_confirmation_detail(candidate_row, spec)
            except Exception:
                confirmation_detail = ""
        candidate_remark = merge_match_confirmation_into_remark1(
            candidate_row.get("备注1", "") if candidate_row is not None else "",
            confirmation_detail,
        )
        slots[bom_own_brand_internal_column("自有品牌", idx)] = item.get("品牌", "")
        slots[bom_own_brand_internal_column("自有型号", idx)] = item.get("型号", "")
        slots[bom_own_brand_internal_column("自有成本", idx)] = item.get("成本", "")
        slots[bom_own_brand_internal_column("自有更新时间", idx)] = item.get("更新时间", "")
        slots[bom_own_brand_internal_column("自有MOQ", idx)] = item.get("MOQ", "")
        slots[bom_own_brand_internal_column("自有L&T", idx)] = item.get("L&T", "")
        slots[bom_own_brand_internal_column("自有匹配说明", idx)] = candidate_reason
        slots[bom_own_brand_internal_column("自有匹配备注", idx)] = candidate_remark
    return slots


def bom_export_slots_have_model(export_slots, limit=BOM_OWN_BRAND_EXPORT_MAX_SLOTS):
    slots = export_slots if isinstance(export_slots, dict) else {}
    return any(
        clean_text(slots.get(bom_own_brand_internal_column("自有型号", idx), "")) != ""
        for idx in range(1, int(limit or 0) + 1)
    )


def bom_output_no_match_reason(export_settings=None):
    settings = normalize_bom_export_settings(export_settings)
    if settings["mode"] == BOM_EXPORT_MODE_CUSTOM:
        brand_text = "、".join(settings["brands"]) or "指定品牌"
        return f"指定品牌（{brand_text}）未找到符合规格的型号；可能原厂无对应型号或当前数据库资料不足"
    return "当前输出品牌范围内未找到符合规格的型号；可能品牌无对应型号或当前数据库资料不足"


def reconcile_bom_output_status(result_row, export_slots, export_settings=None):
    if not isinstance(result_row, dict):
        return result_row
    status = clean_text(result_row.get("状态", ""))
    if status in {"解析失败", "已跳过", "无法识别", "规格不足"}:
        return result_row

    if bom_export_slots_have_model(export_slots):
        if status == "无匹配":
            result_row["状态"] = "可推荐"
            result_row["推荐理由"] = "已匹配原 BOM 型号及当前成本资料"
        return result_row

    settings = normalize_bom_export_settings(export_settings)
    if settings["mode"] != BOM_EXPORT_MODE_CUSTOM and status == "无匹配":
        return result_row

    reason = bom_output_no_match_reason(settings)
    result_row["状态"] = "无匹配"
    result_row["匹配数量"] = 0
    result_row["首选推荐等级"] = ""
    result_row["推荐品牌"] = ""
    result_row["推荐型号"] = ""
    result_row["推荐理由"] = reason
    result_row["差异说明"] = reason
    result_row["前5个其他品牌型号"] = ""
    result_row["备注1"] = ""
    result_row["备注2"] = ""
    result_row["备注3"] = ""
    for idx in range(1, BOM_PREFERRED_BRAND_SLOTS + 1):
        result_row[f"品牌{idx}"] = ""
        result_row[f"型号{idx}"] = ""
    return result_row


def build_bom_export_candidate_frame(matched, query_df=None, spec=None, mode="", exact_model=""):
    frames = []
    exact_model = clean_model(exact_model) or (
        clean_model((spec or {}).get("型号", "")) if isinstance(spec, dict) else ""
    )
    if clean_text(mode) == "料号" or exact_model:
        exact_rows = pd.DataFrame()
        if exact_model and isinstance(query_df, pd.DataFrame) and not query_df.empty and "型号" in query_df.columns:
            exact_rows = query_df[query_df["型号"].astype(str).map(clean_model).eq(exact_model)].copy()
        if exact_model and exact_rows.empty:
            exact_map = load_component_rows_by_exact_models_from_search_sidecar([exact_model])
            exact_rows = exact_map.get(exact_model, pd.DataFrame()) if isinstance(exact_map, dict) else pd.DataFrame()
        if not exact_rows.empty:
            if "推荐等级" not in exact_rows.columns:
                exact_rows["推荐等级"] = "完全匹配"
            else:
                exact_rows["推荐等级"] = exact_rows["推荐等级"].where(
                    exact_rows["推荐等级"].astype(str).map(clean_text).ne(""),
                    "完全匹配",
                )
            frames.append(exact_rows)
    if isinstance(matched, pd.DataFrame) and not matched.empty:
        frames.append(matched)
    if not frames:
        return pd.DataFrame()
    return concat_component_frames(frames)


def choose_bom_display_match(frame, spec=None):
    if frame is None or frame.empty:
        return None
    if spec is not None:
        recommendation = build_procurement_recommendation(frame, spec)
        row = recommendation.get("row")
        if row is not None:
            return row
    if "品牌" not in frame.columns:
        return None
    for _, row in frame.iterrows():
        if match_bom_preferred_brand_label(row.get("品牌", "")) != "":
            return row
    return None


def collect_brand_models_in_frame(frame, aliases):
    if frame is None or frame.empty:
        return ""
    if "品牌" not in frame.columns or "型号" not in frame.columns:
        return ""
    models = []
    seen = set()
    for brand_value, model_value in zip(frame["品牌"].astype(str).tolist(), frame["型号"].astype(str).tolist()):
        if not brand_alias_matches(brand_value, aliases):
            continue
        model = clean_text(model_value)
        if model == "" or model in seen:
            continue
        seen.add(model)
        models.append(model)
    return " | ".join(models)


def empty_mlcc_reference_result():
    return {key: "" for key in MLCC_REFERENCE_ALIAS_MAP}


def lookup_brand_models_for_spec_map(df, spec):
    refs = empty_mlcc_reference_result()
    if df is None or df.empty or spec is None:
        return refs
    if infer_spec_component_type(spec) != "MLCC":
        return refs

    try:
        cache_key = (get_query_cache_signature(), serialize_spec_for_cache(spec))
    except Exception:
        cache_key = None
    if cache_key is not None:
        cached = MLCC_REFERENCE_LOOKUP_CACHE.get(cache_key)
        if cached is not None:
            return cached.copy()

    base = scope_search_dataframe(df, spec)
    if base.empty or "品牌" not in base.columns or "型号" not in base.columns:
        return refs

    spec_tol = clean_tol_for_match(spec.get("容值误差", ""))
    spec_volt = clean_voltage(spec.get("耐压（V）", ""))
    if spec_tol != "":
        base = base[tolerance_allows_series(base, spec_tol)]
        if base.empty:
            return refs
    if spec_volt != "":
        try:
            spec_volt_num = float(spec_volt)
            base = base[base["_volt_num"].notna() & base["_volt_num"].ge(spec_volt_num)]
        except Exception:
            base = base[base["_volt"].eq(spec_volt)]
        if base.empty:
            return refs

    base = apply_match_levels_and_sort(base, spec)
    if base.empty:
        return refs

    for field_name, aliases in MLCC_REFERENCE_ALIAS_MAP.items():
        refs[field_name] = collect_brand_models_in_frame(base, aliases)

    if cache_key is not None:
        MLCC_REFERENCE_LOOKUP_CACHE[cache_key] = refs.copy()
    return refs


def lookup_brand_models_for_spec(df, spec, aliases):
    refs = lookup_brand_models_for_spec_map(df, spec)
    for field_name, field_aliases in MLCC_REFERENCE_ALIAS_MAP.items():
        if tuple(field_aliases) == tuple(aliases):
            return refs.get(field_name, "")
    return ""


def format_other_brand_models(frame, limit=None, exclude_aliases=None, exclude_pairs=None):
    if frame is None or frame.empty:
        return ""
    if "品牌" not in frame.columns or "型号" not in frame.columns:
        return ""
    alias_filter = tuple(exclude_aliases or MLCC_REFERENCE_EXCLUDE_ALIASES)
    excluded_pairs = normalize_brand_model_pair_set(exclude_pairs)
    items = []
    seen = set()
    for brand_value, model_value in zip(frame["品牌"].astype(str).tolist(), frame["型号"].astype(str).tolist()):
        brand = clean_brand(brand_value)
        if alias_filter and brand_alias_matches(brand, alias_filter):
            continue
        model = clean_text(model_value)
        if model == "":
            continue
        key = (brand, model)
        if key in excluded_pairs:
            continue
        if key in seen:
            continue
        seen.add(key)
        items.append(f"{brand}:{model}" if brand != "" else model)
        if limit is not None and len(items) >= limit:
            break
    return " | ".join(items)


def format_bom_sales_brand_model(brand, model):
    model_text = clean_text(model)
    if model_text == "":
        return ""
    brand_text = display_brand_label(clean_brand(brand))
    if brand_text == "":
        return model_text
    return f"{brand_text} {model_text}"


def first_clean_row_value(row, columns):
    for col in columns:
        value = clean_text(row.get(col, "")) if row is not None else ""
        if value != "":
            return value
    return ""


def collect_bom_sales_alternative_models(row, limit=3):
    primary_key = (
        clean_brand(row.get("推荐品牌", "")) if row is not None else "",
        clean_text(row.get("推荐型号", "")) if row is not None else "",
    )
    items = []
    seen = set()

    def append_item(brand, model):
        brand_key = clean_brand(brand)
        model_key = clean_text(model)
        if model_key == "":
            return
        key = (brand_key, model_key)
        if key == primary_key or key in seen:
            return
        display_text = format_bom_sales_brand_model(brand_key, model_key)
        if display_text == "":
            return
        seen.add(key)
        items.append(display_text)

    for idx in range(1, BOM_PREFERRED_BRAND_SLOTS + 1):
        append_item(row.get(f"品牌{idx}", ""), row.get(f"型号{idx}", ""))
        if len(items) >= limit:
            return " | ".join(items[:limit])

    for source_col in ["其他品牌型号", "前5个其他品牌型号"]:
        for brand, model in split_brand_model_list(row.get(source_col, "")):
            append_item(brand, model)
            if len(items) >= limit:
                return " | ".join(items[:limit])

    return " | ".join(items[:limit])


def build_bom_sales_decision_fields(row):
    status = clean_text(row.get("状态", "")) if row is not None else ""
    parse_status = clean_text(row.get("解析状态", "")) if row is not None else ""
    level = first_clean_row_value(row, ["首选推荐等级", "推荐等级"])
    primary_model = format_bom_sales_brand_model(row.get("推荐品牌", ""), row.get("推荐型号", "")) if row is not None else ""
    reason = first_clean_row_value(row, ["推荐理由", "失败原因", "差异说明", "解析说明"])
    alternatives = collect_bom_sales_alternative_models(row)
    can_reply = "否"

    if status == "可推荐":
        if primary_model == "":
            conclusion = "有匹配结果，但未生成首选型号"
            risk = reason or "缺少推荐品牌或型号，不能直接回复客户"
        elif level == "完全匹配":
            can_reply = "是"
            conclusion = "可直接回复客户，优先推荐首选型号"
            risk = reason or "关键规格完全一致"
        elif level in {"高代低", "可直接替代"}:
            can_reply = "是"
            conclusion = "可回复客户，候选规格不低于需求"
            risk = reason or "候选规格不低于需求，仍需确认客户是否接受替代"
        else:
            can_reply = "是"
            conclusion = "可回复客户，建议保留规格确认说明"
            risk = reason or "已按当前识别参数匹配"
    elif status == "需确认":
        conclusion = "先内部确认后再回复客户"
        risk = reason or "存在缺失参数或未确认替代关系"
    elif status == "参数冲突":
        conclusion = "不要直接推荐"
        risk = reason or "候选型号存在关键参数冲突"
    elif status == "无匹配":
        conclusion = "暂无可推荐型号"
        risk = reason or "当前库内没有符合规格的品牌型号"
    elif status == "解析失败" or parse_status == "解析失败":
        conclusion = "需补充或修正BOM信息"
        risk = reason or "输入信息不足或无法解析"
    elif primary_model != "":
        conclusion = "需人工确认后再回复客户"
        risk = reason or "系统未给出明确可推荐状态"
    else:
        conclusion = "暂无可推荐型号"
        risk = reason or "未生成匹配结果"

    return {
        "可直接回复客户": can_reply,
        "销售结论": conclusion,
        "客户回复型号": primary_model,
        "备选型号": alternatives,
        "风险提示": risk,
    }


def ensure_bom_sales_decision_columns(df):
    if df is None:
        return pd.DataFrame()
    out = df.copy()
    for col in BOM_SALES_DECISION_COLUMNS:
        if col not in out.columns:
            out[col] = ""
    if out.empty:
        return out
    decisions = out.apply(build_bom_sales_decision_fields, axis=1)
    for col in BOM_SALES_DECISION_COLUMNS:
        out[col] = decisions.apply(lambda value: clean_text(value.get(col, "")) if isinstance(value, dict) else "")
    return out


def resolve_mlcc_brand_references(df, spec, matched=None, current_model=""):
    refs = empty_mlcc_reference_result()
    if infer_spec_component_type(spec) != "MLCC":
        return refs

    source_brand = clean_brand(spec.get("品牌", "")) if spec is not None else ""
    source_model = clean_text(current_model) or (clean_text(spec.get("型号", "")) if spec is not None else "")
    fallback_refs = None

    for field_name, aliases in MLCC_REFERENCE_ALIAS_MAP.items():
        value = ""
        if matched is not None and not matched.empty:
            value = collect_brand_models_in_frame(matched, aliases)
        if value == "" and df is not None and not df.empty:
            if fallback_refs is None:
                fallback_refs = lookup_brand_models_for_spec_map(df, spec)
            value = fallback_refs.get(field_name, "")
        if value == "" and brand_alias_matches(source_brand, aliases) and source_model != "":
            value = source_model
        refs[field_name] = value

    return refs


def move_columns_after(df, anchor_col, move_cols):
    if df is None or df.empty:
        return df
    existing_moves = [col for col in move_cols if col in df.columns]
    if not existing_moves or anchor_col not in df.columns:
        return df
    columns = [col for col in df.columns if col not in existing_moves]
    insert_at = columns.index(anchor_col) + 1
    for offset, col in enumerate(existing_moves):
        columns.insert(insert_at + offset, col)
    return df[columns]


def move_reference_model_columns_after_rank(df):
    if df is None or df.empty:
        return df
    move_cols = [col for col in ["信昌料号", "华科料号"] if col in df.columns]
    if not move_cols:
        return df
    for anchor in ["首选推荐等级", "推荐等级"]:
        if anchor in df.columns:
            return move_columns_after(df, anchor, move_cols)
    return df


def build_bom_component_distribution_text(result_df):
    if result_df is None or result_df.empty or "器件类型" not in result_df.columns:
        return ""

    type_series = result_df["器件类型"].apply(clean_text)
    type_series = type_series[type_series != ""]
    if type_series.empty:
        return ""

    counts = type_series.value_counts()
    parts = [f"{name} {int(count)} 行" for name, count in counts.items()]
    return "器件类型分布：" + " | ".join(parts)


def compact_bom_detail_text(value):
    text = clean_text(value)
    if text == "":
        return ""
    lines = [clean_text(line) for line in re.split(r"[\r\n]+", text) if clean_text(line) != ""]
    if not lines:
        return text

    def compact_detail_token(token):
        token = clean_text(token)
        if token == "":
            return ""
        token = token.replace("：", ":")
        if ":" not in token:
            return token
        label, raw = token.split(":", 1)
        label = clean_text(label)
        raw = clean_text(raw)
        if raw == "":
            return ""
        raw = raw.replace(" ", "")
        if label in {"容值", "阻值", "压敏电压", "耐压", "功率"}:
            return raw
        if label in {"尺寸", "介质", "材质", "安规", "规格", "脚距"}:
            return raw
        return raw if raw != "" else token

    compacted = [compact_detail_token(line) for line in lines]
    compacted = [item for item in compacted if item != ""]
    if not compacted:
        return text
    joined = " | ".join(compacted)
    joined = re.sub(r"\s+", " ", joined).strip()
    return joined


def build_bom_parse_summary(row):
    status = clean_text(row.get("解析状态", ""))
    source = clean_text(row.get("解析来源", ""))
    failure_reason = clean_text(row.get("失败原因", ""))
    difference_note = clean_text(row.get("差异说明", ""))
    parts = []
    if status != "":
        parts.append(f"状态: {status}")
    if source != "":
        parts.append(f"来源: {source}")
    if failure_reason != "":
        parts.append(f"原因: {failure_reason}")
    if difference_note != "":
        parts.append(f"说明: {difference_note}")
    return " | ".join(parts)


def build_bom_display_df(result_df):
    if result_df is None or result_df.empty:
        return pd.DataFrame()

    display_df = result_df.copy()
    for col in BOM_PREFERRED_SLOT_COLUMNS:
        if col not in display_df.columns:
            display_df[col] = ""
    for source_col, display_col in BOM_PREFERRED_DISPLAY_COLUMN_MAP:
        if source_col in display_df.columns:
            display_df[display_col] = display_df[source_col].astype(str).replace("nan", "").replace("None", "").apply(clean_text)
        else:
            display_df[display_col] = ""
    if "前5个其他品牌型号" in display_df.columns and "其他品牌型号" not in display_df.columns:
        display_df["其他品牌型号"] = display_df["前5个其他品牌型号"]
    display_df["解析说明"] = display_df.apply(build_bom_parse_summary, axis=1)
    display_df = ensure_bom_sales_decision_columns(display_df)

    preferred_columns = [
        "BOM行号",
        "BOM型号",
        "BOM规格",
        "BOM品名",
        "器件类型",
        "规格参数明细",
        "BOM数量",
        "匹配参数明细",
        "首选推荐等级",
        "推荐品牌",
        "推荐型号",
        "推荐品牌1",
        "推荐型号1",
        "推荐品牌2",
        "推荐型号2",
        "推荐品牌3",
        "推荐型号3",
        "其他品牌型号",
        "状态",
        "备注1",
        "备注2",
        "备注3",
    ]
    existing_columns = [col for col in preferred_columns if col in display_df.columns]
    if not existing_columns:
        return apply_brand_display_aliases(display_df)
    return apply_brand_display_aliases(display_df[existing_columns])


def count_bom_recommendation_statuses(result_df):
    counts = {"可推荐": 0, "需确认": 0, "参数冲突": 0, "无匹配": 0, "解析失败": 0}
    if result_df is None or result_df.empty or "状态" not in result_df.columns:
        return counts
    status_series = result_df["状态"].astype(str).apply(clean_text)
    for key in counts:
        counts[key] = int(status_series.eq(key).sum())
    if "解析状态" in result_df.columns:
        parse_fail = result_df["解析状态"].astype(str).apply(clean_text).eq("解析失败")
        known_status = status_series.isin(set(counts.keys()))
        counts["解析失败"] += int((parse_fail & ~known_status).sum())
    return counts


def parse_taiyo_common(model):
    model = clean_model(model)
    # 常见太阳诱电格式示例：TMK105BJ105KV-F / JMK105BJ105KV-F
    prefixes = ["TMK", "JMK", "EMK", "LMK", "AMK"]
    prefix = next((p for p in prefixes if model.startswith(p)), None)
    if prefix is None or len(model) < 11:
        return None

    size_map = {
        **TAIYO_MLCC_SIZE_CODE_MAP,
        "1005": "0402", "1608": "0603", "2012": "0805", "3216": "1206",
        "3225": "1210", "4520": "1808", "4532": "1812", "5750": "2220"
    }
    material_map = {
        "C": "COG(NPO)", "B": "X5R", "E": "X6S", "F": "X7R", "R": "X7R"
    }
    tol_map = {"F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"}
    voltage_map = {
        "0E": "2.5", "0G": "4", "0J": "6.3", "1A": "10", "1C": "16",
        "1E": "25", "1H": "50", "2A": "100", "2D": "200", "2E": "250", "2J": "630",
        "V": "35", "KV": "10"
    }
    series_profile = taiyo_mlcc_series_profile(prefix)

    try:
        size_code = model[3:7]
        mat_code = model[7]
        cap_code = model[8:11]

        tol = ""
        volt = ""

        # 常见：...J105KV-F / ...J105KV
        rest = model[11:]
        if len(rest) >= 1 and rest[0] in tol_map:
            tol = tol_map.get(rest[0], "")
            rest2 = rest[1:]
        else:
            rest2 = rest

        if rest2.startswith("6R3"):
            volt = "6.3"
        elif rest2.startswith("KV"):
            volt = "10"
        elif len(rest2) >= 2 and rest2[:2] in voltage_map:
            volt = voltage_map.get(rest2[:2], "")
        elif len(rest2) >= 1 and rest2[:1] in voltage_map:
            volt = voltage_map.get(rest2[:1], "")

        return {
            "品牌": "太阳诱电Taiyo",
            "型号": model,
            "系列": clean_text(series_profile.get("系列", "")),
            "系列说明": clean_text(series_profile.get("系列说明", "")),
            "特殊用途": clean_text(series_profile.get("特殊用途", "")),
            "_mlcc_series_class": clean_text(series_profile.get("_mlcc_series_class", "")),
            "尺寸（inch）": size_map.get(size_code, ""),
            "材质（介质）": clean_material(material_map.get(mat_code, "")),
            "容值_pf": murata_cap_code_to_pf(cap_code),
            "容值误差": clean_tol_for_match(tol),
            "耐压（V）": clean_voltage(volt),
            "_model_rule_authority": "taiyo_old_series",
        }
    except:
        return None


def parse_taiyo_new_common(model):
    model = clean_model(model)
    prefixes = ("MAAS", "MBAS", "MCAS", "MCAST", "MLAS", "MMAS", "MSAS", "MEASL", "MEAST", "MEASJ")
    if not model.startswith(prefixes):
        return None

    size_map = TAIYO_MLCC_SIZE_CODE_MAP
    material_map = {
        "LAB": "X7R",
        "LBC": "X6S",
        "SCG": "COG(NPO)",
        "CC6": "X6S",
        "MAB": "X5R",
        "SL8": "X8L",
    }
    tol_map = {"A": "0.05PF", "B": "0.1pF", "C": "0.25pF", "D": "0.5pF", "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"}
    voltage_map = {"F": "4", "P": "6.3", "T": "10", "W": "25", "N": "16", "H": "50"}
    series_code = taiyo_mlcc_series_code_from_model(model)
    series_profile = taiyo_mlcc_series_profile(series_code)

    match = re.fullmatch(
        r"(?P<prefix>M[A-Z]{4})(?P<size>\d{2,3})(?P<mat>[A-Z0-9]{3})(?P<body>.*)",
        model,
    )
    if not match:
        return None

    body = match.group("body")
    cap_match = re.fullmatch(r"(?:(?P<cond>\d)(?P<cap>\d{3})|(?P<cap2>R\d+|\d{3,4}))(?P<tol>[BCDFGJKMZ])(?P<volt>[A-Z])(?P<rest>.*)", body)
    if not cap_match:
        return None

    cap_token = cap_match.group("cap") or cap_match.group("cap2")
    if cap_token is None:
        return None
    cap_pf = murata_cap_code_to_pf(cap_token)
    if cap_pf is None:
        return None

    size_code = match.group("size")
    size = size_map.get(size_code, "")
    if size == "" and size_code.isdigit():
        if len(size_code) == 2:
            size = {"31": "1206", "32": "1210"}.get(size_code, "")

    return {
        "品牌": "太阳诱电Taiyo",
        "型号": model,
        "系列": clean_text(series_profile.get("系列", "")),
        "系列说明": clean_text(series_profile.get("系列说明", "")),
        "特殊用途": clean_text(series_profile.get("特殊用途", "")),
        "_mlcc_series_class": clean_text(series_profile.get("_mlcc_series_class", "")),
        "尺寸（inch）": size,
        "材质（介质）": clean_material(material_map.get(match.group("mat"), "")),
        "容值_pf": cap_pf,
        "容值误差": clean_tol_for_match(tol_map.get(cap_match.group("tol"), "")),
        "耐压（V）": clean_voltage(voltage_map.get(cap_match.group("volt"), "")),
        "_model_rule_authority": "taiyo_new_series",
    }


def parse_taiyo_leaded_ceramic_model(model):
    model = clean_model(model)
    match = re.match(r"^(?P<volt>[LETGU])(?P<series>[PT])(?P<size>025|050|075)(?P<body>.+)", model)
    if not match:
        return None
    series = f"{match.group('volt')}{match.group('series')}"
    body = match.group("body")
    cap_match = re.search(r"(?P<cap>R\d+|\dR\d+|\d{3,4})(?P<tol>[DJKMZ])", body)
    cap_pf = murata_cap_code_to_pf(cap_match.group("cap")) if cap_match else None
    tol = clean_tol_for_match(cap_match.group("tol")) if cap_match else ""
    size_parts = TAIYO_LEADED_CERAMIC_SIZE_MM_MAP.get(match.group("size"), ("", ""))
    body_size = format_dimension_mm_text(size_parts[0], size_parts[1])
    return {
        "品牌": "太阳诱电Taiyo",
        "型号": model,
        "器件类型": "引线型陶瓷电容",
        "系列": series,
        "系列说明": "轴向引线陶瓷电容 / Axial leaded ceramic capacitor",
        "安装方式": "插件",
        "封装代码": "AXIAL",
        "尺寸（inch）": "",
        "尺寸（mm）": body_size,
        "_body_size": body_size,
        "容值_pf": cap_pf,
        "容值误差": tol,
        "耐压（V）": clean_voltage(TAIYO_LEADED_CERAMIC_VOLTAGE_MAP.get(match.group("volt"), "")),
        "_model_rule_authority": "taiyo_leaded_ceramic_model",
    }


def parse_generic_size_first_mlcc(model, brand=""):
    model = clean_model(model)
    match = re.fullmatch(
        r"(?P<prefix>[A-Z]{1,3})(?P<size>\d{4})(?P<mat>C0G|COG|NP0|NPO|X5R|X7R|X7S|X7T|X6S|X8R|X8L|Y5V)(?P<cap>(?:\d{3,4}|R\d+))(?P<tol>[BCDFGJKMZ])(?P<volt>(?:6R3|0J|0G|0E|1A|1B|1C|1D|1E|1H|2A|2D|2E|2J|250|500|630|\d{3}))(?P<rest>.*)",
        model,
    )
    if not match:
        return None

    size_map = {
        "01005": "01005", "0201": "0201", "0401": "0401", "0402": "0402",
        "0603": "0603", "0805": "0805", "1206": "1206", "1210": "1210",
        "1808": "1808", "1812": "1812", "2010": "2010", "2220": "2220",
    }
    voltage_map = {
        "6R3": "6.3", "0J": "6.3", "0G": "4", "0E": "2.5", "1A": "10",
        "1B": "16", "1C": "25", "1D": "50", "1E": "100", "1H": "50",
        "2A": "100", "2D": "200", "2E": "250", "2J": "630",
        "250": "25", "500": "50", "630": "63",
    }
    material_map = {
        "C0G": "COG(NPO)", "COG": "COG(NPO)", "NP0": "COG(NPO)", "NPO": "COG(NPO)",
        "X5R": "X5R", "X7R": "X7R", "X7S": "X7S", "X7T": "X7T", "X6S": "X6S",
        "X8R": "X8R", "X8L": "X8L", "Y5V": "Y5V"
    }
    tol_map = {"A": "0.05PF", "B": "0.1pF", "C": "0.25pF", "D": "0.5pF", "F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"}

    brand_text = clean_brand(brand)
    prefix_code = clean_text(match.group("prefix")).upper()
    if "HRE" in brand_text.upper() or "芯声微" in brand_text or (brand_text == "" and prefix_code in {"CAA", "CAI", "CIA", "CGA", "CSA", "CSS", "CSO"}):
        display_brand = "芯声微HRE"
        authority = "hre_generic_size_first"
        series_profile = hre_mlcc_series_profile(prefix_code)
    else:
        display_brand = clean_brand(brand) or "未知"
        authority = "generic_size_first_mlcc"
        series_profile = generic_mlcc_series_profile_from_model(model, brand=brand_text)
    series_code = clean_text(series_profile.get("系列", "")) or prefix_code
    cap_pf = murata_cap_code_to_pf(match.group("cap"))
    tol = clean_tol_for_match(tol_map.get(match.group("tol"), ""))
    voltage = clean_voltage(voltage_map.get(match.group("volt"), ""))
    param_count = sum([
        1 if clean_size(size_map.get(match.group("size"), clean_size(match.group("size")))) else 0,
        1 if clean_material(material_map.get(match.group("mat"), match.group("mat"))) else 0,
        1 if cap_pf is not None else 0,
        1 if tol else 0,
        1 if voltage else 0,
    ])

    return {
        "品牌": display_brand,
        "型号": model,
        "系列": series_code,
        "系列说明": clean_text(series_profile.get("系列说明", "")),
        "特殊用途": clean_text(series_profile.get("特殊用途", "")),
        "_mlcc_series_class": clean_text(series_profile.get("_mlcc_series_class", "")),
        "尺寸（inch）": size_map.get(match.group("size"), clean_size(match.group("size"))),
        "材质（介质）": clean_material(material_map.get(match.group("mat"), match.group("mat"))),
        "容值_pf": cap_pf,
        "容值误差": tol,
        "耐压（V）": voltage,
        "_model_rule_authority": authority,
        "_param_count": param_count,
    }


