def parse_pulse_bbgk_ferrite_bead(model):
    """Decode the official BBGK 2012/0805 ferrite-bead ordering code."""
    model = clean_model(model)
    match = re.fullmatch(
        r"BBGK00(?P<metric>2012)(?P<variant>09)(?P<impedance>\d{3})(?P<tolerance>[YT])00",
        model,
    )
    if match is None:
        return None

    impedance_code = match.group("impedance")
    impedance_ohm = int(impedance_code[:2]) * (10 ** int(impedance_code[2]))
    electrical_table = {
        "600": (60, "900mA", "0.10Ω"),
        "121": (120, "800mA", "0.15Ω"),
        "221": (220, "750mA", "0.18Ω"),
        "301": (300, "700mA", "0.18Ω"),
        "601": (600, "500mA", "0.25Ω"),
        "102": (1000, "400mA", "0.30Ω"),
        "152": (1500, "400mA", "0.40Ω"),
        "202": (2000, "400mA", "0.55Ω"),
    }
    table_row = electrical_table.get(impedance_code)
    if table_row is None or int(table_row[0]) != impedance_ohm:
        return None

    tolerance = {"Y": "±25%", "T": "±30%"}.get(match.group("tolerance"), "")
    return {
        "品牌": "Pulse Electronics（国巨集团）",
        "型号": model,
        "器件类型": "磁珠",
        "系列": "BBGK",
        "系列说明": "BBGK 通用多层片式 EMI 磁珠系列",
        "尺寸（inch）": "0805",
        "尺寸（mm）": "2.00×1.25×1.10mm",
        "长度（mm）": "2.00",
        "宽度（mm）": "1.25",
        "高度（mm）": "1.10",
        "容值": str(impedance_ohm),
        "容值单位": "Ω",
        "容值误差": tolerance,
        "阻抗@100MHz": str(impedance_ohm),
        "阻抗单位": "Ω",
        "额定电流": table_row[1],
        "DCR": table_row[2],
        "工作温度": "-55~125℃",
        "安装方式": "贴片",
        "生产状态": "Active",
        "规格摘要": (
            f"0805 | {impedance_ohm}Ω@100MHz | {tolerance} | "
            f"额定电流 {table_row[1]} | DCR≤{table_row[2]}"
        ),
        "官网链接": "https://yageogroup.com/content/datasheet/asset/file/DATASHEET_BBGK00201209_SERIES",
        "数据来源": "YAGEO Group BBGK00201209 官方规格书",
        "数据状态": "官方PDF核对",
        "校验备注": "BBGK00201209 Series Specification, Electrical Characteristics",
        "_model_rule_authority": "yageo_group_bbgk_official",
    }


def parse_cctc_common(model):
    model = clean_model(model)
    # 常见三环：TCC0402X5R105K6R3AT
    if not model.startswith("TCC") or len(model) < 14:
        return None

    size_map = {
        "0100": "01005", "0201": "0201", "0402": "0402", "0603": "0603",
        "0805": "0805", "1206": "1206", "1210": "1210", "1808": "1808",
        "1812": "1812", "2220": "2220"
    }
    material_map = {"X5R": "X5R", "X7R": "X7R", "C0G": "COG(NPO)", "NP0": "COG(NPO)", "X7T": "X7T"}
    tol_map = {"F": "1", "G": "2", "J": "5", "K": "10", "M": "20", "Z": "+80/-20"}

    try:
        size_code = model[3:7]
        mat_code = model[7:10]
        cap_code = model[10:13]
        tol_code = model[13]
        rest = model[14:]

        volt = ""
        if rest.startswith("6R3"):
            volt = "6.3"
        elif len(rest) >= 3 and rest[:3].isdigit():
            vmap = {"100": "10", "160": "16", "250": "25", "500": "50", "630": "630"}
            volt = vmap.get(rest[:3], rest[:3])

        return {
            "品牌": "三环CCTC",
            "型号": model,
            "尺寸（inch）": size_map.get(size_code, ""),
            "材质（介质）": clean_material(material_map.get(mat_code, "")),
            "容值_pf": eia_code_to_pf(cap_code),
            "容值误差": clean_tol_for_match(tol_map.get(tol_code, "")),
            "耐压（V）": clean_voltage(volt)
        }
    except:
        return None


def parse_samsung_cl_partial(model):
    model = clean_model(model)
    if not model.startswith("CL") or len(model) < 5:
        return None
    size_map = {"02":"01005","03":"0201","05":"0402","10":"0603","21":"0805","31":"1206","32":"1210","42":"1808","43":"1812","55":"2220"}
    material_map = {
        "A": "X5R",
        "B": "X7R",
        "C": "COG(NPO)",
        "X": "X6S",
        "Y": "X7S",
        "Z": "X7T",
    }
    tol_map = {"F":"1","G":"2","J":"5","K":"10","M":"20","Z":"+80/-20"}
    voltage_map = {"R":"4","Q":"6.3","P":"10","O":"16","A":"25","L":"35","B":"50","C":"100","D":"200","E":"250","F":"500","G":"630","H":"1000"}
    size = size_map.get(model[2:4], "") if len(model) >= 4 else ""
    mat = material_map.get(model[4], "") if len(model) >= 5 else ""
    pf = eia_code_to_pf(model[5:8]) if len(model) >= 8 else None
    tol = tol_map.get(model[8], "") if len(model) >= 9 else ""
    volt = voltage_map.get(model[9], "") if len(model) >= 10 else ""
    param_count = sum([1 if size else 0, 1 if mat else 0, 1 if pf is not None else 0, 1 if tol else 0, 1 if volt else 0])
    if param_count < 3:
        return None
    return {"品牌": "Samsung","型号": model,"尺寸（inch）": clean_size(size),"材质（介质）": clean_material(mat),"容值_pf": pf,"容值误差": clean_tol_for_match(tol),"耐压（V）": clean_voltage(volt),"_param_count": param_count,"_partial_part": True}

