MLCC_DIMENSION_BACKFILL_DB_COLUMNS = ["长度（mm）", "宽度（mm）", "高度（mm）", "尺寸来源"]


def ensure_sqlite_table_columns_exist(conn, table_name, column_definitions):
    if conn is None or clean_text(table_name) == "" or not isinstance(column_definitions, dict):
        return
    try:
        existing_columns = {
            clean_text(row[1])
            for row in conn.execute(f'PRAGMA table_info("{table_name}")').fetchall()
        }
    except Exception:
        return
    for column_name, column_type in column_definitions.items():
        if clean_text(column_name) == "" or column_name in existing_columns:
            continue
        try:
            conn.execute(
                f'ALTER TABLE "{table_name}" ADD COLUMN "{column_name}" {column_type} DEFAULT \'\''
            )
            try:
                conn.commit()
            except Exception:
                pass
        except Exception:
            pass


def build_mlcc_dimension_backfill_updates(chunk, allow_online_lookup=False):
    if chunk is None or chunk.empty:
        return []
    if "__rowid__" not in chunk.columns:
        raise KeyError("__rowid__")

    original_chunk = chunk.copy()
    row_ids = pd.to_numeric(original_chunk.pop("__rowid__"), errors="coerce")
    filled_chunk = enrich_mlcc_dimension_fields_in_dataframe(original_chunk, allow_online_lookup=allow_online_lookup)
    updates = []
    for row_index, row_id in enumerate(row_ids.tolist()):
        if pd.isna(row_id):
            continue
        current_values = tuple(
            normalize_dimension_mm_value(chunk.iloc[row_index].get(column, "")) if column != "尺寸来源" else clean_text(chunk.iloc[row_index].get(column, ""))
            for column in MLCC_DIMENSION_BACKFILL_DB_COLUMNS
        )
        new_values = tuple(
            normalize_dimension_mm_value(filled_chunk.iloc[row_index].get(column, "")) if column != "尺寸来源" else clean_text(filled_chunk.iloc[row_index].get(column, ""))
            for column in MLCC_DIMENSION_BACKFILL_DB_COLUMNS
        )
        if new_values != current_values:
            updates.append((*new_values, int(row_id)))
    return updates


def apply_verified_mlcc_dimension_fields_to_record(record):
    if not isinstance(record, dict):
        return {}, False
    updated = dict(record)
    fields, source_text = lookup_verified_mlcc_dimension_fields_from_record(updated)
    if not fields:
        return updated, False
    existing_source = clean_text(updated.get("尺寸来源", ""))
    verified_source = clean_text(source_text)
    replace_unverified = existing_source == "" or mlcc_dimension_source_is_unverified_nominal(existing_source)
    refresh_same_verified_source = verified_source != "" and existing_source == verified_source
    changed = False
    for col in MLCC_DIMENSION_COLUMNS:
        value = normalize_dimension_mm_value(fields.get(col, ""))
        if value == "":
            continue
        current_value = normalize_dimension_mm_value(updated.get(col, ""))
        if current_value == "" or replace_unverified or refresh_same_verified_source:
            if current_value != value:
                updated[col] = value
                changed = True
    if verified_source != "" and (existing_source == "" or replace_unverified):
        if existing_source != verified_source:
            updated["尺寸来源"] = verified_source
            changed = True
    return updated, changed


def build_verified_mlcc_dimension_backfill_updates(chunk):
    if chunk is None or chunk.empty:
        return []
    if "__rowid__" not in chunk.columns:
        raise KeyError("__rowid__")
    updates = []
    row_ids = pd.to_numeric(chunk["__rowid__"], errors="coerce")
    for row_index in chunk.index.tolist():
        row_id = row_ids.at[row_index]
        if pd.isna(row_id):
            continue
        current_record = chunk.loc[row_index].to_dict()
        updated_record, changed = apply_verified_mlcc_dimension_fields_to_record(current_record)
        if not changed:
            continue
        new_values = tuple(
            normalize_dimension_mm_value(updated_record.get(column, "")) if column != "尺寸来源" else clean_text(updated_record.get(column, ""))
            for column in MLCC_DIMENSION_BACKFILL_DB_COLUMNS
        )
        updates.append((*new_values, int(row_id)))
    return updates


def verified_mlcc_dimension_sql_filter():
    brand_filters = [
        'UPPER(COALESCE("品牌", "")) LIKE "%WALSIN%"',
        'COALESCE("品牌", "") LIKE "%华新科%"',
        'UPPER(COALESCE("品牌", "")) LIKE "%PDC%"',
        'UPPER(COALESCE("品牌", "")) LIKE "%PSA%"',
        'COALESCE("品牌", "") LIKE "%信昌%"',
        'UPPER(COALESCE("品牌", "")) LIKE "%HRE%"',
        'COALESCE("品牌", "") LIKE "%芯声%"',
    ]
    return (
        'COALESCE("器件类型", "") LIKE "%MLCC%" '
        f'AND ({" OR ".join(brand_filters)}) '
        'AND ('
        'COALESCE("高度（mm）", "") = "" '
        'OR COALESCE("尺寸来源", "") = "" '
        'OR COALESCE("尺寸来源", "") LIKE "%封装码标称%" '
        'OR COALESCE("尺寸来源", "") LIKE "%尺寸码推断%" '
        'OR COALESCE("尺寸来源", "") LIKE "%Walsin规格书%" '
        'OR COALESCE("尺寸来源", "") LIKE "%PDC/PSA规格书%" '
        'OR COALESCE("尺寸来源", "") LIKE "%HRE规格书%" '
        ')'
    )


def backfill_verified_mlcc_dimension_fields_in_database_in_place(chunk_rows=100000):
    if not os.path.exists(DB_PATH):
        raise FileNotFoundError(DB_PATH)
    conn = sqlite3.connect(DB_PATH, timeout=60)
    conn.execute("PRAGMA busy_timeout = 60000")
    try:
        conn.execute("PRAGMA journal_mode = WAL")
    except sqlite3.DatabaseError:
        pass

    try:
        ensure_sqlite_table_columns_exist(
            conn,
            "components",
            {
                "长度（mm）": "TEXT",
                "宽度（mm）": "TEXT",
                "高度（mm）": "TEXT",
                "尺寸来源": "TEXT",
            },
        )
        update_sql = (
            'UPDATE components SET "长度（mm）" = ?, "宽度（mm）" = ?, "高度（mm）" = ?, "尺寸来源" = ? '
            'WHERE rowid = ?'
        )
        query = (
            'SELECT rowid AS "__rowid__", * FROM components '
            f'WHERE {verified_mlcc_dimension_sql_filter()}'
        )
        updated_rows = 0
        for chunk in pd.read_sql_query(query, conn, chunksize=max(int(chunk_rows), 1000)):
            updates = build_verified_mlcc_dimension_backfill_updates(chunk)
            if updates:
                conn.executemany(update_sql, updates)
                conn.commit()
                updated_rows += len(updates)
        return updated_rows
    finally:
        conn.close()


def backfill_verified_mlcc_dimension_fields_in_prepared_cache():
    if not os.path.exists(PREPARED_CACHE_PATH):
        return 0
    prepared = read_prepared_cache()
    if prepared is None or prepared.empty:
        return 0
    work = prepared.copy()
    for col in MLCC_DIMENSION_BACKFILL_DB_COLUMNS:
        if col not in work.columns:
            work[col] = ""
    brand_series = work["品牌"].astype("string").fillna("")
    type_series = work["器件类型"].astype("string").fillna("") if "器件类型" in work.columns else pd.Series([""] * len(work), index=work.index, dtype="string")
    brand_upper = brand_series.str.upper()
    candidate_mask = (
        type_series.str.contains("MLCC", na=False)
        & (
            brand_upper.str.contains("WALSIN", na=False)
            | brand_series.str.contains("华新科", na=False)
            | brand_upper.str.contains("PDC", na=False)
            | brand_upper.str.contains("PSA", na=False)
            | brand_series.str.contains("信昌", na=False)
            | brand_upper.str.contains("HRE", na=False)
            | brand_series.str.contains("芯声", na=False)
        )
    )
    updated_rows = 0
    for idx in work.index[candidate_mask].tolist():
        updated_record, changed = apply_verified_mlcc_dimension_fields_to_record(work.loc[idx].to_dict())
        if not changed:
            continue
        for col in MLCC_DIMENSION_BACKFILL_DB_COLUMNS:
            work.at[idx, col] = updated_record.get(col, "")
        updated_rows += 1
    if updated_rows <= 0:
        return 0
    cache_dir = os.path.dirname(PREPARED_CACHE_PATH)
    if cache_dir:
        os.makedirs(cache_dir, exist_ok=True)
    temp_parquet_path = build_unique_temp_path(PREPARED_CACHE_PATH, "verified_mlcc_dimensions")
    temp_meta_path = build_unique_temp_path(PREPARED_CACHE_META_PATH, "verified_mlcc_dimensions")
    optimized = optimize_prepared_dataframe_dtypes(work)
    optimized.to_parquet(temp_parquet_path, index=False)
    meta = dict(get_database_signature())
    bundle_signature = get_public_bundle_signature_for_cache()
    if bundle_signature:
        meta["bundle_signature"] = bundle_signature
    with open(temp_meta_path, "w", encoding="utf-8") as handle:
        json.dump(meta, handle, ensure_ascii=False, indent=2)
    replace_file_atomically(temp_parquet_path, PREPARED_CACHE_PATH)
    replace_file_atomically(temp_meta_path, PREPARED_CACHE_META_PATH)
    return updated_rows


def backfill_mlcc_dimension_fields_in_database_in_place(chunk_rows=100000, allow_online_lookup=False, rebuild_cache=True):
    if not os.path.exists(DB_PATH):
        raise FileNotFoundError(DB_PATH)

    conn = sqlite3.connect(DB_PATH, timeout=60)
    conn.execute("PRAGMA busy_timeout = 60000")
    try:
        conn.execute("PRAGMA journal_mode = WAL")
    except sqlite3.DatabaseError:
        pass

    try:
        batch_size = max(int(chunk_rows), 1000)
        update_sql = (
            'UPDATE components SET "长度（mm）" = ?, "宽度（mm）" = ?, "高度（mm）" = ?, "尺寸来源" = ? '
            'WHERE rowid = ?'
        )
        updated_rows = 0
        chunk = None
        query = (
            'SELECT rowid AS "__rowid__", * FROM components '
            'WHERE COALESCE("器件类型", "") LIKE "%MLCC%" '
            'AND (COALESCE("长度（mm）", "") = "" OR COALESCE("宽度（mm）", "") = "" OR COALESCE("高度（mm）", "") = "" OR COALESCE("尺寸来源", "") = "")'
        )
        for chunk in pd.read_sql_query(query, conn, chunksize=batch_size):
            if chunk is not None and not chunk.empty:
                updates = build_mlcc_dimension_backfill_updates(chunk, allow_online_lookup=allow_online_lookup)
                if updates:
                    conn.executemany(update_sql, updates)
                    conn.commit()
                    updated_rows += len(updates)
        clear_data_load_caches()
        if rebuild_cache:
            rebuild_prepared_cache_from_database()
        return updated_rows
    finally:
        conn.close()


def backfill_series_fields_in_database(chunk_rows=100000):
    if not os.path.exists(DB_PATH):
        raise FileNotFoundError(DB_PATH)

    temp_db_path = build_unique_temp_path(DB_PATH, "series_backfill")

    read_conn = sqlite3.connect(DB_PATH, timeout=60)
    read_conn.execute("PRAGMA busy_timeout = 60000")
    write_conn = sqlite3.connect(temp_db_path, timeout=60)
    write_conn.execute("PRAGMA busy_timeout = 60000")
    wrote_any = False

    try:
        source_columns = [
            clean_text(row[1])
            for row in read_conn.execute('PRAGMA table_info("components")').fetchall()
            if clean_text(row[1]) != ""
        ]
        for chunk in pd.read_sql_query("SELECT * FROM components", read_conn, chunksize=int(chunk_rows)):
            if chunk is None or chunk.empty:
                continue
            filled = fill_missing_series_from_model(chunk)
            if source_columns:
                # Keep the rebuilt table aligned with the persisted DB schema.
                # fill_missing_series_from_model may add transient helper columns.
                filled = filled.reindex(columns=source_columns, fill_value="")
            filled.to_sql(
                "components",
                write_conn,
                if_exists="replace" if not wrote_any else "append",
                index=False,
            )
            wrote_any = True
        if not wrote_any:
            raise RuntimeError("no database rows were written")
        create_database_indexes(write_conn)
    finally:
        read_conn.close()
        write_conn.close()

    try:
        replace_file_atomically(temp_db_path, DB_PATH)
    except PermissionError:
        try:
            if os.path.exists(temp_db_path):
                os.remove(temp_db_path)
        except OSError:
            pass
        backfill_series_fields_in_database_in_place(chunk_rows=chunk_rows)
    else:
        if os.path.exists(temp_db_path):
            try:
                os.remove(temp_db_path)
            except OSError:
                pass
    clear_data_load_caches()
    rebuild_prepared_cache_from_database()


@st.cache_data(ttl=3600)
def _load_prepared_data_cached(cache_signature):
    if prepared_cache_is_current():
        try:
            cached = read_prepared_cache()
            if prepared_dataframe_looks_sane(cached):
                return cached
        except Exception:
            pass
    try:
        rebuild_prepared_cache_from_database()
        cached = read_prepared_cache()
        if prepared_dataframe_looks_sane(cached):
            return cached
    except Exception:
        pass
    prepared = prepare_search_dataframe(load_data())
    try:
        write_prepared_cache(prepared)
    except Exception:
        pass
    return prepared


def load_prepared_data(cache_signature=None):
    if cache_signature is None:
        cache_signature = get_data_cache_signature()
    return _load_prepared_data_cached(cache_signature)


def clear_data_load_caches():
    global SAMSUNG_MLCC_DIMENSION_LOOKUP, SAMSUNG_MLCC_DIMENSION_LOOKUP_SIGNATURE
    global MLCC_LCSC_DIMENSION_CACHE, MLCC_LCSC_DIMENSION_CACHE_SIGNATURE
    MODEL_REVERSE_LOOKUP_CACHE.clear()
    MLCC_REFERENCE_LOOKUP_CACHE.clear()
    clear_session_query_caches()
    SAMSUNG_MLCC_DIMENSION_LOOKUP = None
    SAMSUNG_MLCC_DIMENSION_LOOKUP_SIGNATURE = None
    MLCC_LCSC_DIMENSION_CACHE = None
    MLCC_LCSC_DIMENSION_CACHE_SIGNATURE = None
    for cached_func in (_load_data_cached, _load_prepared_data_cached):
        try:
            cached_func.clear()
        except Exception:
            continue


def maybe_update_database(force=False, min_interval_sec=60):
    startup_trace(f"maybe_update_database:enter force={force}")
    if force:
        update_database(force=True)
        startup_trace("maybe_update_database:forced-done")
        return
    # Keep app startup responsive: if a usable database already exists,
    # don't block the initial page render with a full source refresh.
    if database_has_component_rows():
        startup_trace("maybe_update_database:already-has-db")
        return
    try:
        now = time.time()
        last_check = float(st.session_state.get("_db_refresh_checked_at", 0.0))
        if now - last_check < float(min_interval_sec):
            startup_trace("maybe_update_database:skip-throttle")
            return
    except Exception:
        pass
    update_database(force=False)
    startup_trace("maybe_update_database:update-done")
    try:
        st.session_state["_db_refresh_checked_at"] = time.time()
    except Exception:
        pass


